window.QUIZ_DATA = [{"id": "set1", "title": "ชุดที่ 1 — Cardiology + Pulmonology", "questions": [{"topic": "Cardiology", "q": "A 58-year-old man has crushing central chest pain radiating to the jaw for 40 minutes with diaphoresis. ECG shows ST elevation in V2–V4. He is at a hospital capable of primary PCI. What is the most appropriate reperfusion strategy?", "choices": ["Immediate fibrinolytic therapy", "Primary PCI within 90 minutes", "Wait for troponin before deciding", "Start warfarin", "Observe for 24 hours"], "ans": 1, "exp": "นี่คือ anterior STEMI (LAD). เมื่อทำ primary PCI ได้ในเวลา ควรเลือก PCI ภายใน 90 นาที (door-to-balloon) ซึ่งเป็น reperfusion ที่ดีที่สุด. Fibrinolytic ใช้เมื่อ PCI ไม่ทัน (คาดว่าเกิน 120 นาที). ไม่ต้องรอ troponin เพราะ ST elevation วินิจฉัย STEMI ได้แล้ว.", "id": "set1-1"}, {"topic": "Cardiology", "q": "A patient with inferior STEMI (II, III, aVF) has BP 88/60. After sublingual nitroglycerin the BP drops markedly. What is the most likely mechanism?", "choices": ["Aortic dissection", "Right ventricular infarction", "Pericardial tamponade", "Tension pneumothorax", "Vasovagal reaction"], "ans": 1, "exp": "Inferior MI มักมี RV infarction ร่วม ซึ่ง preload-dependent การให้ nitrate จะลด preload ทำให้ BP ตก. รักษาด้วย IV fluid และหลีกเลี่ยง nitrate. ควรตรวจ right-sided lead (V4R).", "id": "set1-2"}, {"topic": "Cardiology", "q": "A 65-year-old woman with DM and HT has exertional dyspnea, orthopnea, leg edema, elevated JVP, bibasal crepitations, and S3. Echo shows EF 30%. Which drug does NOT reduce mortality in HFrEF?", "choices": ["ARNI (sacubitril/valsartan)", "Beta-blocker", "SGLT2 inhibitor", "MRA (spironolactone)", "Amlodipine"], "ans": 4, "exp": "HFrEF ใช้ 4 เสาหลัก: ARNI/ACEI/ARB + beta-blocker + MRA + SGLT2i. Amlodipine (DHP-CCB) ไม่ลด mortality ใน HFrEF ใช้เฉพาะคุมความดัน/angina; non-DHP CCB (verapamil/diltiazem) เป็นข้อห้ามใน HFrEF.", "id": "set1-3"}, {"topic": "Cardiology", "q": "A 70-year-old man has palpitations and an irregularly irregular pulse. ECG shows absent P waves. CHA2DS2-VASc = 4. Which intervention most reduces his stroke risk?", "choices": ["Aspirin alone", "Anticoagulation with a DOAC", "Digoxin", "Immediate cardioversion without work-up", "Statin"], "ans": 1, "exp": "AF ที่ CHA2DS2-VASc ≥ 2 (ชาย) ควรได้ anticoagulant โดย DOAC เป็นตัวเลือกแรก (เหนือ warfarin ยกเว้น mechanical valve/moderate-severe MS). Aspirin ไม่พอ; cardioversion โดยไม่ประเมิน thrombus เสี่ยง embolic stroke.", "id": "set1-4"}, {"topic": "Cardiology", "q": "A patient with AF for more than 48 hours who has NOT been anticoagulated is scheduled for cardioversion. What is the most important risk?", "choices": ["Torsades de pointes", "Embolic stroke", "Hyperkalemia", "Malignant hyperthermia", "Aortic dissection"], "ans": 1, "exp": "AF > 48 ชม. อาจมี thrombus ใน left atrial appendage การ cardiovert อาจทำให้ลิ่มหลุดเกิด embolic stroke. ต้อง anticoagulate ≥ 3 สัปดาห์ก่อน หรือทำ TEE ตัด thrombus ก่อน แล้ว anticoagulate ต่อ ≥ 4 สัปดาห์.", "id": "set1-5"}, {"topic": "Cardiology", "q": "A patient develops polymorphic VT that twists around the baseline; ECG before the event showed a prolonged QT. What is the most appropriate immediate treatment?", "choices": ["IV magnesium sulfate", "IV amiodarone bolus", "IV digoxin", "IV verapamil", "Adenosine"], "ans": 0, "exp": "นี่คือ Torsades de pointes (polymorphic VT บน long QT). รักษาด้วย IV magnesium sulfate + แก้สาเหตุ QT ยาว (ยา, hypoK/Mg/Ca), overdrive pacing ถ้าจำเป็น. Amiodarone/ยาที่ยืด QT อาจทำให้แย่ลง.", "id": "set1-6"}, {"topic": "Cardiology", "q": "A 60-year-old man has predictable chest pain on exertion that resolves within 5 minutes of rest, with no dynamic troponin change. What is the most appropriate diagnosis and next step?", "choices": ["Unstable angina; give fibrinolytic", "Stable angina; exercise stress test or CT coronary angiography", "STEMI; primary PCI", "Pericarditis; NSAIDs", "Aortic dissection; CT aorta"], "ans": 1, "exp": "อาการ predictable เจ็บเวลาออกแรงและหายเมื่อพัก = stable angina. ประเมินด้วย non-invasive test (exercise stress test/CTCA) และให้ ASA + statin + anti-anginal + คุมปัจจัยเสี่ยง.", "id": "set1-7"}, {"topic": "Cardiology", "q": "According to current guidelines, the LDL-C target for a very-high-risk patient after ACS is:", "choices": ["< 130 mg/dL", "< 100 mg/dL", "< 70 mg/dL", "< 55 mg/dL and ≥ 50% reduction", "No target"], "ans": 3, "exp": "แนวทางปัจจุบัน (ESC 2023 ACS / ACC-AHA 2025) เป้า LDL-C < 55 mg/dL และลดลง ≥ 50% จาก baseline. ถ้าไม่ถึงเป้าด้วย high-intensity statin เต็มขนาด เพิ่ม ezetimibe แล้ว PCSK9 inhibitor. (สไลด์เดิมมักระบุ < 70).", "id": "set1-8"}, {"topic": "Cardiology", "q": "A 55-year-old asymptomatic woman has office BP averaging 150/95 on two visits. What is the most appropriate step before confirming a diagnosis of hypertension?", "choices": ["Start two antihypertensives immediately", "Confirm with home BP monitoring or ambulatory BP monitoring", "Refer for adrenalectomy", "Give a trial of a diuretic", "Diagnose hypertensive emergency"], "ans": 1, "exp": "ควรยืนยันด้วยการวัดนอกคลินิก (HBPM เฉลี่ย ≥135/85 หรือ ABPM) เพื่อตัด white-coat hypertension ก่อนวินิจฉัยและเริ่มยา (ยกเว้น BP สูงมาก/มี target organ damage).", "id": "set1-9"}, {"topic": "Cardiology", "q": "A 30-year-old man has hypertension resistant to three drugs and is found to have hypokalemia. Which screening test is most appropriate for a secondary cause?", "choices": ["Aldosterone-to-renin ratio", "24-hour urine cortisol", "Renal artery Doppler", "Plasma metanephrines", "TSH"], "ans": 0, "exp": "HT + hypokalemia (โดยเฉพาะ resistant/อายุน้อย) นึกถึง primary aldosteronism (Conn) คัดกรองด้วย aldosterone-to-renin ratio ที่สูง. Pheochromocytoma (metanephrine) มี HT เป็นพักๆ + ปวดหัว/เหงื่อ/ใจสั่น.", "id": "set1-10"}, {"topic": "Cardiology", "q": "A 45-year-old man has BP 230/130 with severe headache, blurred vision, papilledema, and rising creatinine. What is the appropriate management?", "choices": ["Oral antihypertensive and discharge", "Controlled BP reduction with IV agents (~10–20% in the first hour)", "Normalize BP within 15 minutes", "No BP reduction needed", "Sublingual nifedipine"], "ans": 1, "exp": "นี่คือ hypertensive emergency (encephalopathy + retinopathy + AKI) ต้องลด BP แบบควบคุมด้วยยา IV ~10–20% ใน 1 ชม.แรก (dissection ลดเร็วกว่า) เพื่อเลี่ยง hypoperfusion. Sublingual nifedipine เสี่ยง ischemia.", "id": "set1-11"}, {"topic": "Cardiology", "q": "ECG shows the PR interval progressively lengthening until a QRS is dropped, then the cycle repeats. What is the diagnosis?", "choices": ["First-degree AV block", "Mobitz type I (Wenckebach)", "Mobitz type II", "Complete heart block", "Atrial flutter"], "ans": 1, "exp": "PR ยาวขึ้นเรื่อยๆ จน drop beat = Mobitz I (Wenckebach) มักไม่รุนแรง ไม่ต้อง pacemaker ถ้าไม่มีอาการ. ต่างจาก Mobitz II (PR คงที่แล้ว drop ทันที) ที่เสี่ยงและต้อง pacemaker.", "id": "set1-12"}, {"topic": "Cardiology", "q": "A patient with complete (third-degree) AV block, heart rate 35, has recurrent presyncope. What is the definitive long-term treatment?", "choices": ["Atropine indefinitely", "Permanent pacemaker", "Beta-blocker", "Digoxin", "Observation"], "ans": 1, "exp": "Complete heart block ที่มีอาการเสี่ยง asystole รักษาชั่วคราวด้วย atropine/transcutaneous pacing และรักษาถาวรด้วย permanent pacemaker. Beta-blocker/digoxin จะยิ่งกด conduction.", "id": "set1-13"}, {"topic": "Cardiology", "q": "A 68-year-old woman has exertional syncope, an ejection systolic murmur at the base radiating to the carotids, and pulsus parvus et tardus. What is the diagnosis?", "choices": ["Mitral regurgitation", "Aortic stenosis", "Mitral stenosis", "Aortic regurgitation", "Ventricular septal defect"], "ans": 1, "exp": "Ejection systolic murmur ร้าวคอ + pulsus parvus et tardus = aortic stenosis. Triad: angina/syncope/HF; symptomatic severe AS ควรทำ AVR/TAVI. Syncope เวลาออกแรงเป็นลักษณะเด่น.", "id": "set1-14"}, {"topic": "Cardiology", "q": "A patient has fever, a new murmur, splinter hemorrhages, and blood cultures growing Staphylococcus aureus. What is the diagnosis and the key confirmatory investigation?", "choices": ["Rheumatic fever; ASO titer", "Infective endocarditis; echocardiography", "Pericarditis; ECG", "Myocarditis; cardiac MRI", "Pulmonary embolism; CTPA"], "ans": 1, "exp": "ไข้ + murmur ใหม่ + peripheral emboli + positive blood culture เข้า Duke criteria ของ infective endocarditis. ทำ echocardiography หา vegetation และให้ IV antibiotics ตามเชื้อ 4–6 สัปดาห์.", "id": "set1-15"}, {"topic": "Cardiology", "q": "In a diabetic patient with albuminuria, which antihypertensive class is first-line?", "choices": ["Beta-blocker", "ACE inhibitor or ARB", "Alpha-blocker", "Hydralazine", "Loop diuretic"], "ans": 1, "exp": "เบาหวาน + albuminuria/CKD ควรใช้ ACEI หรือ ARB เป็นแนวหน้าเพราะลด proteinuria และชะลอไตเสื่อม. ห้ามใช้ ACEI ร่วม ARB. อาจเพิ่ม SGLT2i เพื่อป้องกันไต/หัวใจ.", "id": "set1-16"}, {"topic": "Cardiology", "q": "A patient with stable, narrow-complex regular SVT is hemodynamically stable. What is the first step?", "choices": ["Synchronized cardioversion", "Vagal maneuver then adenosine", "Amiodarone drip", "Defibrillation", "IV verapamil push immediately"], "ans": 1, "exp": "SVT ที่ stable เริ่มด้วย vagal maneuver (Valsalva/carotid massage) ถ้าไม่ได้ผลให้ adenosine IV push. ถ้า unstable จึงทำ synchronized cardioversion. Defibrillation ใช้กับ pulseless VT/VF.", "id": "set1-17"}, {"topic": "Cardiology", "q": "A CKD patient has ECG showing peaked T waves, prolonged PR, and widening QRS. Which drug should be given FIRST to protect the heart?", "choices": ["Insulin plus glucose", "Calcium gluconate", "Nebulized salbutamol", "Sodium bicarbonate", "Kayexalate (resin)"], "ans": 1, "exp": "ECG เข้าได้กับ hyperkalemia รุนแรง. ลำดับแรกคือ IV calcium gluconate เพื่อ stabilize cardiac membrane (แม้ไม่ลดระดับ K). จากนั้นจึง shift K (insulin+glucose, beta-agonist) และกำจัด K (diuretic/resin/dialysis).", "id": "set1-18"}, {"topic": "Cardiology", "q": "Which murmur is characteristic of mitral stenosis?", "choices": ["Holosystolic radiating to axilla", "Mid-diastolic rumble with opening snap at the apex", "Ejection systolic radiating to the carotids", "Early diastolic at the left sternal border", "Continuous machinery murmur"], "ans": 1, "exp": "Mitral stenosis: mid-diastolic rumble ที่ apex + opening snap. สาเหตุหลัก rheumatic heart disease มักสัมพันธ์ AF และ hemoptysis. Holosystolic ร้าวรักแร้ = MR; early diastolic = AR.", "id": "set1-19"}, {"topic": "Cardiology", "q": "A patient in acute decompensated heart failure with pulmonary edema has BP 150/90. What is the appropriate initial management?", "choices": ["IV beta-blocker bolus", "Sit upright, O2/NIV, IV loop diuretic ± nitrate", "IV fluid bolus", "Calcium channel blocker", "Immediate digoxin"], "ans": 1, "exp": "Acute pulmonary edema: นั่งตัวตรง, O2/NIV, IV loop diuretic (furosemide) ลด preload, nitrate ถ้า BP พอ, หา precipitant. IV fluid และ beta-blocker bolus เป็นข้อห้ามในภาวะ decompensated.", "id": "set1-20"}, {"topic": "Cardiology", "q": "Which complication is the most common cause of sudden death in the first hour of an acute MI?", "choices": ["Ventricular free wall rupture", "Ventricular arrhythmia (VT/VF)", "Dressler syndrome", "Papillary muscle rupture", "LV aneurysm"], "ans": 1, "exp": "สาเหตุตายเฉียบพลันที่พบบ่อยสุดในช่วงแรกของ MI คือ ventricular arrhythmia (VT/VF). Free wall/papillary muscle rupture มักเกิดวันถัดมา; Dressler syndrome เกิดเป็นสัปดาห์-เดือนหลัง MI.", "id": "set1-21"}, {"topic": "Cardiology", "q": "How long should standard dual antiplatelet therapy (DAPT) be given after ACS in a patient not at high bleeding risk?", "choices": ["1 month", "3 months", "At least 12 months", "1 week", "Not necessary"], "ans": 2, "exp": "DAPT (aspirin + P2Y12 inhibitor) มาตรฐานหลัง ACS คืออย่างน้อย 12 เดือนในผู้ที่ไม่เสี่ยงเลือดออกสูง. ถ้าเสี่ยงเลือดออกอาจสั้นลง; ถ้าเสี่ยง ischemic สูงอาจยาวขึ้น.", "id": "set1-22"}, {"topic": "Cardiology", "q": "Which ECG leads localize an inferior wall myocardial infarction?", "choices": ["V1–V2", "V3–V4", "II, III, aVF", "I, aVL", "V5–V6"], "ans": 2, "exp": "Inferior wall MI แสดง ST changes ที่ II, III, aVF (มัก RCA). V1–V2 = septal, V3–V4 = anterior (LAD), I/aVL/V5–V6 = lateral (LCx).", "id": "set1-23"}, {"topic": "Cardiology", "q": "Which pulse finding is characteristic of chronic aortic regurgitation?", "choices": ["Pulsus parvus et tardus", "Water-hammer (Corrigan) pulse", "Pulsus paradoxus", "Pulsus alternans", "Bisferiens only"], "ans": 1, "exp": "AR เรื้อรังมี wide pulse pressure ทำให้เกิด water-hammer (Corrigan) pulse + early diastolic murmur. Pulsus parvus et tardus = AS; pulsus paradoxus = tamponade.", "id": "set1-24"}, {"topic": "Cardiology", "q": "A patient with AF and rheumatic moderate-to-severe mitral stenosis needs anticoagulation. Which agent should be used?", "choices": ["DOAC (apixaban)", "Warfarin", "Aspirin", "Clopidogrel", "None"], "ans": 1, "exp": "AF ที่มี moderate-severe mitral stenosis (rheumatic) หรือ mechanical valve ต้องใช้ warfarin เท่านั้น ไม่ใช้ DOAC เพราะ DOAC ด้อยกว่าและยังไม่รับรองในกลุ่มนี้.", "id": "set1-25"}, {"topic": "Cardiology", "q": "Under the 2024 ESC classification, the new category of 'Elevated BP' corresponds to which range?", "choices": ["< 120/70", "120–139/70–89", "140–159/90–99", "≥ 160/100", "≥ 180/110"], "ans": 1, "exp": "ESC 2024 เพิ่มหมวด Elevated BP = 120–139/70–89 (พิจารณาให้ยาตามความเสี่ยง CV); Non-elevated < 120/70; Hypertension ≥ 140/90. เป้าการรักษา default SBP 120–129 ถ้าทนได้.", "id": "set1-26"}, {"topic": "Cardiology", "q": "A patient with stable angina cannot take a beta-blocker due to severe asthma. Which anti-anginal is appropriate?", "choices": ["A calcium channel blocker and/or long-acting nitrate", "Digoxin", "Warfarin", "Furosemide", "Spironolactone"], "ans": 0, "exp": "เมื่อ beta-blocker มีข้อห้าม ใช้ CCB (non-DHP diltiazem หรือ DHP amlodipine) และ/หรือ long-acting nitrate เป็น anti-anginal ร่วมกับ ASA + statin.", "id": "set1-27"}, {"topic": "Cardiology", "q": "A patient with chest pain has diffuse concave ST elevation with PR depression and an audible friction rub. What is the diagnosis?", "choices": ["STEMI", "Acute pericarditis", "Aortic dissection", "Pulmonary embolism", "Early repolarization"], "ans": 1, "exp": "Diffuse concave ST elevation + PR depression + friction rub = acute pericarditis. รักษาด้วย NSAID + colchicine. ต่างจาก STEMI ที่ ST elevation จำกัด territory + reciprocal change.", "id": "set1-28"}, {"topic": "Cardiology", "q": "Which bedside test best confirms pericardial tamponade?", "choices": ["ECG", "Echocardiography", "Chest X-ray", "Troponin", "BNP"], "ans": 1, "exp": "Tamponade วินิจฉัยด้วย echocardiography (pericardial effusion + RA/RV diastolic collapse). อาการ Beck triad + pulsus paradoxus. รักษา pericardiocentesis.", "id": "set1-29"}, {"topic": "Cardiology", "q": "Which ECG feature characterizes Wolff-Parkinson-White syndrome?", "choices": ["Peaked T waves", "Delta wave with short PR interval", "Long QT", "Epsilon wave", "Osborn wave"], "ans": 1, "exp": "WPW มี accessory pathway → short PR + delta wave + wide QRS. ระวัง AF ใน WPW ห้ามใช้ AV nodal blocker (digoxin/verapamil/adenosine) เพราะอาจ conduct เร็วผ่าน accessory pathway.", "id": "set1-30"}, {"topic": "Cardiology", "q": "In a young athlete with hypertrophic cardiomyopathy, strenuous exercise most increases the risk of which event?", "choices": ["Aortic dissection", "Sudden cardiac death", "Pulmonary embolism", "Stroke from AF only", "Myxoma emboli"], "ans": 1, "exp": "HCM (โดยเฉพาะในนักกีฬาอายุน้อย) เป็นสาเหตุ sudden cardiac death ขณะออกกำลังหักโหม จาก outflow obstruction/arrhythmia. ควรจำกัดกิจกรรมหักโหมและประเมิน ICD ในผู้เสี่ยงสูง.", "id": "set1-31"}, {"topic": "Cardiology", "q": "Which agent, beyond its benefit in HFrEF, also reduces heart-failure hospitalization in HFpEF based on recent evidence?", "choices": ["Digoxin", "SGLT2 inhibitor", "Ivabradine", "Hydralazine", "Amlodipine"], "ans": 1, "exp": "SGLT2 inhibitor (dapagliflozin/empagliflozin) ลด HF hospitalization ทั้งใน HFrEF และ HFpEF จึงเป็นเสาหลักที่ใช้ได้กว้าง. Ivabradine/hydralazine ใช้เฉพาะ HFrEF บางกลุ่ม.", "id": "set1-32"}, {"topic": "Cardiology", "q": "A 50-year-old man develops sudden dyspnea after major surgery, with a swollen left leg. ECG shows sinus tachycardia and an S1Q3T3 pattern. What should be suspected first?", "choices": ["Acute MI", "Pulmonary embolism", "Pericarditis", "Aortic dissection", "Pneumothorax"], "ans": 1, "exp": "หลังผ่าตัด + ขาบวมข้างเดียว + เหนื่อยเฉียบพลัน + S1Q3T3/RV strain ชี้ pulmonary embolism (VTE). ยืนยันด้วย CTPA; รักษา anticoagulation, massive PE + shock พิจารณา thrombolysis.", "id": "set1-33"}, {"topic": "Cardiology", "q": "What is the immediate treatment of pulseless ventricular tachycardia or ventricular fibrillation?", "choices": ["Synchronized cardioversion", "Immediate defibrillation with CPR", "Adenosine", "IV magnesium only", "Vagal maneuver"], "ans": 1, "exp": "Pulseless VT/VF เป็น cardiac arrest ต้อง defibrillation (unsynchronized) ทันที + CPR คุณภาพสูง + epinephrine ตาม ACLS. Synchronized cardioversion ใช้กับ tachyarrhythmia ที่ยังมีชีพจรแต่ unstable.", "id": "set1-34"}, {"topic": "Cardiology", "q": "Three weeks after an MI, a patient develops low-grade fever, pleuritic chest pain, a friction rub, and a pericardial effusion. What is the diagnosis?", "choices": ["Reinfarction", "Dressler syndrome (post-MI pericarditis)", "Infective endocarditis", "Pulmonary embolism", "Myocarditis"], "ans": 1, "exp": "Dressler syndrome = post-MI autoimmune pericarditis เกิดหลายสัปดาห์หลัง MI. รักษาด้วย NSAID/colchicine (หลีกเลี่ยง steroid ระยะแรกหลัง MI).", "id": "set1-35"}, {"topic": "Cardiology", "q": "A patient with symptomatic bradycardia (HR 38, BP 80/50) does not respond to atropine. What is the next step?", "choices": ["Beta-blocker", "Transcutaneous pacing (± dopamine/epinephrine)", "Adenosine", "Digoxin", "Verapamil"], "ans": 1, "exp": "Symptomatic bradycardia ที่ไม่ตอบสนอง atropine ให้ transcutaneous pacing และ/หรือ chronotropic infusion (dopamine/epinephrine) แล้วเตรียม pacemaker. ยา AV nodal blocker เป็นข้อห้าม.", "id": "set1-36"}, {"topic": "Cardiology", "q": "In a diabetic patient screened for lipids, what is the first-line drug class to reduce ASCVD risk?", "choices": ["Fibrate primarily", "Statin according to risk level", "Omega-3 alone", "Niacin", "No drug needed"], "ans": 1, "exp": "ยาแนวหน้าลด ASCVD คือ statin ตามระดับความเสี่ยง (high-intensity ในผู้เสี่ยงสูง/มี ASCVD). Fibrate ใช้เมื่อ TG สูงมากเพื่อลด pancreatitis. เป้า LDL ต่ำลงตามความเสี่ยง.", "id": "set1-37"}, {"topic": "Cardiology", "q": "Which adverse effect of NSAIDs is most concerning in a patient with heart failure?", "choices": ["Hypokalemia", "Fluid retention worsening HF and reduced diuretic effect", "Hyperthyroidism", "Bradycardia", "QT prolongation"], "ans": 1, "exp": "NSAID ทำให้ Na/น้ำคั่ง ลดประสิทธิภาพ diuretic และ ACEI/ARB ทำให้ HF กำเริบและเสี่ยง AKI จึงควรหลีกเลี่ยงใน HF/CKD.", "id": "set1-38"}, {"topic": "Cardiology", "q": "Which auscultatory finding is characteristic of mitral valve prolapse?", "choices": ["Mid-systolic click and late systolic murmur", "Opening snap", "Continuous murmur", "Early diastolic murmur", "Fixed split S2"], "ans": 0, "exp": "MVP มี mid-systolic click ตามด้วย late systolic murmur; ท่าที่ลด preload (standing/Valsalva) ทำให้ click มาเร็วขึ้น. MVP เป็นสาเหตุ chronic MR ที่พบบ่อย.", "id": "set1-39"}, {"topic": "Cardiology", "q": "After successful fibrinolysis for STEMI, what should be done next?", "choices": ["Observation only", "Refer for coronary angiography ± PCI", "Start long-term warfarin immediately", "Stop antiplatelet therapy", "Give a calcium channel blocker"], "ans": 1, "exp": "หลัง fibrinolytic ควรส่งต่อทำ coronary angiography ± PCI (routine early หรือ rescue PCI ถ้า reperfusion ล้มเหลว) ตาม pharmaco-invasive strategy. ยังคง DAPT + anticoagulant ตามข้อบ่งชี้.", "id": "set1-40"}, {"topic": "Cardiology", "q": "A woman at 30 weeks gestation has BP 160/110 with proteinuria and headache. What is the diagnosis and appropriate drug?", "choices": ["Chronic HT; ACE inhibitor", "Preeclampsia; labetalol/hydralazine/nifedipine", "Gestational HT; atenolol", "Pheochromocytoma; phenoxybenzamine", "White-coat HT; no drug"], "ans": 1, "exp": "BP สูง + proteinuria หลัง 20 สัปดาห์ = preeclampsia. ยาปลอดภัย: labetalol, hydralazine, nifedipine + MgSO4 ป้องกัน/รักษา eclampsia. ACEI/ARB เป็นข้อห้ามในการตั้งครรภ์.", "id": "set1-41"}, {"topic": "Cardiology", "q": "Which drug reduces mortality in HFrEF via neprilysin inhibition combined with an ARB?", "choices": ["Sacubitril/valsartan (ARNI)", "Ivabradine", "Digoxin", "Amlodipine", "Hydrochlorothiazide"], "ans": 0, "exp": "Sacubitril/valsartan (ARNI) ยับยั้ง neprilysin + block AT1 receptor ลด mortality เหนือ ACEI ใน HFrEF. ห้ามใช้ร่วม/ใกล้ ACEI (เสี่ยง angioedema) ต้องเว้น 36 ชม.", "id": "set1-42"}, {"topic": "Cardiology", "q": "ECG shows a wide QRS with an rSR' pattern in V1 and a slurred S wave in leads I and V6. What is it?", "choices": ["LBBB", "RBBB", "LVH", "WPW", "Hyperkalemia"], "ans": 1, "exp": "rSR' (rabbit ear) ที่ V1 + wide QRS + slurred S ที่ lateral leads = RBBB. LBBB จะมี broad monophasic R ที่ I/V6 และอาจ mask MI.", "id": "set1-43"}, {"topic": "Cardiology", "q": "In symptomatic severe aortic stenosis, which intervention improves survival?", "choices": ["Vasodilators", "Aortic valve replacement (SAVR/TAVI)", "Beta-blocker", "Balloon valvuloplasty as permanent therapy", "Diuretic alone"], "ans": 1, "exp": "Symptomatic severe AS มี prognosis แย่หากไม่ผ่าตัด การรักษาที่ปรับ prognosis คือ aortic valve replacement (surgical/TAVI). Vasodilator ต้องระวังเพราะ preload/afterload sensitive.", "id": "set1-44"}, {"topic": "Cardiology", "q": "Which antihypertensive class should be avoided in a patient with gout?", "choices": ["ACE inhibitor", "ARB", "High-dose thiazide diuretic", "Calcium channel blocker", "ARB plus CCB"], "ans": 2, "exp": "Thiazide เพิ่มกรดยูริกและกระตุ้น gout จึงควรหลีกเลี่ยง. ทางเลือกที่ดีกว่าเช่น CCB/ACEI/ARB (losartan มีฤทธิ์ลด uric เล็กน้อย).", "id": "set1-45"}, {"topic": "Cardiology", "q": "Using the rapid '300 rule', if the R-R interval spans 4 large boxes, the heart rate is approximately:", "choices": ["150", "100", "75", "60", "50"], "ans": 2, "exp": "300 หารด้วยจำนวนช่องใหญ่ระหว่าง R-R: 300/4 = 75 ครั้ง/นาที (1 ช่อง=300, 2=150, 3=100, 4=75, 5=60, 6=50).", "id": "set1-46"}, {"topic": "Cardiology", "q": "Which is first-line rate control for AF in a patient with normal EF and no heart failure?", "choices": ["Digoxin", "Beta-blocker or non-DHP calcium channel blocker", "Amiodarone", "Adenosine", "Ivabradine"], "ans": 1, "exp": "Rate control ใน AF ที่ EF ปกติ เริ่มด้วย beta-blocker หรือ non-DHP CCB (diltiazem/verapamil). Digoxin ใช้เสริมเมื่อมี HF/ความดันต่ำ. ใน HFrEF ห้าม non-DHP CCB.", "id": "set1-47"}, {"topic": "Cardiology", "q": "A 55-year-old man with prior MI has LDL-C 60 mg/dL on maximally tolerated statin. His residual risk is high. What is the reasonable next step to lower LDL further?", "choices": ["Stop statin", "Add ezetimibe ± PCSK9 inhibitor", "Switch to a fibrate", "Add niacin", "No change needed"], "ans": 1, "exp": "เป้า LDL หลัง ACS < 55; ที่ 60 ยังไม่ถึงเป้า ควรเพิ่ม ezetimibe และ/หรือ PCSK9 inhibitor ตามแนวทาง 2025 ACS lipid. Fibrate/niacin ไม่ใช่ตัวเลือกหลักลด LDL.", "id": "set1-48"}, {"topic": "Cardiology", "q": "A patient with new AF is planned for rhythm control. According to the 2023 AF guideline, in which group is early rhythm control/catheter ablation particularly favored as first-line?", "choices": ["Asymptomatic elderly with permanent AF", "Symptomatic AF, especially with HFrEF", "AF with mechanical valve only", "Isolated first episode resolved spontaneously", "AF with active major bleeding"], "ans": 1, "exp": "2023 ACC/AHA/ACCP/HRS เน้น early rhythm control และ catheter ablation เป็น first-line ในบางกลุ่ม เช่น symptomatic AF และผู้ป่วย HFrEF (ablation ลด mortality/HF hospitalization). และเน้น modify ปัจจัยเสี่ยง.", "id": "set1-49"}, {"topic": "Cardiology", "q": "A 65-year-old man has sudden severe 'tearing' chest pain radiating to the back, BP 180/100 in the right arm but 140/80 in the left arm, and a widened mediastinum on CXR. What is the most likely diagnosis?", "choices": ["Acute MI", "Aortic dissection", "Pulmonary embolism", "Pericarditis", "Pneumothorax"], "ans": 1, "exp": "เจ็บอกแบบ tearing ร้าวหลัง + ความดันสองแขนต่างกัน + mediastinum กว้าง = aortic dissection. Type A (ascending) ต้องผ่าตัดฉุกเฉิน; Type B คุมด้วยยา (beta-blocker ลด HR/BP ก่อน). ยืนยันด้วย CT angiography.", "id": "set1-50"}, {"topic": "Pulmonology", "q": "A 25-year-old with episodic wheeze and nocturnal cough has spirometry showing an obstructive pattern that improves after a bronchodilator (FEV1 rises 15% and 300 mL). What is the diagnosis?", "choices": ["COPD", "Asthma", "Bronchiectasis", "Interstitial lung disease", "Vocal cord dysfunction"], "ans": 1, "exp": "Reversible airflow obstruction (FEV1 เพิ่ม ≥12% และ ≥200 mL หลัง bronchodilator) + อาการเป็นๆ หายๆ = asthma. ต่างจาก COPD ที่ obstruction ไม่ reversible เต็มที่.", "id": "set1-51"}, {"topic": "Pulmonology", "q": "According to GINA 2025, what is the preferred reliever/controller strategy even in mild asthma?", "choices": ["SABA alone as needed", "ICS-formoterol as reliever (and maintenance)", "Oral steroid as needed", "LABA alone", "Theophylline"], "ans": 1, "exp": "GINA 2025 ห้ามใช้ SABA เดี่ยว; ทุกคนต้องได้ ICS-containing reliever โดยแนะนำ ICS-formoterol เป็นทั้ง reliever และ maintenance (AIR/MART) เพราะลดการกำเริบรุนแรงและการเสียชีวิต.", "id": "set1-52"}, {"topic": "Pulmonology", "q": "A patient with acute severe asthma is tiring; ABG shows a 'normal' PaCO2. How should this be interpreted?", "choices": ["Reassuring, improving", "Impending respiratory failure", "Metabolic alkalosis", "Normal finding", "Chronic compensation"], "ans": 1, "exp": "ในหอบรุนแรง ผู้ป่วยควร hyperventilate ทำให้ PaCO2 ต่ำ. PaCO2 ที่ 'ปกติ' หรือสูงขึ้นบ่งชี้กล้ามเนื้อหายใจล้า = impending respiratory failure ต้องเฝ้าใกล้ชิด/เตรียมช่วยหายใจ.", "id": "set1-53"}, {"topic": "Pulmonology", "q": "A 65-year-old smoker has chronic productive cough and dyspnea; post-bronchodilator FEV1/FVC is 0.60. What is the single most effective intervention to slow disease progression?", "choices": ["Inhaled corticosteroid", "Smoking cessation", "Theophylline", "Long-term antibiotics", "Mucolytics"], "ans": 1, "exp": "COPD (FEV1/FVC < 0.70 post-BD). การหยุดบุหรี่เป็นสิ่งเดียวที่ชะลอการเสื่อมของ lung function และลด mortality ได้ชัดเจนที่สุด. ยาสูดช่วยอาการ/ลด exacerbation แต่ไม่ชะลอ decline เท่า.", "id": "set1-54"}, {"topic": "Pulmonology", "q": "Under GOLD 2025, a COPD patient in Group B or Group E should be started on which initial inhaled therapy?", "choices": ["SABA as needed only", "LABA + LAMA combination", "ICS monotherapy", "Oral corticosteroid", "Theophylline"], "ans": 1, "exp": "GOLD 2025 แนะนำเริ่ม LABA + LAMA (คู่) ในทั้ง Group B และ Group E. Group A ใช้ bronchodilator เดี่ยว. เพิ่ม ICS (triple) เมื่อ eosinophil > 300 หรือ Group E ที่ eos สูง.", "id": "set1-55"}, {"topic": "Pulmonology", "q": "A COPD patient presents with increased dyspnea, sputum volume, and purulence. Besides bronchodilators and systemic steroids, what else is indicated?", "choices": ["Antibiotics", "Immediate intubation", "IV magnesium", "Diuretics", "Long-term oxygen at home"], "ans": 0, "exp": "AECOPD ที่มี cardinal symptoms ครบ (เหนื่อยเพิ่ม + เสมหะเพิ่ม + เสมหะเป็นหนอง) หรือเสมหะเป็นหนอง+อีก 1 ข้อ หรือต้องใช้ ventilator → ให้ antibiotics ร่วมกับ SABA±SAMA และ systemic corticosteroid 5 วัน.", "id": "set1-56"}, {"topic": "Pulmonology", "q": "A COPD patient in exacerbation has pH 7.28, PaCO2 68. What is the most appropriate respiratory support?", "choices": ["High-flow oxygen to normalize SpO2 to 100%", "Non-invasive ventilation (BiPAP)", "Immediate tracheostomy", "Nasal cannula only", "Sedation"], "ans": 1, "exp": "Hypercapnic respiratory acidosis (pH < 7.35, PaCO2 สูง) ใน AECOPD ตอบสนองดีต่อ NIV (BiPAP) ซึ่งลดการใส่ท่อและ mortality. ให้ O2 แบบควบคุม (เป้า SpO2 88–92%) ไม่ใช่ให้จนถึง 100%.", "id": "set1-57"}, {"topic": "Pulmonology", "q": "A previously healthy adult with CAP has CURB-65 = 0 and no comorbidities. What is appropriate first-line outpatient therapy?", "choices": ["IV ceftriaxone + azithromycin", "High-dose amoxicillin (or a macrolide/doxycycline)", "Respiratory fluoroquinolone IV", "Vancomycin", "No antibiotic"], "ans": 1, "exp": "CAP ที่ CURB-65 ต่ำและไม่มีโรคร่วม รักษาแบบผู้ป่วยนอกด้วย amoxicillin ขนาดสูง หรือ macrolide/doxycycline. ผู้มีโรคร่วมใช้ β-lactam + macrolide หรือ respiratory FQ; admit ใช้ ceftriaxone + azithromycin.", "id": "set1-58"}, {"topic": "Pulmonology", "q": "A 32-year-old man with HIV (CD4 120) has 3 weeks of exertional dyspnea, dry cough, SpO2 88%, and bilateral perihilar interstitial infiltrates. Which test best confirms the diagnosis?", "choices": ["Sputum AFB smear/culture", "PCR for Mycoplasma", "Immunofluorescence of induced sputum for Pneumocystis jirovecii", "Blood culture for pneumococcus", "Urine Legionella antigen"], "ans": 2, "exp": "ภาพเข้าได้กับ PCP (Pneumocystis jirovecii) ใน HIV ที่ CD4 < 200. ยืนยันด้วย immunofluorescence/stain ของ induced sputum หรือ BAL. รักษาด้วย high-dose co-trimoxazole + steroid ถ้า PaO2 ต่ำ/A-a gradient กว้าง. (แนวข้อสอบ NLE2)", "id": "set1-59"}, {"topic": "Pulmonology", "q": "A 50-year-old with 2 weeks of productive cough, hemoptysis, night sweats, and a right-upper-lobe cavity on CXR most likely has:", "choices": ["Community-acquired pneumonia", "Pulmonary tuberculosis", "Lung abscess from aspiration", "Pulmonary embolism", "Sarcoidosis"], "ans": 1, "exp": "ไอเรื้อรัง + ไอเป็นเลือด + เหงื่อกลางคืน + upper-lobe cavity เข้าได้กับ pulmonary TB. ยืนยันด้วย sputum AFB/Xpert MTB/RIF (บอกดื้อ rifampicin) + culture.", "id": "set1-60"}, {"topic": "Pulmonology", "q": "According to WHO 2022, which regimen is now an option for drug-susceptible pulmonary TB?", "choices": ["A 4-month rifapentine–moxifloxacin regimen", "A 24-month injectable regimen", "Isoniazid monotherapy", "Rifampicin alone for 2 months", "BPaL for all cases"], "ans": 0, "exp": "WHO 2022 มีสูตร 4 เดือนสำหรับ DS-TB (2 เดือน HPZM + 2 เดือน HPM, rifapentine+moxifloxacin) เป็นทางเลือกนอกเหนือสูตร 6 เดือน 2HRZE/4HR. BPaL/BPaLM ใช้กับ DR-TB.", "id": "set1-61"}, {"topic": "Pulmonology", "q": "Which anti-TB drug most classically causes optic neuritis (reduced visual acuity and color vision)?", "choices": ["Isoniazid", "Rifampicin", "Pyrazinamide", "Ethambutol", "Streptomycin"], "ans": 3, "exp": "Ethambutol ทำให้เกิด optic neuritis (visual acuity/color vision ลด). INH → peripheral neuropathy (ให้ pyridoxine); Rifampicin → orange secretions; PZA → hyperuricemia; ทั้งกลุ่มเสี่ยง hepatitis.", "id": "set1-62"}, {"topic": "Pulmonology", "q": "A pleural effusion has pleural/serum protein ratio 0.7 and pleural/serum LDH ratio 0.8. How is it classified and what does it suggest?", "choices": ["Transudate; heart failure", "Exudate; infection/malignancy/TB", "Transudate; cirrhosis", "Chylothorax", "Hemothorax"], "ans": 1, "exp": "เข้าเกณฑ์ Light's criteria เป็น exudate (protein ratio > 0.5 หรือ LDH ratio > 0.6). สาเหตุ exudate = infection (parapneumonic/empyema), malignancy, TB. Transudate = HF, cirrhosis, nephrotic.", "id": "set1-63"}, {"topic": "Pulmonology", "q": "A parapneumonic effusion has pH 7.10, low glucose, and frank pus. What is the appropriate management?", "choices": ["Antibiotics alone", "Chest tube drainage plus antibiotics", "Observation", "Diuretics", "Repeat tap in 1 week"], "ans": 1, "exp": "Complicated parapneumonic effusion/empyema (pH < 7.2, glucose ต่ำ, หนอง) ต้องระบายด้วย chest tube (ICD) ร่วมกับ antibiotics; อาจต้อง fibrinolytic/VATS ถ้า loculated.", "id": "set1-64"}, {"topic": "Pulmonology", "q": "A tall thin young man has sudden pleuritic chest pain and dyspnea; exam shows hyperresonance and absent breath sounds on one side with tracheal deviation and hypotension. What is the immediate action?", "choices": ["Chest X-ray first", "Needle/finger decompression then chest tube", "CT chest", "Observation and oxygen only", "Intubation only"], "ans": 1, "exp": "อาการเข้ากับ tension pneumothorax (hypotension + tracheal deviation) เป็นการวินิจฉัยทางคลินิก อย่ารอ CXR ต้อง decompress ทันที (needle/finger) แล้วใส่ ICD.", "id": "set1-65"}, {"topic": "Pulmonology", "q": "Which describes type 2 (hypercapnic) respiratory failure?", "choices": ["PaO2 < 60 with normal/low PaCO2", "PaCO2 > 45 with respiratory acidosis", "Normal ABG", "Metabolic acidosis only", "Isolated hypoxemia from shunt"], "ans": 1, "exp": "Type 2 respiratory failure = hypoventilation → PaCO2 > 45 + respiratory acidosis (COPD, neuromuscular, CNS depression). Type 1 = hypoxemic (PaO2 < 60, PaCO2 ปกติ/ต่ำ) จาก V/Q mismatch/shunt.", "id": "set1-66"}, {"topic": "Pulmonology", "q": "ABG: pH 7.30, HCO3 14, PaCO2 30, Na 140, Cl 100. What is the primary disorder?", "choices": ["Respiratory acidosis", "High anion gap metabolic acidosis", "Metabolic alkalosis", "Respiratory alkalosis", "Normal"], "ans": 1, "exp": "pH ต่ำ + HCO3 ต่ำ = metabolic acidosis; anion gap = 140 − 100 − 14 = 26 (สูง) → high anion gap metabolic acidosis. PaCO2 30 = respiratory compensation (Winter: 1.5×14+8=29 ≈ เหมาะสม). สาเหตุ MUDPILES.", "id": "set1-67"}, {"topic": "Pulmonology", "q": "Which condition causes a NORMAL anion gap (hyperchloremic) metabolic acidosis?", "choices": ["Diabetic ketoacidosis", "Lactic acidosis", "Severe diarrhea", "Methanol poisoning", "Uremia"], "ans": 2, "exp": "Severe diarrhea เสีย HCO3 ทาง GI ทำให้ normal anion gap (hyperchloremic) metabolic acidosis. DKA, lactic acidosis, methanol, uremia ล้วนเป็น high anion gap (MUDPILES).", "id": "set1-68"}, {"topic": "Pulmonology", "q": "A patient with sepsis-related ARDS has bilateral infiltrates and PaO2/FiO2 = 150 with no cardiac cause. Which ventilator strategy is recommended?", "choices": ["High tidal volume 12 mL/kg", "Lung-protective ventilation (Vt ~6 mL/kg, plateau < 30) + consider prone", "High FiO2 with high PEEP only", "Permissive hyperoxia", "Avoid PEEP"], "ans": 1, "exp": "ARDS ใช้ lung-protective ventilation (Vt 6 mL/kg predicted BW, plateau pressure < 30) + prone positioning ในราย moderate-severe + จัดการสาเหตุ. High tidal volume เพิ่ม ventilator-induced lung injury.", "id": "set1-69"}, {"topic": "Pulmonology", "q": "A post-operative patient develops sudden dyspnea and pleuritic chest pain; Wells score is high. What is the best confirmatory test?", "choices": ["D-dimer", "CT pulmonary angiography", "Chest X-ray", "Echocardiography", "Sputum culture"], "ans": 1, "exp": "เมื่อ pretest probability สูง (Wells สูง) ควรทำ CT pulmonary angiography (gold standard) เลย ไม่ใช้ D-dimer (มีประโยชน์เฉพาะ low/intermediate เพื่อ rule out). V/Q scan ใช้เมื่อทำ CT ไม่ได้.", "id": "set1-70"}, {"topic": "Pulmonology", "q": "A hemodynamically unstable patient with massive PE and shock should receive:", "choices": ["Anticoagulation with DOAC only", "Systemic thrombolysis (or embolectomy)", "IVC filter alone", "Aspirin", "Observation"], "ans": 1, "exp": "Massive PE (hypotension/shock) มี indication สำหรับ systemic thrombolysis (หรือ catheter/surgical embolectomy ถ้ามีข้อห้าม) นอกเหนือจาก anticoagulation. Submassive/stable ใช้ anticoagulation เป็นหลัก.", "id": "set1-71"}, {"topic": "Pulmonology", "q": "A 55-year-old heavy smoker has a spiculated 2 cm lung nodule that grew compared to a prior film. What is the most appropriate next step?", "choices": ["Repeat CXR in 1 year", "Tissue diagnosis (biopsy) ± PET/CT staging", "Reassure, no follow-up", "Start empiric antibiotics", "Start anti-TB drugs"], "ans": 1, "exp": "Nodule ที่ spiculated, โตขึ้น, ในผู้สูบจัด = เสี่ยงมะเร็งสูง ควร characterize ด้วย CT/PET และ tissue diagnosis (biopsy) เพื่อวินิจฉัยและ staging. การรอเฉยเหมาะกับ nodule เสี่ยงต่ำเท่านั้น.", "id": "set1-72"}, {"topic": "Pulmonology", "q": "Which lung cancer is most strongly associated with SIADH and Cushing (ectopic ACTH) paraneoplastic syndromes?", "choices": ["Adenocarcinoma", "Squamous cell carcinoma", "Small cell lung cancer", "Large cell carcinoma", "Carcinoid"], "ans": 2, "exp": "Small cell lung cancer (SCLC) สัมพันธ์ paraneoplastic ที่เป็น neuroendocrine เช่น SIADH และ ectopic ACTH (Cushing), Lambert-Eaton. Squamous cell → hypercalcemia (PTHrP).", "id": "set1-73"}, {"topic": "Pulmonology", "q": "A squamous cell lung cancer patient presents with confusion, constipation, and a calcium of 13 mg/dL. What is the mechanism?", "choices": ["SIADH", "PTHrP secretion (humoral hypercalcemia)", "Ectopic ACTH", "Bone metastasis only", "Hypoparathyroidism"], "ans": 1, "exp": "Squamous cell carcinoma หลั่ง PTHrP ทำให้เกิด humoral hypercalcemia of malignancy (hyperCa → stones/bones/groans/moans). รักษา IV fluid + bisphosphonate/calcitonin + รักษามะเร็ง.", "id": "set1-74"}, {"topic": "Pulmonology", "q": "Which oxygen delivery device most precisely controls FiO2, useful in COPD patients at risk of CO2 retention?", "choices": ["Nasal cannula", "Simple face mask", "Venturi mask", "Non-rebreather mask", "Bag-valve mask"], "ans": 2, "exp": "Venturi mask ให้ FiO2 ที่แม่นยำ (24–60%) จึงเหมาะกับ COPD ที่ต้องคุม O2 (เป้า SpO2 88–92%) เพื่อเลี่ยง CO2 retention. Non-rebreather ให้ FiO2 สูงแต่ควบคุมไม่แม่น.", "id": "set1-75"}, {"topic": "Pulmonology", "q": "A patient with stable COPD has resting PaO2 54 mmHg (SpO2 87%). Which intervention improves survival?", "choices": ["Inhaled steroid", "Long-term oxygen therapy (>15 h/day)", "Theophylline", "Prophylactic antibiotics", "Mucolytics"], "ans": 1, "exp": "Long-term oxygen therapy (LTOT) ในผู้ป่วย COPD ที่ PaO2 ≤ 55 หรือ SpO2 ≤ 88% (หรือ ≤ 59/89% ที่มี cor pulmonale/polycythemia) ช่วยเพิ่มอัตราการรอดชีวิตเมื่อใช้ > 15 ชม./วัน.", "id": "set1-76"}, {"topic": "Pulmonology", "q": "A young non-smoker with recurrent pneumonia, chronic cough with copious purulent sputum, and 'tram-track' opacities most likely has:", "choices": ["Asthma", "Bronchiectasis", "Simple chronic bronchitis", "Pulmonary fibrosis", "Sarcoidosis"], "ans": 1, "exp": "อาการไอเสมหะมากเรื้อรัง + ปอดอักเสบซ้ำ + tram-track/ring shadow เข้าได้กับ bronchiectasis (ยืนยันด้วย HRCT). หาสาเหตุ (post-infection, CF, immunodeficiency) + airway clearance + ATB เวลากำเริบ.", "id": "set1-77"}, {"topic": "Pulmonology", "q": "Which finding on examination suggests consolidation (e.g., lobar pneumonia)?", "choices": ["Hyperresonance and absent breath sounds", "Bronchial breath sounds, increased vocal fremitus, egophony", "Tracheal deviation away", "Wheeze only", "Pleural rub only"], "ans": 1, "exp": "Consolidation ทำให้เสียงส่งผ่านดีขึ้น: bronchial breath sound, increased tactile/vocal fremitus, egophony (E→A), dullness to percussion. Hyperresonance + absent breath sound = pneumothorax.", "id": "set1-78"}, {"topic": "Pulmonology", "q": "A patient has an exudative lymphocyte-predominant pleural effusion with high adenosine deaminase (ADA). What is the most likely cause in an endemic area?", "choices": ["Heart failure", "Tuberculous pleuritis", "Rheumatoid effusion", "Chylothorax", "Empyema"], "ans": 1, "exp": "Exudate ที่ lymphocyte เด่น + ADA สูง ในพื้นที่ระบาด เข้าได้กับ tuberculous pleuritis. ยืนยันด้วย pleural biopsy (granuloma)/culture; ตอบสนองดีต่อ anti-TB.", "id": "set1-79"}, {"topic": "Pulmonology", "q": "What is the classic ECG finding sometimes seen in acute pulmonary embolism (though sinus tachycardia is most common)?", "choices": ["Delta wave", "S1Q3T3", "Peaked T waves", "U waves", "Osborn wave"], "ans": 1, "exp": "S1Q3T3 (S ใน I, Q และ T inversion ใน III) เป็น classic แต่พบไม่บ่อยใน PE; สิ่งที่พบบ่อยสุดคือ sinus tachycardia. อาจเห็น RV strain (T inversion V1–V4).", "id": "set1-80"}, {"topic": "Pulmonology", "q": "A patient on long-term home oxygen for COPD suddenly becomes drowsy after oxygen was turned up to high flow. What happened?", "choices": ["Oxygen toxicity seizure", "CO2 retention/hypercapnia worsened by uncontrolled high-flow O2", "Hypoglycemia", "Pulmonary embolism", "Pneumothorax"], "ans": 1, "exp": "ในบาง COPD ที่เป็น chronic CO2 retainer การให้ O2 สูงเกินไปอาจทำให้ CO2 คั่งมากขึ้น (ลด hypoxic drive + V/Q + Haldane effect) → ซึม. ควรให้ O2 แบบควบคุมเป้า SpO2 88–92% และตรวจ ABG.", "id": "set1-81"}, {"topic": "Pulmonology", "q": "Which is the initial diagnostic test of choice to confirm airflow obstruction in suspected COPD?", "choices": ["Chest CT", "Spirometry (post-bronchodilator FEV1/FVC)", "Peak flow only", "ABG", "D-dimer"], "ans": 1, "exp": "COPD ยืนยันด้วย spirometry ที่ post-bronchodilator FEV1/FVC < 0.70. CXR/CT ช่วยดู complication/ตัดสาเหตุอื่น แต่ไม่ใช้วินิจฉัยหลัก.", "id": "set1-82"}, {"topic": "Pulmonology", "q": "A patient with asthma has frequent night symptoms despite low-dose ICS-formoterol maintenance. According to GINA, what is the appropriate step-up?", "choices": ["Add SABA only", "Increase to medium-dose ICS-formoterol", "Stop ICS", "Oral steroid long-term", "Add antibiotics"], "ans": 1, "exp": "เมื่อคุมไม่ได้ด้วย low-dose ICS-formoterol maintenance (step 3) ให้ step up เป็น medium-dose ICS-formoterol (step 4) ก่อนพิจารณา LAMA/biologic (step 5). ตรวจ adherence/inhaler technique/trigger ก่อนเสมอ.", "id": "set1-83"}, {"topic": "Pulmonology", "q": "A patient develops an anaphylactic reaction with wheeze, hypotension, and angioedema after a bee sting. What is the first-line drug?", "choices": ["IV hydrocortisone", "Intramuscular adrenaline (epinephrine)", "IV antihistamine", "Nebulized salbutamol", "IV fluids only"], "ans": 1, "exp": "Anaphylaxis รักษาลำดับแรกด้วย IM adrenaline (epinephrine) ที่ต้นขาด้านนอก ทันที + วางราบ/ยกขา + O2 + IV fluid; steroid/antihistamine เป็น adjunct ไม่ใช่ตัวหลัก.", "id": "set1-84"}, {"topic": "Pulmonology", "q": "A patient with idiopathic pulmonary fibrosis has fine bibasal 'velcro' crackles and reticular changes with honeycombing at the bases on HRCT. Which is true about management?", "choices": ["High-dose steroid cures it", "Antifibrotics (pirfenidone/nintedanib) slow decline", "Antibiotics are curative", "Bronchodilators reverse it", "No treatment affects progression"], "ans": 1, "exp": "IPF (UIP pattern: subpleural basal reticulation + honeycombing) รักษาด้วย antifibrotic (pirfenidone/nintedanib) ชะลอการเสื่อมของ FVC; steroid ไม่ช่วยและอาจอันตรายใน IPF. พิจารณา lung transplant.", "id": "set1-85"}, {"topic": "Pulmonology", "q": "A diabetic patient has fever, right-sided chest pain, and CXR shows a cavity with an air-fluid level following an aspiration event. What is the likely diagnosis?", "choices": ["Tuberculosis", "Lung abscess", "Pulmonary embolism", "Sarcoidosis", "Lung cancer"], "ans": 1, "exp": "หลัง aspiration + cavity ที่มี air-fluid level = lung abscess (มัก anaerobe/mixed oral flora, บริเวณ dependent เช่น RLL/posterior segment). รักษาด้วย antibiotics คลุม anaerobe (clindamycin/β-lactam-β-lactamase inhibitor) นาน.", "id": "set1-86"}, {"topic": "Pulmonology", "q": "A young woman has dyspnea, bilateral hilar lymphadenopathy on CXR, erythema nodosum, and elevated serum ACE. What is the most likely diagnosis?", "choices": ["Tuberculosis", "Sarcoidosis", "Lymphoma", "Silicosis", "Histoplasmosis"], "ans": 1, "exp": "Bilateral hilar lymphadenopathy + erythema nodosum + ACE สูง เข้าได้กับ sarcoidosis (non-caseating granuloma). Löfgren syndrome (arthritis + BHL + erythema nodosum) พยากรณ์ดี มักหายเอง.", "id": "set1-87"}, {"topic": "Pulmonology", "q": "In interpreting a chest X-ray, Kerley B lines and cephalization of vessels suggest:", "choices": ["Pneumonia", "Pulmonary edema (cardiogenic congestion)", "Pneumothorax", "Emphysema", "Pleural effusion only"], "ans": 1, "exp": "Kerley B lines + cephalization + perihilar (bat-wing) opacities + cardiomegaly เข้าได้กับ cardiogenic pulmonary edema. ช่วยแยกจาก ARDS ที่หัวใจปกติและ infiltrate กระจายทั่ว.", "id": "set1-88"}, {"topic": "Pulmonology", "q": "A patient with severe CAP requiring ICU admission should receive which empiric regimen?", "choices": ["Oral amoxicillin", "IV beta-lactam (e.g., ceftriaxone) plus a macrolide or respiratory fluoroquinolone", "Oral doxycycline alone", "Vancomycin alone", "No antibiotics until culture"], "ans": 1, "exp": "Severe CAP (ICU) ใช้ IV β-lactam (ceftriaxone) + macrolide (azithromycin) หรือ respiratory fluoroquinolone. พิจารณาคลุม MRSA/Pseudomonas ตามความเสี่ยง.", "id": "set1-89"}, {"topic": "Pulmonology", "q": "A patient with obstructive sleep apnea has daytime somnolence and witnessed apneas. What is the first-line treatment for moderate-to-severe OSA?", "choices": ["Weight loss only", "Continuous positive airway pressure (CPAP)", "Nocturnal oxygen", "Sedatives", "Tracheostomy"], "ans": 1, "exp": "OSA ระดับปานกลาง-รุนแรง first-line คือ CPAP (ร่วมกับลดน้ำหนัก/เลี่ยงแอลกอฮอล์-ยานอนหลับ). O2 เดี่ยวไม่แก้ obstruction; sedative จะทำให้แย่ลง.", "id": "set1-90"}, {"topic": "Pulmonology", "q": "A patient with massive hemoptysis (>200 mL/day). What is the priority in initial management?", "choices": ["Immediate lobectomy", "Airway protection and positioning bleeding side down", "Give thrombolytics", "Start anticoagulation", "Discharge with cough suppressant"], "ans": 1, "exp": "Massive hemoptysis เสี่ยง asphyxiation มากกว่า exsanguination — จัดการ airway ก่อน (ป้องกันเลือดท่วมปอดดี, จัดท่าให้ข้างที่เลือดออกอยู่ล่าง), resuscitate, แล้ว localize (bronchoscopy/CT) + bronchial artery embolization; หลีกเลี่ยง anticoagulant.", "id": "set1-91"}, {"topic": "Pulmonology", "q": "Which criterion is part of CURB-65 for pneumonia severity?", "choices": ["Age ≥ 50", "Confusion, Urea > 19 mg/dL (7 mmol/L), RR ≥ 30, BP < 90/60, Age ≥ 65", "WBC > 12,000", "CRP > 100", "SpO2 < 95%"], "ans": 1, "exp": "CURB-65 = Confusion, Urea > 7 mmol/L (~19 mg/dL BUN), RR ≥ 30, BP (SBP<90 หรือ DBP≤60), Age ≥ 65. คะแนนสูงขึ้น = พิจารณา admit/ICU.", "id": "set1-92"}, {"topic": "Pulmonology", "q": "A febrile neutropenic oncology patient develops cough and a new lung infiltrate. Empiric antibiotics should be started within what time frame?", "choices": ["24 hours", "Within 1 hour", "72 hours", "After culture results", "Only if unstable"], "ans": 1, "exp": "Febrile neutropenia เป็นภาวะฉุกเฉิน ต้องให้ empiric broad-spectrum antibiotic (คลุม Pseudomonas เช่น piperacillin-tazobactam/cefepime/carbapenem) ภายใน 1 ชม.หลังเจาะ culture.", "id": "set1-93"}, {"topic": "Pulmonology", "q": "A patient with COPD is assessed for exacerbation risk. Which parameter guides the addition of inhaled corticosteroid to LABA/LAMA?", "choices": ["Serum CRP", "Blood eosinophil count", "D-dimer", "BNP", "Serum IgE only"], "ans": 1, "exp": "GOLD ใช้ blood eosinophil count นำการเพิ่ม ICS: เพิ่ม ICS (triple therapy) เมื่อ eos ≥ 300 หรือใน Group E ที่ eos สูง/ประวัติ exacerbation บ่อย; หลีกเลี่ยง ICS ถ้า eos < 100 (ประโยชน์น้อย เสี่ยงปอดอักเสบ).", "id": "set1-94"}, {"topic": "Pulmonology", "q": "A 40-year-old presents with acute hypersensitivity: fever, cough, and dyspnea hours after exposure to moldy hay, with diffuse ground-glass on CT. What is the diagnosis?", "choices": ["Asthma", "Hypersensitivity pneumonitis", "Bacterial pneumonia", "Pulmonary embolism", "COPD"], "ans": 1, "exp": "อาการหลังสัมผัส antigen (moldy hay = Farmer's lung) + ไข้/ไอ/เหนื่อย + ground-glass เข้าได้กับ hypersensitivity pneumonitis. การรักษาสำคัญคือหลีกเลี่ยง antigen ± corticosteroid.", "id": "set1-95"}, {"topic": "Pulmonology", "q": "Which best differentiates cardiogenic pulmonary edema (type of respiratory failure) from ARDS?", "choices": ["Bilateral infiltrates present in both", "Elevated BNP and cardiac cause supports cardiogenic edema", "PaO2/FiO2 ratio", "Presence of dyspnea", "Need for oxygen"], "ans": 1, "exp": "ทั้งคู่มี bilateral infiltrate + hypoxemia. สิ่งที่แยกคือหลักฐานของ cardiac cause (BNP สูง, EF ต่ำ, cardiomegaly, response to diuretic) ใน cardiogenic edema; ARDS ไม่ได้เกิดจาก hydrostatic/cardiac เพียงอย่างเดียว.", "id": "set1-96"}, {"topic": "Pulmonology", "q": "A patient develops stridor and drooling with rapid-onset severe sore throat and high fever; he is sitting forward (tripod). What is the immediate concern?", "choices": ["Viral pharyngitis", "Acute epiglottitis (airway emergency)", "Common cold", "Allergic rhinitis", "Tonsillar stone"], "ans": 1, "exp": "Stridor + drooling + tripod position + toxic เข้าได้กับ acute epiglottitis เป็นภาวะฉุกเฉินทางเดินหายใจ — ห้ามตรวจคอโดยไม่พร้อม, ให้ secure airway โดยผู้เชี่ยวชาญ + IV antibiotics (ceftriaxone).", "id": "set1-97"}, {"topic": "Pulmonology", "q": "A patient recovering from viral illness develops a normal-anion-gap picture with rapid deep breathing (Kussmaul) — actually found to have DKA. Kussmaul breathing represents what compensation?", "choices": ["Respiratory acidosis", "Respiratory compensation for metabolic acidosis", "Metabolic alkalosis", "Primary respiratory alkalosis", "No compensation"], "ans": 1, "exp": "Kussmaul breathing (หายใจลึกเร็ว) เป็น respiratory compensation ต่อ metabolic acidosis (เช่น DKA) เพื่อขับ CO2 ลด acidemia. คำนวณด้วย Winter's formula เพื่อดูว่า compensation เหมาะสม.", "id": "set1-98"}, {"topic": "Pulmonology", "q": "Which patient with a solitary pulmonary nodule can be safely followed with serial imaging rather than immediate biopsy?", "choices": ["Spiculated, growing nodule in a heavy smoker", "Small (<6 mm) smooth nodule with benign (popcorn/central) calcification in a low-risk patient", "Nodule with PET avidity", "Nodule with cavitation and weight loss", "Enlarging nodule over 3 months"], "ans": 1, "exp": "Nodule ที่เล็ก, ขอบเรียบ, มี benign calcification (popcorn = hamartoma, central/laminated), ในคนเสี่ยงต่ำ มีโอกาสมะเร็งต่ำ ติดตามด้วย imaging ได้. ลักษณะเสี่ยง (spiculated, โตเร็ว, PET avid, สูบจัด) → biopsy.", "id": "set1-99"}, {"topic": "Pulmonology", "q": "A patient presents with acute dyspnea and wheeze. Which single feature most strongly indicates a life-threatening asthma attack requiring immediate escalation?", "choices": ["Peak flow 70% predicted", "Silent chest with inability to speak in full sentences", "Mild expiratory wheeze", "Respiratory rate 18", "SpO2 97%"], "ans": 1, "exp": "Silent chest (airflow น้อยจนไม่ได้ยิน wheeze) + พูดไม่จบประโยค + ใช้กล้ามเนื้อช่วยหายใจ = life-threatening asthma. ต้อง O2, nebulized SABA+ipratropium ซ้ำ, systemic steroid, IV magnesium และเตรียมช่วยหายใจ.", "id": "set1-100"}]}, {"id": "set2", "title": "ชุดที่ 2 — Nephrology + Endocrine", "questions": [{"topic": "Nephrology", "q": "A hypotensive patient after GI bleeding has oliguria, BUN/Cr ratio 25, FeNa 0.5%, and concentrated urine. What type of AKI is this?", "choices": ["Prerenal azotemia", "Acute tubular necrosis", "Acute interstitial nephritis", "Postrenal obstruction", "Glomerulonephritis"], "ans": 0, "exp": "BUN/Cr > 20, FeNa < 1%, urine เข้มข้น + ประวัติ hypovolemia = prerenal AKI (ไตยัง reabsorb Na/น้ำได้ดี). รักษาโดยแก้ volume; ถ้าปล่อยไว้อาจกลายเป็น ATN.", "id": "set2-1"}, {"topic": "Nephrology", "q": "A patient develops AKI after prolonged hypotension; urine shows muddy brown granular casts and FeNa 3%. What is the diagnosis?", "choices": ["Prerenal azotemia", "Acute tubular necrosis", "Postrenal obstruction", "Minimal change disease", "Prerenal from CHF"], "ans": 1, "exp": "Muddy brown granular cast + FeNa > 2% (ไตเสียความสามารถ reabsorb Na) หลัง ischemia/hypotension = acute tubular necrosis. รักษาแบบประคับประคอง หลีกเลี่ยง nephrotoxin, รอ recovery.", "id": "set2-2"}, {"topic": "Nephrology", "q": "Which is an absolute indication for urgent dialysis in AKI?", "choices": ["BUN 40 mg/dL", "Refractory hyperkalemia or pulmonary edema, severe acidosis, uremic complications, or intoxication", "Cr 2.5 mg/dL", "Mild metabolic acidosis", "Proteinuria"], "ans": 1, "exp": "ข้อบ่งชี้ dialysis (AEIOU): Acidosis รุนแรงดื้อยา, Electrolyte (hyperK ดื้อยา), Intoxication, Overload (pulmonary edema ดื้อยา), Uremia (encephalopathy/pericarditis/bleeding). ค่า BUN/Cr เดี่ยวไม่ใช่ข้อบ่งชี้.", "id": "set2-3"}, {"topic": "Nephrology", "q": "A patient started on an ACE inhibitor for hypertension has a creatinine rise of 40% within a week and a bruit is heard over the abdomen. What is the likely cause?", "choices": ["Bilateral renal artery stenosis", "Diabetic nephropathy", "Glomerulonephritis", "Dehydration only", "Normal ACEI effect"], "ans": 0, "exp": "Cr เพิ่มมาก (> 30%) หลังเริ่ม ACEI + abdominal bruit นึกถึง bilateral renal artery stenosis ซึ่ง efferent arteriole พึ่ง angiotensin II เพื่อคง GFR. หยุด ACEI และประเมิน renal artery.", "id": "set2-4"}, {"topic": "Nephrology", "q": "A CKD patient has Hb 8.5, low iron studies corrected, and no bleeding. What is the main mechanism of the anemia?", "choices": ["Iron deficiency only", "Reduced erythropoietin production", "Hemolysis", "B12 deficiency", "Thalassemia"], "ans": 1, "exp": "Anemia of CKD เกิดจากไตผลิต erythropoietin ลดลง (normocytic normochromic). รักษาด้วย ESA (erythropoiesis-stimulating agent) หลังแก้ iron ให้พอ; เป้า Hb ไม่สูงเกิน (~10–11.5).", "id": "set2-5"}, {"topic": "Nephrology", "q": "Which medication class is now recommended to slow CKD progression in a patient with eGFR 30 and albuminuria (per KDIGO 2024)?", "choices": ["Loop diuretic", "SGLT2 inhibitor", "Calcium channel blocker", "Beta-blocker", "NSAID"], "ans": 1, "exp": "KDIGO 2024 แนะนำ SGLT2 inhibitor ใน CKD (eGFR ≥ 20) ที่มี albuminuria (ACR ≥ 200) หรือ HF เพื่อชะลอการเสื่อมของไต ร่วมกับ ACEI/ARB. Finerenone เพิ่มเติมใน T2D + albuminuria.", "id": "set2-6"}, {"topic": "Nephrology", "q": "A patient with type 2 diabetes, eGFR 40, albuminuria persists despite maximal ARB and an SGLT2i, K+ normal. What can be added to further reduce albuminuria?", "choices": ["Spironolactone (steroidal)", "Finerenone (nonsteroidal MRA)", "Another ARB", "Amlodipine", "Hydralazine"], "ans": 1, "exp": "KDIGO/ADA แนะนำ finerenone (nonsteroidal MRA) ใน T2D + albuminuria, eGFR > 25, K+ ปกติ ที่ยังมี albuminuria แม้ใช้ RASi เต็มที่ — ลด CV/renal events. ไม่ใช้ ACEI+ARB ร่วมกัน.", "id": "set2-7"}, {"topic": "Nephrology", "q": "A patient has serum Na 118 mmol/L, is euvolemic, with high urine osmolality and urine Na > 40. Which is the most likely cause?", "choices": ["Diarrhea", "SIADH", "Heart failure", "Diabetes insipidus", "Adrenal excess"], "ans": 1, "exp": "Euvolemic hyponatremia + urine osmolality สูง + urine Na สูง = SIADH (หลัง exclude hypothyroid/adrenal insufficiency). สาเหตุ: CNS, ปอด (SCLC), ยา, ปวด/คลื่นไส้. รักษาจำกัดน้ำ + แก้สาเหตุ.", "id": "set2-8"}, {"topic": "Nephrology", "q": "When correcting severe chronic hyponatremia, what complication results from correcting too rapidly?", "choices": ["Cerebral edema", "Osmotic demyelination syndrome (central pontine myelinolysis)", "Seizure from hypocalcemia", "Rhabdomyolysis", "Hyperkalemia"], "ans": 1, "exp": "แก้ Na เร็วเกิน (> 8–10 mEq/L/24 ชม.) ใน chronic hyponatremia เสี่ยง osmotic demyelination (central pontine myelinolysis). แก้ hypernatremia เร็วเกินต่างหากที่เสี่ยง cerebral edema.", "id": "set2-9"}, {"topic": "Nephrology", "q": "A patient with CKD has ECG showing peaked T waves and K+ 7.2. After IV calcium, which combination best shifts potassium into cells?", "choices": ["Furosemide", "Insulin with glucose (± nebulized salbutamol)", "Kayexalate", "Sodium bicarbonate alone", "Normal saline"], "ans": 1, "exp": "หลัง calcium gluconate (stabilize membrane) ให้ insulin + glucose (± beta-agonist) เพื่อ shift K เข้าเซลล์อย่างรวดเร็ว. Furosemide/resin/dialysis กำจัด K ออกจากร่างกาย (ช้ากว่า).", "id": "set2-10"}, {"topic": "Nephrology", "q": "A patient with hypokalemia does not improve despite potassium replacement. What should be checked and corrected?", "choices": ["Serum magnesium", "Serum calcium", "Serum phosphate", "Serum albumin", "TSH"], "ans": 0, "exp": "Hypokalemia ที่ดื้อต่อการเติม K มักมี hypomagnesemia ร่วม (Mg ต่ำทำให้ renal K wasting) ต้องแก้ Mg ก่อน K จึงจะขึ้น.", "id": "set2-11"}, {"topic": "Nephrology", "q": "A patient has hypercalcemia with 'stones, bones, groans, and psychiatric moans'. PTH is elevated and phosphate is low. What is the diagnosis?", "choices": ["Malignancy hypercalcemia", "Primary hyperparathyroidism", "Vitamin D toxicity", "Sarcoidosis", "Milk-alkali syndrome"], "ans": 1, "exp": "Hypercalcemia + PTH สูง + phosphate ต่ำ = primary hyperparathyroidism (มัก parathyroid adenoma). ต่างจาก malignancy ที่ PTH ต่ำ (PTHrP). รักษา parathyroidectomy ถ้าเข้าเกณฑ์.", "id": "set2-12"}, {"topic": "Nephrology", "q": "Immediate management of severe symptomatic hypercalcemia (Ca 14) includes:", "choices": ["Fluid restriction", "IV isotonic saline hydration + calcitonin ± bisphosphonate", "Thiazide diuretic", "Oral calcium", "Vitamin D"], "ans": 1, "exp": "Severe hypercalcemia รักษาด้วย IV isotonic saline (rehydrate + promote calciuresis) + calcitonin (ออกเร็ว) + bisphosphonate (ออกช้าแต่ยาว). หลีกเลี่ยง thiazide (เพิ่ม Ca reabsorption).", "id": "set2-13"}, {"topic": "Nephrology", "q": "A patient presents with tetany, perioral numbness, positive Chvostek sign, and a prolonged QT after thyroid surgery. What is the cause?", "choices": ["Hyperkalemia", "Hypocalcemia from hypoparathyroidism", "Hypernatremia", "Hypomagnesemia only", "Hyperphosphatemia only"], "ans": 1, "exp": "หลังผ่าตัด thyroid/parathyroid เสี่ยง hypoparathyroidism → hypocalcemia (ชา เกร็ง Chvostek/Trousseau, QT ยาว). รักษาด้วย IV/oral calcium + calcitriol.", "id": "set2-14"}, {"topic": "Nephrology", "q": "A child has periorbital edema, proteinuria > 3.5 g/day, hypoalbuminemia, and hyperlipidemia. What is the most likely histology?", "choices": ["Minimal change disease", "IgA nephropathy", "Post-streptococcal GN", "Rapidly progressive GN", "Thin basement membrane"], "ans": 0, "exp": "Nephrotic syndrome ในเด็กส่วนใหญ่คือ minimal change disease (ตอบสนองดีต่อ steroid). Nephrotic = proteinuria > 3.5 g/day, hypoalbuminemia, edema, hyperlipidemia; เสี่ยง infection และ VTE.", "id": "set2-15"}, {"topic": "Nephrology", "q": "A 10-year-old develops hematuria, hypertension, and periorbital edema 2 weeks after a sore throat; C3 is low and ASO is elevated. What is the diagnosis?", "choices": ["Minimal change disease", "Post-streptococcal glomerulonephritis", "IgA nephropathy", "Alport syndrome", "Membranous nephropathy"], "ans": 1, "exp": "Nephritic syndrome หลัง strep 1–3 สัปดาห์ + C3 ต่ำ + ASO สูง = post-streptococcal GN. รักษาประคับประคอง (คุมความดัน/บวม); ส่วนใหญ่หายเองในเด็ก.", "id": "set2-16"}, {"topic": "Nephrology", "q": "A patient with gross hematuria occurring 1–2 days after an upper respiratory infection (synpharyngitic) most likely has:", "choices": ["Post-streptococcal GN", "IgA nephropathy", "Minimal change disease", "Diabetic nephropathy", "Membranous nephropathy"], "ans": 1, "exp": "Hematuria พร้อม/หลัง URI ทันที (1–2 วัน, synpharyngitic) ต่างจาก PSGN (ล่าช้า 1–3 สัปดาห์) = IgA nephropathy (Berger). วินิจฉัยด้วย renal biopsy (mesangial IgA).", "id": "set2-17"}, {"topic": "Nephrology", "q": "A nephrotic syndrome patient develops sudden flank pain and worsening renal function. Which complication should be suspected?", "choices": ["Renal vein thrombosis", "Pyelonephritis", "Renal stone", "Renal artery stenosis", "Papillary necrosis"], "ans": 0, "exp": "Nephrotic syndrome ทำให้ hypercoagulable (เสีย antithrombin III ทางปัสสาวะ) เสี่ยง renal vein thrombosis (โดยเฉพาะ membranous) → flank pain + hematuria + ไตแย่ลง. ยืนยันด้วย imaging; รักษา anticoagulation.", "id": "set2-18"}, {"topic": "Nephrology", "q": "A woman has dysuria, frequency, and suprapubic discomfort but no fever or flank pain. What is the appropriate management of uncomplicated cystitis?", "choices": ["IV ceftriaxone", "Short course nitrofurantoin/fosfomycin/co-trimoxazole", "No treatment", "Long-term antibiotics", "Renal ultrasound first"], "ans": 1, "exp": "Uncomplicated cystitis (ไม่มีไข้/ปวดสีข้าง) รักษาด้วยยา oral สั้น: nitrofurantoin, fosfomycin, หรือ co-trimoxazole (ตาม local resistance). ไม่ต้อง imaging ในรายไม่ซับซ้อน.", "id": "set2-19"}, {"topic": "Nephrology", "q": "A woman has high fever, chills, and costovertebral angle tenderness with pyuria. What is the diagnosis and management?", "choices": ["Cystitis; oral nitrofurantoin", "Acute pyelonephritis; ceftriaxone or fluoroquinolone (± admission)", "Asymptomatic bacteriuria; observe", "Interstitial cystitis; analgesia", "Renal stone; lithotripsy"], "ans": 1, "exp": "ไข้สูง + CVA tenderness + pyuria = acute pyelonephritis. เก็บ urine + hemoculture, ให้ ceftriaxone/fluoroquinolone, admit ถ้ารุนแรง/อาเจียน/ตั้งครรภ์. Nitrofurantoin ไม่เหมาะกับ pyelonephritis (tissue level ต่ำ).", "id": "set2-20"}, {"topic": "Nephrology", "q": "In which situation should asymptomatic bacteriuria be treated?", "choices": ["All elderly patients", "Pregnancy or before urologic procedure", "Diabetic patients routinely", "Patients with indwelling catheter routinely", "Never"], "ans": 1, "exp": "Asymptomatic bacteriuria รักษาเฉพาะหญิงตั้งครรภ์ (ลด pyelonephritis/preterm) และก่อนหัตถการทางเดินปัสสาวะที่เสี่ยงเลือดออก. กลุ่มอื่น (สูงอายุ, เบาหวาน, คาสาย) ไม่ต้องรักษาเพราะเพิ่ม resistance.", "id": "set2-21"}, {"topic": "Nephrology", "q": "Urinalysis shows RBC casts. Which condition does this most specifically indicate?", "choices": ["Urinary tract infection", "Glomerulonephritis", "Acute tubular necrosis", "Prerenal azotemia", "Bladder cancer"], "ans": 1, "exp": "RBC cast จำเพาะต่อ glomerular bleeding = glomerulonephritis. WBC cast = pyelonephritis/AIN; muddy brown cast = ATN; hyaline cast = ปกติ/dehydration.", "id": "set2-22"}, {"topic": "Nephrology", "q": "A patient with diabetes has microalbuminuria. Besides glycemic control, which drug slows progression of diabetic nephropathy?", "choices": ["Beta-blocker", "ACE inhibitor or ARB (plus SGLT2i)", "Calcium channel blocker", "Alpha-blocker", "Loop diuretic"], "ans": 1, "exp": "Diabetic nephropathy ที่มี albuminuria ใช้ ACEI/ARB ลด intraglomerular pressure/proteinuria + SGLT2i ชะลอไตเสื่อม. คุมน้ำตาล/ความดัน/lipid ร่วมด้วย.", "id": "set2-23"}, {"topic": "Nephrology", "q": "A patient on chronic NSAIDs presents with AKI, sterile pyuria, eosinophiluria, and a maculopapular rash. What is the diagnosis?", "choices": ["Acute tubular necrosis", "Acute interstitial nephritis", "Prerenal azotemia", "Post-streptococcal GN", "Renal stone"], "ans": 1, "exp": "AKI + rash + eosinophilia/eosinophiluria + ประวัติยา (NSAID, antibiotic, PPI) = acute interstitial nephritis (allergic). รักษาโดยหยุดยาต้นเหตุ ± corticosteroid.", "id": "set2-24"}, {"topic": "Nephrology", "q": "ABG in a patient with prolonged vomiting shows pH 7.50, HCO3 34, PaCO2 46. What is the primary acid-base disorder?", "choices": ["Metabolic acidosis", "Metabolic alkalosis", "Respiratory acidosis", "Respiratory alkalosis", "Normal"], "ans": 1, "exp": "pH สูง + HCO3 สูง = metabolic alkalosis; อาเจียนเสีย HCl + volume contraction. PaCO2 สูงเล็กน้อยเป็น respiratory compensation. รักษาด้วย isotonic saline (chloride-responsive).", "id": "set2-25"}, {"topic": "Nephrology", "q": "A patient with distal (type 1) renal tubular acidosis typically has which electrolyte/stone pattern?", "choices": ["Hyperkalemia and no stones", "Hypokalemia with normal anion gap acidosis and calcium phosphate stones", "High anion gap acidosis", "Metabolic alkalosis", "Hyperphosphatemia"], "ans": 1, "exp": "Distal (type 1) RTA: ไม่สามารถขับ H+ ที่ distal tubule → normal anion gap metabolic acidosis + hypokalemia + urine pH สูง (> 5.5) + เสี่ยง calcium phosphate stones/nephrocalcinosis.", "id": "set2-26"}, {"topic": "Nephrology", "q": "A patient develops rapidly rising creatinine over days with hematuria, RBC casts, and crescents on biopsy. What is the diagnosis?", "choices": ["Minimal change disease", "Rapidly progressive (crescentic) glomerulonephritis", "Chronic kidney disease", "Prerenal azotemia", "ATN"], "ans": 1, "exp": "ไตวายเร็ว + nephritic (RBC cast) + crescents = rapidly progressive GN (RPGN). สาเหตุ: ANCA-associated vasculitis, anti-GBM (Goodpasture), immune complex (lupus). ต้องรีบวินิจฉัย + immunosuppression.", "id": "set2-27"}, {"topic": "Nephrology", "q": "Which finding best distinguishes chronic kidney disease from acute kidney injury on imaging/labs?", "choices": ["Elevated creatinine", "Small echogenic kidneys, anemia, and CKD-MBD (high PTH, low Ca)", "Oliguria", "Hyperkalemia", "Proteinuria"], "ans": 1, "exp": "CKD มักมีไตเล็ก echogenic, anemia (EPO ต่ำ), และ CKD-MBD (PTH สูง, Ca ต่ำ, PO4 สูง) ที่ค่อยเป็นค่อยไป — ต่างจาก AKI ที่ไตขนาดปกติและ acute. ช่วยแยกเมื่อไม่มี baseline.", "id": "set2-28"}, {"topic": "Nephrology", "q": "A patient with CKD stage 4 has high phosphate. What is the first-line dietary/pharmacologic management?", "choices": ["High phosphate diet", "Dietary phosphate restriction + phosphate binders", "Calcium supplement alone", "Vitamin D megadose", "Loop diuretic"], "ans": 1, "exp": "Hyperphosphatemia ใน CKD จัดการด้วยจำกัดฟอสเฟตในอาหาร + phosphate binder (calcium-based หรือ non-calcium เช่น sevelamer) เพื่อคุม CKD-MBD และลด vascular calcification.", "id": "set2-29"}, {"topic": "Nephrology", "q": "A patient with rhabdomyolysis (CK very high) after crush injury is at risk of AKI. What is the key initial treatment?", "choices": ["Fluid restriction", "Aggressive IV fluid to maintain urine output", "Immediate dialysis for all", "Diuretic alone", "Bicarbonate contraindicated"], "ans": 1, "exp": "Rhabdomyolysis → myoglobin cast + AKI; รักษาด้วย aggressive IV fluid รักษา urine output สูง (± urine alkalinization ในบางราย). ระวัง hyperkalemia และ hypocalcemia. Dialysis เมื่อมีข้อบ่งชี้.", "id": "set2-30"}, {"topic": "Nephrology", "q": "An elderly patient with poor water intake has Na 158, lethargy, and concentrated urine. How should hypernatremia be corrected?", "choices": ["Rapid bolus of hypotonic fluid", "Slowly replace free water deficit (avoid dropping Na > 10 mEq/L/day)", "Give hypertonic saline", "Fluid restriction", "Loop diuretic alone"], "ans": 1, "exp": "Hypernatremia แก้โดยค่อยๆ ทดแทน free water deficit ช้าๆ (ลด Na ไม่เกิน ~10 mEq/L/วัน) เพื่อป้องกัน cerebral edema. หาสาเหตุ (ขาดน้ำ, DI). การแก้เร็วเกินอันตราย.", "id": "set2-31"}, {"topic": "Nephrology", "q": "A patient with polyuria and dilute urine does not concentrate urine after water deprivation but responds to desmopressin. What is the diagnosis?", "choices": ["Nephrogenic diabetes insipidus", "Central diabetes insipidus", "Primary polydipsia", "SIADH", "Osmotic diuresis"], "ans": 1, "exp": "ตอบสนองต่อ desmopressin (urine osmolality เพิ่ม) = central DI (ขาด ADH). Nephrogenic DI จะไม่ตอบสนอง desmopressin (ไตดื้อ ADH). Primary polydipsia จะ concentrate ได้เมื่อ deprive.", "id": "set2-32"}, {"topic": "Nephrology", "q": "A patient with severe flank pain radiating to the groin and microscopic hematuria most likely has:", "choices": ["Pyelonephritis", "Ureteric (renal) colic from a stone", "Cystitis", "Glomerulonephritis", "Bladder cancer"], "ans": 1, "exp": "ปวดสีข้าวร้าวลงขาหนีบ (colicky) + hematuria = ureteric stone (renal colic). ยืนยันด้วย non-contrast CT KUB; รักษา analgesia, hydration, medical expulsive therapy (alpha-blocker) สำหรับนิ่วเล็ก; intervention ถ้านิ่วใหญ่/อุดตัน/ติดเชื้อ.", "id": "set2-33"}, {"topic": "Nephrology", "q": "A diabetic patient is scheduled for contrast CT. What is the best strategy to reduce contrast-associated AKI?", "choices": ["Give NSAIDs", "Ensure adequate IV hydration and hold nephrotoxins", "Give a diuretic before contrast", "Withhold all fluids", "Give high-dose vitamin C"], "ans": 1, "exp": "ลดเสี่ยง contrast-associated nephropathy ด้วยการให้ isotonic IV hydration รอบการฉีด contrast + หยุด nephrotoxin (NSAID) + ใช้ contrast ปริมาณน้อย. Diuretic/NSAID ทำให้แย่ลง.", "id": "set2-34"}, {"topic": "Nephrology", "q": "A cirrhotic patient with tense ascites develops AKI unresponsive to volume, with bland urine and no other cause. What is the diagnosis?", "choices": ["Prerenal azotemia", "Hepatorenal syndrome", "Acute tubular necrosis", "Glomerulonephritis", "Postrenal obstruction"], "ans": 1, "exp": "AKI ใน cirrhosis ที่ตัดสาเหตุอื่นและไม่ตอบสนอง volume (bland urine, FeNa ต่ำ) = hepatorenal syndrome. รักษาด้วย terlipressin (หรือ noradrenaline) + albumin; แก้ precipitant; ปลูกถ่ายตับ.", "id": "set2-35"}, {"topic": "Nephrology", "q": "An adult with flank masses, hypertension, hematuria, and a family history of kidney failure has multiple bilateral renal cysts. What is the diagnosis?", "choices": ["Simple renal cysts", "Autosomal dominant polycystic kidney disease", "Medullary sponge kidney", "Renal cell carcinoma", "Acquired cystic disease"], "ans": 1, "exp": "Multiple bilateral cysts + HT + ประวัติครอบครัว = ADPKD (PKD1/2). สัมพันธ์ berry aneurysm (SAH), hepatic cysts, MVP. คุมความดัน (ACEI/ARB); tolvaptan ชะลอในรายเสี่ยงสูง.", "id": "set2-36"}, {"topic": "Nephrology", "q": "A patient has nephrotic syndrome; biopsy shows subepithelial deposits and thickened GBM (membranous nephropathy). Which underlying condition should be excluded, especially in older adults?", "choices": ["Diabetes", "Underlying malignancy (and anti-PLA2R testing)", "Viral hepatitis only", "Amyloidosis only", "Thyroid disease"], "ans": 1, "exp": "Membranous nephropathy อาจ secondary ต่อ malignancy (โดยเฉพาะผู้สูงอายุ), infection (HBV), SLE, ยา. ควรคัดกรองมะเร็งตามอายุ + ตรวจ anti-PLA2R (primary). เสี่ยง renal vein thrombosis สูง.", "id": "set2-37"}, {"topic": "Nephrology", "q": "A young woman with SLE has proteinuria, hematuria, red cell casts, and rising creatinine. What is essential for guiding treatment?", "choices": ["Renal biopsy to classify lupus nephritis", "Empiric antibiotics", "Observation", "Loop diuretic only", "Dialysis immediately"], "ans": 0, "exp": "Lupus nephritis ต้อง renal biopsy จำแนก class (I–VI) เพราะกำหนดการรักษา (class III/IV → induction ด้วย steroid + mycophenolate/cyclophosphamide). Complement ต่ำ + anti-dsDNA สูงช่วยประเมิน activity.", "id": "set2-38"}, {"topic": "Nephrology", "q": "A patient presents with hemoptysis and rapidly progressive glomerulonephritis; anti-GBM antibody is positive. What is the diagnosis?", "choices": ["Granulomatosis with polyangiitis", "Goodpasture syndrome (anti-GBM disease)", "Microscopic polyangiitis", "IgA nephropathy", "Post-strep GN"], "ans": 1, "exp": "RPGN + pulmonary hemorrhage + anti-GBM positive = Goodpasture syndrome. รักษาด้วย plasmapheresis + steroid + cyclophosphamide. ต่างจาก ANCA-vasculitis ที่ ANCA positive.", "id": "set2-39"}, {"topic": "Nephrology", "q": "A patient with fatigue, weight loss, sinusitis, hemoptysis, and RPGN has c-ANCA (anti-PR3) positive. What is the diagnosis?", "choices": ["Goodpasture syndrome", "Granulomatosis with polyangiitis (GPA)", "Minimal change disease", "Diabetic nephropathy", "Amyloidosis"], "ans": 1, "exp": "Upper+lower respiratory (sinusitis, hemoptysis) + RPGN + c-ANCA/PR3 = granulomatosis with polyangiitis. รักษา induction ด้วย steroid + rituximab/cyclophosphamide.", "id": "set2-40"}, {"topic": "Nephrology", "q": "ABG shows pH 7.34, PaCO2 60, HCO3 32 in a COPD patient. What is the interpretation?", "choices": ["Acute respiratory acidosis", "Chronic (compensated) respiratory acidosis", "Metabolic acidosis", "Respiratory alkalosis", "Mixed alkalosis"], "ans": 1, "exp": "PaCO2 สูง + HCO3 สูงชดเชย + pH เกือบปกติ (แค่ต่ำเล็กน้อย) = chronic respiratory acidosis with metabolic compensation (พบใน COPD). Acute จะมี pH ต่ำชัดโดย HCO3 ยังไม่ขึ้น.", "id": "set2-41"}, {"topic": "Nephrology", "q": "A patient with type 4 (hyporeninemic hypoaldosteronism) RTA, common in diabetics, typically shows:", "choices": ["Hypokalemia", "Hyperkalemia with normal anion gap metabolic acidosis", "High anion gap acidosis", "Metabolic alkalosis", "Hypernatremia"], "ans": 1, "exp": "Type 4 RTA (hypoaldosteronism, พบในเบาหวาน) มี hyperkalemia + normal anion gap metabolic acidosis. รักษาแก้ hyperkalemia (จำกัด K, diuretic, fludrocortisone ในบางราย).", "id": "set2-42"}, {"topic": "Nephrology", "q": "A patient develops thrombocytopenia, microangiopathic hemolytic anemia, and AKI after bloody diarrhea (E. coli O157:H7). What is the diagnosis?", "choices": ["TTP", "Hemolytic uremic syndrome (HUS)", "DIC", "ITP", "Evans syndrome"], "ans": 1, "exp": "เด็ก/หลัง bloody diarrhea (Shiga toxin E. coli) + MAHA + thrombocytopenia + AKI = HUS. รักษาประคับประคอง (มัก supportive, dialysis ถ้าจำเป็น); หลีกเลี่ยง antibiotics/antimotility ที่อาจเพิ่ม toxin.", "id": "set2-43"}, {"topic": "Nephrology", "q": "An older man has difficulty voiding, weak stream, nocturia, and a distended bladder with AKI. What is the mechanism of his kidney injury?", "choices": ["Prerenal", "Postrenal obstruction from BPH", "Intrinsic ATN", "Glomerulonephritis", "Interstitial nephritis"], "ans": 1, "exp": "BPH ทำให้ bladder outlet obstruction → postrenal AKI (hydronephrosis 2 ข้าง). ระบายปัสสาวะด้วย catheter จะทำให้ไตดีขึ้น; ระวัง post-obstructive diuresis.", "id": "set2-44"}, {"topic": "Nephrology", "q": "A patient on hemodialysis develops hypotension, muscle cramps during the session. What is the most likely cause?", "choices": ["Excess fluid removal (intradialytic hypotension)", "Air embolism", "Hemolysis", "Anaphylaxis", "Hyperkalemia"], "ans": 0, "exp": "Intradialytic hypotension มักจากการดึงน้ำเร็ว/มากเกิน (ultrafiltration) → hypotension + cramps. จัดการโดยลด ultrafiltration rate, ให้ saline, ประเมิน dry weight.", "id": "set2-45"}, {"topic": "Nephrology", "q": "Which is the recommended blood pressure target for most CKD patients with albuminuria (KDIGO), if tolerated?", "choices": ["< 160/100", "< 150/90", "Systolic < 120", "< 140/90 only", "No target"], "ans": 2, "exp": "KDIGO แนะนำเป้า systolic < 120 mmHg (วัดแบบมาตรฐาน) ในผู้ป่วย CKD ส่วนใหญ่ถ้าทนได้ เพื่อลด CV events. ใช้ ACEI/ARB เป็นยาหลักเมื่อมี albuminuria.", "id": "set2-46"}, {"topic": "Nephrology", "q": "A patient has persistent proteinuria on dipstick. What is the best test to quantify and characterize it?", "choices": ["Serum albumin only", "Spot urine albumin/protein-to-creatinine ratio (or 24-hr urine protein)", "Renal ultrasound", "Serum creatinine only", "CBC"], "ans": 1, "exp": "Quantify proteinuria ด้วย spot urine protein/creatinine ratio หรือ albumin/creatinine ratio (สะดวกกว่า 24-hr และสัมพันธ์กันดี). ช่วยประเมิน glomerular disease และ CKD progression.", "id": "set2-47"}, {"topic": "Nephrology", "q": "A patient with recurrent calcium oxalate stones should be advised to:", "choices": ["Restrict dietary calcium severely", "Increase fluid intake and reduce sodium/oxalate; maintain normal dietary calcium", "Increase protein intake", "Take vitamin C supplements", "Restrict fluids"], "ans": 1, "exp": "ป้องกันนิ่ว calcium oxalate: ดื่มน้ำมาก (urine > 2 L/วัน), ลดเกลือและ oxalate, กิน calcium ปกติ (ไม่จำกัดเข้ม เพราะการจำกัด Ca เพิ่ม oxalate absorption), thiazide ในราย hypercalciuria.", "id": "set2-48"}, {"topic": "Nephrology", "q": "A patient presents with painless gross hematuria and no infection. In an older smoker, which diagnosis must be excluded?", "choices": ["Simple UTI", "Urothelial (bladder) carcinoma", "Prerenal azotemia", "Minimal change disease", "Renal colic"], "ans": 1, "exp": "Painless gross hematuria ในผู้สูงอายุ/สูบบุหรี่ ต้องตัด urothelial (bladder) carcinoma ด้วย cystoscopy + CT urography. อย่าเหมาว่าเป็น UTI ถ้าไม่มีหลักฐานติดเชื้อ.", "id": "set2-49"}, {"topic": "Endocrinology", "q": "Which of the following meets the diagnostic criteria for diabetes mellitus?", "choices": ["Fasting glucose 110 mg/dL", "HbA1c 6.5% or fasting glucose ≥ 126 mg/dL (confirmed)", "Random glucose 160 mg/dL without symptoms", "2-hr OGTT 150 mg/dL", "HbA1c 6.0%"], "ans": 1, "exp": "เกณฑ์เบาหวาน: FPG ≥ 126, 2-hr OGTT ≥ 200, HbA1c ≥ 6.5% (ยืนยันซ้ำถ้าไม่มีอาการ), หรือ random ≥ 200 + อาการ. FPG 100–125 = IFG (prediabetes); A1c 5.7–6.4 = prediabetes.", "id": "set2-50"}, {"topic": "Endocrinology", "q": "A patient with T2DM and established ASCVD needs glucose-lowering therapy. Which agents should be included irrespective of A1c?", "choices": ["Sulfonylurea", "GLP-1 receptor agonist and/or SGLT2 inhibitor with proven CV benefit", "Basal insulin", "Thiazolidinedione", "Acarbose"], "ans": 1, "exp": "ADA 2025/26: ในผู้ป่วย T2DM + ASCVD/ความเสี่ยงสูง ให้ GLP-1 RA และ/หรือ SGLT2i ที่มีหลักฐานลด CV events โดยไม่ขึ้นกับ A1c หรือการใช้ metformin. HF → SGLT2i; CKD → SGLT2i first-line.", "id": "set2-51"}, {"topic": "Endocrinology", "q": "A T2DM patient with heart failure needs additional therapy. Which class both lowers glucose and reduces HF hospitalization?", "choices": ["Sulfonylurea", "SGLT2 inhibitor", "DPP-4 inhibitor", "Thiazolidinedione", "Insulin"], "ans": 1, "exp": "SGLT2 inhibitor ลด HF hospitalization (ทั้ง HFrEF/HFpEF) และชะลอ CKD จึงเป็นตัวเลือกใน T2DM + HF. TZD (pioglitazone) ทำให้ fluid retention/HF แย่ลง.", "id": "set2-52"}, {"topic": "Endocrinology", "q": "A patient with T1DM presents with vomiting, Kussmaul breathing, glucose 450, pH 7.15, HCO3 10, and ketonuria. What is the first step in management?", "choices": ["IV insulin bolus before fluids", "IV isotonic fluid resuscitation (then insulin, with potassium monitoring)", "Oral hydration", "Sodium bicarbonate routinely", "Give glucose"], "ans": 1, "exp": "DKA รักษาลำดับ: IV fluid resuscitation ก่อน → insulin drip → เติม K (ถ้า K < 3.3 ต้องเติม K ก่อนเริ่ม insulin) → หา precipitant. Bicarbonate ให้เฉพาะ pH ต่ำมาก (< 6.9). อย่าเริ่ม insulin ก่อน fluid/ตรวจ K.", "id": "set2-53"}, {"topic": "Endocrinology", "q": "An elderly T2DM patient has glucose 900, serum osmolality 350, profound dehydration, and minimal ketones. What is the diagnosis?", "choices": ["DKA", "Hyperosmolar hyperglycemic state (HHS)", "Lactic acidosis", "Hypoglycemia", "Diabetes insipidus"], "ans": 1, "exp": "น้ำตาลสูงมาก (>600) + osmolality สูง + ไม่มี ketoacidosis เด่น + ซึม/ขาดน้ำ = HHS. เน้น aggressive fluid resuscitation เป็นหลัก + insulin + แก้ electrolyte + หาสาเหตุ (ติดเชื้อ).", "id": "set2-54"}, {"topic": "Endocrinology", "q": "A diabetic on insulin becomes confused and diaphoretic with glucose 45 mg/dL. What is the immediate treatment if conscious and able to swallow?", "choices": ["IV insulin", "Oral fast-acting carbohydrate (glucose)", "IM glucagon only", "Observation", "IV normal saline"], "ans": 1, "exp": "Hypoglycemia (< 70) ที่รู้ตัวและกลืนได้ → ให้ oral carbohydrate/glucose 15 g ทันที (rule of 15). ถ้าไม่รู้ตัว/กลืนไม่ได้ → IV glucose หรือ IM glucagon. Whipple triad ยืนยันภาวะน้ำตาลต่ำ.", "id": "set2-55"}, {"topic": "Endocrinology", "q": "A T2DM patient is screened for diabetic complications. How often should retinal examination be performed?", "choices": ["Every 5 years", "Annually", "Only if symptomatic", "Every month", "Never"], "ans": 1, "exp": "ควรตรวจตา (dilated retinal exam) อย่างน้อยปีละครั้งเพื่อคัดกรอง diabetic retinopathy; ตรวจเท้า (monofilament) และ urine ACR + eGFR ปีละครั้งเช่นกัน.", "id": "set2-56"}, {"topic": "Endocrinology", "q": "A patient with diabetic neuropathy has painful burning feet. Which is an appropriate first-line agent for neuropathic pain?", "choices": ["Paracetamol", "Pregabalin/gabapentin or duloxetine/amitriptyline", "Ibuprofen", "Opioid first-line", "Topical steroid"], "ans": 1, "exp": "Painful diabetic neuropathy ใช้ pregabalin/gabapentin, duloxetine, หรือ TCA (amitriptyline) เป็น first-line. NSAID/paracetamol ได้ผลน้อย; opioid ไม่ใช่ตัวแรก.", "id": "set2-57"}, {"topic": "Endocrinology", "q": "A patient has palpitations, weight loss, heat intolerance, tremor, exophthalmos, and pretibial myxedema. TSH is low. What is the diagnosis?", "choices": ["Toxic multinodular goiter", "Graves disease", "Subacute thyroiditis", "Hashimoto thyroiditis", "Iodine deficiency"], "ans": 1, "exp": "Hyperthyroid + exophthalmos + pretibial myxedema (จำเพาะ) + TRAb = Graves disease (autoimmune). รักษาด้วย antithyroid drug (methimazole), RAI, หรือผ่าตัด + beta-blocker คุมอาการ.", "id": "set2-58"}, {"topic": "Endocrinology", "q": "A pregnant woman in the first trimester needs antithyroid drug for hyperthyroidism. Which is preferred?", "choices": ["Methimazole", "Propylthiouracil (PTU)", "Radioactive iodine", "Carbimazole", "Levothyroxine"], "ans": 1, "exp": "Trimester 1 เลือก PTU (methimazole เสี่ยง teratogenic – aplasia cutis, choanal atresia ในช่วงต้น). หลัง trimester 1 มักเปลี่ยนเป็น methimazole (PTU เสี่ยง hepatotoxicity). RAI เป็นข้อห้ามในการตั้งครรภ์.", "id": "set2-59"}, {"topic": "Endocrinology", "q": "A patient with fever, tachycardia/AF, agitation, and heart failure after infection has severe thyrotoxicosis. What is the treatment sequence for thyroid storm?", "choices": ["Iodine first, then PTU", "PTU first, then iodine (>1 h later), beta-blocker, hydrocortisone", "Levothyroxine", "RAI immediately", "Methimazole alone"], "ans": 1, "exp": "Thyroid storm: ให้ PTU (block synthesis + peripheral T4→T3 conversion) ก่อน แล้วให้ iodine (Lugol) หลัง ≥ 1 ชม. (ให้ก่อนจะเป็นสารตั้งต้น hormone) + beta-blocker (propranolol) + hydrocortisone + ลดไข้ + รักษา precipitant.", "id": "set2-60"}, {"topic": "Endocrinology", "q": "A patient has fatigue, cold intolerance, weight gain, constipation, and bradycardia. TSH is high and free T4 low. What is the treatment?", "choices": ["Methimazole", "Levothyroxine", "Radioactive iodine", "Propranolol", "Prednisolone"], "ans": 1, "exp": "Primary hypothyroidism (TSH สูง, FT4 ต่ำ; มัก Hashimoto) รักษาด้วย levothyroxine แล้วปรับตาม TSH. เริ่มขนาดต่ำในผู้สูงอายุ/โรคหัวใจ.", "id": "set2-61"}, {"topic": "Endocrinology", "q": "A patient presents with hypothermia, bradycardia, hyponatremia, and depressed consciousness with a history of untreated hypothyroidism. What is the management of myxedema coma?", "choices": ["Oral levothyroxine and discharge", "IV levothyroxine (± T3) plus IV hydrocortisone and supportive care", "Methimazole", "Active rewarming only", "Observation"], "ans": 1, "exp": "Myxedema coma เป็นภาวะฉุกเฉิน: IV levothyroxine (± T3) + IV hydrocortisone (กัน adrenal crisis) + supportive (warming, ventilation, แก้ hyponatremia/hypoglycemia) + รักษา precipitant.", "id": "set2-62"}, {"topic": "Endocrinology", "q": "A patient has a thyroid nodule. What is the appropriate initial investigation?", "choices": ["Immediate surgery", "Serum TSH, then thyroid ultrasound and FNA based on risk", "CT neck", "Thyroid scan for all", "Start levothyroxine"], "ans": 1, "exp": "Thyroid nodule เริ่มด้วย TSH → ถ้าต่ำทำ thyroid scan (hot nodule มักไม่ร้าย); ทำ ultrasound (TIRADS) แล้ว FNA ตามขนาด/ลักษณะเสี่ยง (Bethesda). ไม่ผ่าตัดทุกราย.", "id": "set2-63"}, {"topic": "Endocrinology", "q": "Which thyroid cancer is the most common and generally has the best prognosis?", "choices": ["Follicular", "Papillary", "Medullary", "Anaplastic", "Lymphoma"], "ans": 1, "exp": "Papillary thyroid carcinoma พบบ่อยสุดและพยากรณ์ดี (แพร่ทาง lymphatic). Follicular แพร่ทาง hematogenous; medullary จาก C-cell (calcitonin, MEN2); anaplastic ดุ พยากรณ์แย่.", "id": "set2-64"}, {"topic": "Endocrinology", "q": "A patient with medullary thyroid carcinoma should be screened for which associated condition?", "choices": ["MEN 2 (pheochromocytoma, hyperparathyroidism)", "MEN 1 only", "Addison disease", "Graves disease", "Cushing disease"], "ans": 0, "exp": "Medullary thyroid carcinoma สัมพันธ์กับ MEN 2 (pheochromocytoma, primary hyperparathyroidism, RET mutation). ต้องคัดกรอง pheochromocytoma ก่อนผ่าตัด thyroid.", "id": "set2-65"}, {"topic": "Endocrinology", "q": "A patient has central obesity, moon face, purple striae, proximal weakness, hypertension, and hyperglycemia. Which test screens for Cushing syndrome?", "choices": ["Morning cortisol only", "Late-night salivary cortisol / 1-mg overnight dexamethasone suppression / 24-hr urinary free cortisol", "Random cortisol", "ACTH stimulation test", "TSH"], "ans": 1, "exp": "คัดกรอง Cushing ด้วย 1 ใน 3: overnight low-dose dexamethasone suppression test, 24-hr urinary free cortisol, หรือ late-night salivary cortisol. จากนั้นหาสาเหตุด้วย ACTH + high-dose dexamethasone/imaging.", "id": "set2-66"}, {"topic": "Endocrinology", "q": "A patient has fatigue, weight loss, hyperpigmentation, hypotension, hyponatremia, and hyperkalemia. What is the diagnosis?", "choices": ["Cushing syndrome", "Primary adrenal insufficiency (Addison disease)", "Hyperthyroidism", "Conn syndrome", "SIADH"], "ans": 1, "exp": "Hyperpigmentation (ACTH สูง) + hypotension + hypoNa + hyperK = primary adrenal insufficiency (Addison). ยืนยันด้วย morning cortisol ต่ำ + ACTH stimulation test. รักษา hydrocortisone + fludrocortisone.", "id": "set2-67"}, {"topic": "Endocrinology", "q": "A patient in shock refractory to fluids and vasopressors, with a history of chronic steroid use recently stopped, should receive:", "choices": ["More fluids only", "IV hydrocortisone immediately (treat adrenal crisis)", "Antibiotics only", "Insulin", "Thyroxine"], "ans": 1, "exp": "Shock ดื้อ fluid/vasopressor + ประวัติหยุด steroid = adrenal crisis. ให้ IV hydrocortisone ทันทีโดยไม่ต้องรอผลตรวจ + fluid resuscitation + หา/แก้ precipitant.", "id": "set2-68"}, {"topic": "Endocrinology", "q": "A patient has episodic severe hypertension with headache, palpitations, and diaphoresis. Which test and treatment order are correct?", "choices": ["Metanephrines; give beta-blocker first", "Plasma/urine metanephrines; alpha-blockade before beta-blockade, then surgery", "TSH; levothyroxine", "Aldosterone; spironolactone", "Cortisol; surgery"], "ans": 1, "exp": "Pheochromocytoma: HT เป็นพักๆ + triad (ปวดหัว/ใจสั่น/เหงื่อ). ตรวจ plasma/urine metanephrines. ผ่าตัดหลังเตรียมด้วย alpha-blockade (phenoxybenzamine) ก่อน beta-block (ถ้าให้ beta ก่อนจะเกิด unopposed alpha → HT crisis).", "id": "set2-69"}, {"topic": "Endocrinology", "q": "A hypertensive patient with hypokalemia and a high aldosterone-to-renin ratio most likely has:", "choices": ["Pheochromocytoma", "Primary aldosteronism (Conn syndrome)", "Cushing syndrome", "Addison disease", "Renal artery stenosis"], "ans": 1, "exp": "HT + hypokalemia + aldosterone/renin ratio สูง = primary aldosteronism (Conn). ยืนยันด้วย confirmatory test + adrenal imaging/AVS; รักษา MRA (spironolactone/eplerenone) หรือผ่าตัดถ้า adenoma ข้างเดียว.", "id": "set2-70"}, {"topic": "Endocrinology", "q": "A young woman has amenorrhea, galactorrhea, and reduced libido; prolactin is markedly elevated with a pituitary mass. What is first-line treatment?", "choices": ["Transsphenoidal surgery first", "Dopamine agonist (cabergoline)", "Radiotherapy", "Estrogen", "Observation"], "ans": 1, "exp": "Prolactinoma รักษาลำดับแรกด้วย dopamine agonist (cabergoline/bromocriptine) ซึ่งลด prolactin และขนาด tumor ได้ดีแม้ macroadenoma. ผ่าตัดสงวนไว้เมื่อดื้อยา/ทน side effect ไม่ได้.", "id": "set2-71"}, {"topic": "Endocrinology", "q": "An adult with enlarging hands/feet, coarse facial features, and headache has elevated IGF-1. What confirms acromegaly?", "choices": ["Random GH", "Oral glucose tolerance test showing failure to suppress GH", "Prolactin", "TSH", "Cortisol"], "ans": 1, "exp": "Acromegaly (GH เกินในผู้ใหญ่): คัดกรองด้วย IGF-1 สูง ยืนยันด้วย OGTT ที่ GH ไม่ suppress. หา pituitary adenoma ด้วย MRI; รักษาผ่าตัด ± somatostatin analog.", "id": "set2-72"}, {"topic": "Endocrinology", "q": "A patient with head trauma develops polyuria with dilute urine and rising sodium; urine osmolality is inappropriately low. What is the diagnosis?", "choices": ["SIADH", "Central diabetes insipidus", "Primary polydipsia", "Osmotic diuresis", "Nephrogenic DI"], "ans": 1, "exp": "หลัง head trauma/ผ่าตัด pituitary + polyuria เจือจาง + hypernatremia + urine osmolality ต่ำ = central diabetes insipidus (ขาด ADH). รักษาด้วย desmopressin.", "id": "set2-73"}, {"topic": "Endocrinology", "q": "A patient with lung small cell carcinoma has euvolemic hyponatremia, high urine osmolality, and high urine sodium. What is the diagnosis and initial management?", "choices": ["Addison; steroid", "SIADH; fluid restriction", "DI; desmopressin", "Diuretic effect; stop diuretic", "Cushing; surgery"], "ans": 1, "exp": "Euvolemic hyponatremia + urine osmolality/Na สูง + มะเร็งปอด = SIADH (ectopic ADH). รักษาเริ่มด้วยจำกัดน้ำ; รายรุนแรง/ชักใช้ hypertonic saline (แก้ช้าๆ), รักษาสาเหตุ.", "id": "set2-74"}, {"topic": "Endocrinology", "q": "A postmenopausal woman has a fragility fracture. A DEXA scan shows a T-score of -2.8. What is the diagnosis and a first-line treatment?", "choices": ["Osteomalacia; vitamin D only", "Osteoporosis; bisphosphonate plus calcium/vitamin D", "Paget disease; calcitonin", "Normal; no treatment", "Hyperparathyroidism; surgery"], "ans": 1, "exp": "T-score ≤ -2.5 = osteoporosis (fragility fracture ยิ่งยืนยัน). รักษาด้วย bisphosphonate (alendronate) + calcium/vitamin D + ออกกำลัง/ป้องกันล้ม. ประเมิน secondary causes.", "id": "set2-75"}, {"topic": "Endocrinology", "q": "A patient with subclinical hypothyroidism has TSH 8 and normal free T4, is asymptomatic and not pregnant. What is the general recommendation?", "choices": ["Always treat immediately", "Consider treatment if TSH > 10, symptomatic, pregnant, or positive antibodies; otherwise monitor", "Give methimazole", "Radioactive iodine", "Surgery"], "ans": 1, "exp": "Subclinical hypothyroidism (TSH สูงเล็กน้อย, FT4 ปกติ) พิจารณา levothyroxine เมื่อ TSH > 10, มีอาการ, ตั้งครรภ์/วางแผนตั้งครรภ์, หรือ anti-TPO บวก; ที่เหลือมักติดตาม.", "id": "set2-76"}, {"topic": "Endocrinology", "q": "A patient recently started metformin. Which is a key contraindication/precaution to remember?", "choices": ["Use in eGFR > 30 with caution; avoid/stop if eGFR < 30 or acute illness (lactic acidosis risk)", "Contraindicated in obesity", "Causes weight gain", "Causes hypoglycemia commonly", "Contraindicated with SGLT2i"], "ans": 0, "exp": "Metformin หลีกเลี่ยงเมื่อ eGFR < 30 (เสี่ยง lactic acidosis) และหยุดชั่วคราวช่วงเจ็บป่วยเฉียบพลัน/ก่อนฉีด contrast ในราย eGFR ต่ำ. ข้อดี: ไม่ทำให้น้ำตาลต่ำ/น้ำหนักเป็นกลาง.", "id": "set2-77"}, {"topic": "Endocrinology", "q": "Which diabetes drug class is associated with euglycemic diabetic ketoacidosis, especially perioperatively?", "choices": ["Sulfonylurea", "SGLT2 inhibitor", "Metformin", "DPP-4 inhibitor", "Insulin"], "ans": 1, "exp": "SGLT2 inhibitor อาจทำให้เกิด euglycemic DKA (โดยเฉพาะช่วงผ่าตัด/อดอาหาร/เจ็บป่วย) จึงแนะนำหยุด 3–4 วันก่อนผ่าตัดใหญ่. ต้องนึกถึงแม้ระดับน้ำตาลไม่สูงมาก.", "id": "set2-78"}, {"topic": "Endocrinology", "q": "A patient with type 1 diabetes should receive which insulin regimen as the physiologic standard?", "choices": ["Sliding scale only", "Basal-bolus (long-acting basal + rapid-acting with meals)", "Premixed twice daily only", "Metformin", "GLP-1 agonist alone"], "ans": 1, "exp": "T1DM ต้องใช้ insulin เสมอ; basal-bolus (basal long-acting + rapid-acting ก่อนอาหาร) เลียนแบบสรีรวิทยาได้ดีสุด. Sliding scale เดี่ยวไม่พอ; oral agents ไม่ใช้เป็นหลักใน T1DM.", "id": "set2-79"}, {"topic": "Endocrinology", "q": "A woman has secondary amenorrhea; workup shows high FSH/LH and low estrogen before age 40. What is the diagnosis?", "choices": ["Pregnancy", "Primary ovarian insufficiency (premature)", "Hypothalamic amenorrhea", "PCOS", "Prolactinoma"], "ans": 1, "exp": "High FSH/LH + low estrogen (hypergonadotropic hypogonadism) ก่อนอายุ 40 = primary ovarian insufficiency. ต่างจาก hypothalamic (FSH/LH ต่ำ). พิจารณา estrogen replacement + หา autoimmune/genetic cause.", "id": "set2-80"}, {"topic": "Endocrinology", "q": "A patient has a low serum cortisol; ACTH stimulation shows an appropriate cortisol rise. This suggests:", "choices": ["Primary adrenal insufficiency", "Secondary (central) adrenal insufficiency", "Cushing syndrome", "Pheochromocytoma", "Conn syndrome"], "ans": 1, "exp": "Cortisol ต่ำแต่ตอบสนองต่อ ACTH stimulation ดี ชี้ secondary/central adrenal insufficiency (pituitary ACTH ขาด, ต่อมหมวกไตยังทำงานได้) — มัก no hyperpigmentation, K ปกติ. Primary จะไม่ตอบสนอง ACTH.", "id": "set2-81"}, {"topic": "Endocrinology", "q": "A young woman with hirsutism, acne, oligomenorrhea, and polycystic ovaries on ultrasound has which condition, and what is first-line for menstrual regulation?", "choices": ["Cushing; surgery", "Polycystic ovary syndrome; combined oral contraceptive (± metformin)", "Prolactinoma; cabergoline", "Congenital adrenal hyperplasia; steroid", "Ovarian tumor; surgery"], "ans": 1, "exp": "PCOS (Rotterdam: 2/3 ของ oligo-ovulation, hyperandrogenism, polycystic ovaries) รักษา menstrual/hirsutism ด้วย combined OCP; metformin ช่วย insulin resistance; ลดน้ำหนัก; letrozole สำหรับ ovulation induction.", "id": "set2-82"}, {"topic": "Endocrinology", "q": "A patient with primary hyperparathyroidism has asymptomatic hypercalcemia. Which is an indication for parathyroidectomy?", "choices": ["Any elevated PTH", "Age < 50, calcium > 1 mg/dL above normal, eGFR < 60, osteoporosis, or nephrolithiasis", "Normal calcium", "Vitamin D deficiency", "Mild fatigue only"], "ans": 1, "exp": "Indication ผ่าตัดใน primary hyperparathyroidism: อายุ < 50, Ca สูงกว่าปกติ > 1 mg/dL, eGFR < 60, osteoporosis (T ≤ -2.5)/fracture, หรือนิ่วไต/hypercalciuria. Asymptomatic ที่ไม่เข้าเกณฑ์ ติดตามได้.", "id": "set2-83"}, {"topic": "Endocrinology", "q": "A patient with hypocalcemia, high phosphate, and LOW PTH after neck surgery has:", "choices": ["Primary hyperparathyroidism", "Hypoparathyroidism", "Secondary hyperparathyroidism", "Vitamin D deficiency", "Pseudohypoparathyroidism"], "ans": 1, "exp": "หลังผ่าตัดคอ + Ca ต่ำ + PO4 สูง + PTH ต่ำ = hypoparathyroidism (มัก iatrogenic). รักษาด้วย calcium + calcitriol. Secondary hyperparathyroidism (CKD/vit D ต่ำ) จะมี PTH สูง.", "id": "set2-84"}, {"topic": "Endocrinology", "q": "A patient has fasting triglycerides of 1200 mg/dL. What is the main acute risk and treatment?", "choices": ["Stroke; statin", "Acute pancreatitis; fibrate/omega-3 and control of diabetes/alcohol", "MI; aspirin", "Gout; allopurinol", "None; observe"], "ans": 1, "exp": "TG สูงมาก (> 500–1000) เสี่ยง acute pancreatitis. รักษาด้วย fibrate/omega-3, คุมเบาหวาน/งดแอลกอฮอล์/ลดน้ำตาล/ลดน้ำหนัก. Statin ลด LDL แต่ไม่ใช่ตัวหลักลด TG สูงมาก.", "id": "set2-85"}, {"topic": "Endocrinology", "q": "A patient with newly diagnosed T2DM and A1c 11% with symptoms (polyuria, weight loss). What is appropriate initial therapy?", "choices": ["Lifestyle alone for 3 months", "Insulin (± metformin) given marked hyperglycemia/symptoms", "Sulfonylurea only", "Acarbose", "Observation"], "ans": 1, "exp": "A1c สูงมาก (> 10%) + อาการ/catabolic (น้ำหนักลด) ควรเริ่ม insulin (± metformin) เพื่อคุมน้ำตาลเร็ว แล้วค่อยปรับลดเมื่อดีขึ้น. Lifestyle เดี่ยวไม่พอในภาวะน้ำตาลสูงมีอาการ.", "id": "set2-86"}, {"topic": "Endocrinology", "q": "A patient develops flushing, diarrhea, and right-sided heart valve disease; urine 5-HIAA is elevated. What is the diagnosis?", "choices": ["Pheochromocytoma", "Carcinoid syndrome", "Cushing syndrome", "Medullary thyroid cancer", "VIPoma"], "ans": 1, "exp": "Flushing + diarrhea + right-heart valvular disease + urine 5-HIAA สูง = carcinoid syndrome (serotonin จาก neuroendocrine tumor, มัก GI + liver metastasis). รักษาด้วย somatostatin analog (octreotide).", "id": "set2-87"}, {"topic": "Endocrinology", "q": "A patient with poorly controlled diabetes has bilateral lower-limb sensory loss in a 'stocking' distribution. What is the pattern of neuropathy?", "choices": ["Mononeuropathy", "Distal symmetric polyneuropathy", "Radiculopathy", "Autonomic only", "Plexopathy"], "ans": 1, "exp": "Diabetic peripheral neuropathy ที่พบบ่อยสุดคือ distal symmetric (length-dependent) polyneuropathy แบบ stocking-glove. เสี่ยงแผลที่เท้า จึงต้องตรวจเท้า/สอนดูแลเท้า.", "id": "set2-88"}, {"topic": "Endocrinology", "q": "A patient on long-term glucocorticoids is at risk of which complications requiring monitoring?", "choices": ["Hypoglycemia and weight loss", "Hyperglycemia, osteoporosis, hypertension, infection, adrenal suppression", "Hyperkalemia", "Bradycardia", "Hypercalcemia"], "ans": 1, "exp": "Long-term corticosteroid เสี่ยง hyperglycemia, osteoporosis, HT, น้ำหนักขึ้น/central obesity, ติดเชื้อ, cataract, และ HPA axis suppression (ห้ามหยุดกะทันหัน → adrenal crisis). ต้อง taper และให้ stress dose.", "id": "set2-89"}, {"topic": "Endocrinology", "q": "A patient with type 2 diabetes and obesity would benefit most (for weight and glycemia) from which class?", "choices": ["Sulfonylurea", "GLP-1 receptor agonist (or dual GIP/GLP-1, e.g., tirzepatide)", "Insulin", "Thiazolidinedione", "DPP-4 inhibitor"], "ans": 1, "exp": "GLP-1 RA (semaglutide/liraglutide) และ dual GIP/GLP-1 (tirzepatide) ลดทั้งน้ำตาลและน้ำหนักเด่นชัด เหมาะกับ T2DM + obesity. Sulfonylurea/insulin/TZD ทำให้น้ำหนักขึ้น.", "id": "set2-90"}, {"topic": "Endocrinology", "q": "A diabetic patient has an A1c goal individualized. Which patient is appropriate for a LESS stringent target (e.g., < 8%)?", "choices": ["Young, newly diagnosed, no complications", "Elderly with multiple comorbidities and hypoglycemia risk", "Pregnant patient", "Patient wanting tight control", "Athlete"], "ans": 1, "exp": "เป้า A1c ปรับตามผู้ป่วย: ผ่อนเป้า (< 8%) ในผู้สูงอายุ/โรคร่วมมาก/เสี่ยง hypoglycemia/ life expectancy สั้น. เข้มขึ้น (< 6.5%) ในคนอายุน้อย สุขภาพดี ไม่มีภาวะแทรกซ้อน.", "id": "set2-91"}, {"topic": "Endocrinology", "q": "A patient has weight gain, proximal myopathy, easy bruising, and hyperglycemia; ACTH is elevated and high-dose dexamethasone suppresses cortisol. Where is the lesion?", "choices": ["Adrenal adenoma", "Pituitary (Cushing disease)", "Ectopic ACTH from lung cancer", "Exogenous steroid", "Adrenal carcinoma"], "ans": 1, "exp": "ACTH-dependent Cushing ที่ high-dose dexamethasone suppress ได้ = pituitary source (Cushing disease). Ectopic ACTH (เช่น SCLC) มักไม่ suppress และ ACTH สูงมาก.", "id": "set2-92"}, {"topic": "Endocrinology", "q": "A patient with hypothyroidism on levothyroxine still has high TSH despite adherence. What common issue should be checked?", "choices": ["Taking it with food/calcium/iron (impaired absorption) or inadequate dose", "Overdose", "Hyperthyroidism", "Adrenal crisis", "Normal finding"], "ans": 0, "exp": "TSH ยังสูงทั้งที่กินยา — ตรวจการดูดซึม: levothyroxine ควรกินตอนท้องว่าง ห่างจากอาหาร/calcium/iron/PPI; หรือขนาดยาไม่พอ. ปรับขนาดตาม TSH ทุก 6–8 สัปดาห์.", "id": "set2-93"}, {"topic": "Endocrinology", "q": "A patient presents with tetany and carpopedal spasm; ionized calcium is low. Which acute treatment is appropriate for symptomatic hypocalcemia?", "choices": ["Oral calcium only", "IV calcium gluconate", "Vitamin D alone", "Phosphate", "Bisphosphonate"], "ans": 1, "exp": "Symptomatic hypocalcemia (tetany, Trousseau/Chvostek, seizure, QT ยาว) รักษาด้วย IV calcium gluconate + แก้ Mg ถ้าต่ำ + ตามด้วย oral calcium/calcitriol. หาสาเหตุ (hypoparathyroid, vit D).", "id": "set2-94"}, {"topic": "Endocrinology", "q": "A patient with Graves disease is treated with radioactive iodine. What is the most common long-term outcome to counsel about?", "choices": ["Permanent hyperthyroidism", "Hypothyroidism requiring levothyroxine", "Thyroid cancer", "No change", "Adrenal failure"], "ans": 1, "exp": "RAI สำหรับ Graves มักทำให้เกิด hypothyroidism ในระยะยาว ต้องได้ levothyroxine. RAI เป็นข้อห้ามในการตั้งครรภ์/ให้นม และอาจทำให้ Graves ophthalmopathy แย่ลงชั่วคราว (พิจารณา steroid คลุม).", "id": "set2-95"}, {"topic": "Endocrinology", "q": "A patient with an incidental adrenal mass (incidentaloma) requires evaluation for which functional problems?", "choices": ["Only size", "Hormonal hypersecretion (cortisol/Cushing, pheochromocytoma, aldosterone) and malignancy features", "Thyroid function", "Prolactin", "GH only"], "ans": 1, "exp": "Adrenal incidentaloma ต้องประเมิน functional: cortisol excess (dexamethasone suppression), pheochromocytoma (metanephrines), และ aldosterone (ARR ถ้ามี HT/hypoK) + ลักษณะ malignant (size > 4 cm, imaging phenotype).", "id": "set2-96"}, {"topic": "Endocrinology", "q": "A malnourished alcoholic patient is started on IV dextrose and develops confusion; you should also give which vitamin to prevent Wernicke encephalopathy?", "choices": ["Vitamin C", "Thiamine (B1) before/with glucose", "Folate only", "Vitamin D", "Vitamin K"], "ans": 1, "exp": "ผู้ป่วยขาดสารอาหาร/แอลกอฮอล์ ต้องให้ thiamine (B1) ก่อนหรือพร้อมกับ glucose เพื่อป้องกัน/รักษา Wernicke encephalopathy (การให้ glucose ก่อนอาจกระตุ้นอาการ). Triad: confusion, ophthalmoplegia, ataxia.", "id": "set2-97"}, {"topic": "Endocrinology", "q": "A patient with a large non-functioning pituitary macroadenoma presents with bitemporal hemianopia. What is the mechanism?", "choices": ["Cavernous sinus invasion", "Compression of the optic chiasm", "Increased intracranial pressure", "Retinal detachment", "Occipital stroke"], "ans": 1, "exp": "Pituitary macroadenoma กด optic chiasm ทำให้เกิด bitemporal hemianopia (เสียลานสายตาด้านนอกทั้งสองข้าง). ประเมิน visual field + MRI + hormone panel; ผ่าตัด transsphenoidal ถ้ากดเส้นประสาท.", "id": "set2-98"}, {"topic": "Endocrinology", "q": "A patient with hypothyroidism and coexisting untreated adrenal insufficiency is given levothyroxine first. What can occur?", "choices": ["Nothing", "Precipitation of adrenal crisis", "Thyroid storm", "Hyperkalemia resolves", "Hypoglycemia only"], "ans": 1, "exp": "ถ้ามี adrenal insufficiency ร่วม การเริ่ม levothyroxine ก่อนให้ steroid จะเพิ่ม metabolic demand และ cortisol clearance → กระตุ้น adrenal crisis. ต้องให้ glucocorticoid ก่อน/พร้อมกับ thyroid replacement.", "id": "set2-99"}, {"topic": "Endocrinology", "q": "A patient with diabetes has an A1c that seems discordantly low despite high glucose readings. Which condition can falsely lower A1c?", "choices": ["Iron deficiency anemia", "Hemolytic anemia or recent blood loss (reduced RBC lifespan)", "Splenectomy", "Vitamin B12 deficiency", "Renal failure raising it"], "ans": 1, "exp": "A1c ต่ำผิดปกติเมื่อ RBC lifespan สั้นลง (hemolysis, เสียเลือด, ตั้งครรภ์). ในทางกลับกัน iron deficiency/asplenia ทำให้ A1c สูงลวง. ในกรณีเหล่านี้ใช้ fructosamine หรือ glucose monitoring แทน.", "id": "set2-100"}]}, {"id": "set3", "title": "ชุดที่ 3 — GI/Hepatology + Hematology", "questions": [{"topic": "GI/Hepatology", "q": "A 48-year-old obese man has retrosternal burning after large meals, worse when lying down, with no alarm features. What is the most appropriate initial step?", "choices": ["Immediate endoscopy", "Lifestyle modification and an empiric PPI trial", "24-hour pH monitoring", "Barium swallow", "Nissen fundoplication"], "ans": 1, "exp": "GERD ที่ไม่มี alarm features รักษาเริ่มด้วย lifestyle modification + empiric PPI. Endoscopy เมื่อมี alarm (กลืนลำบาก/น้ำหนักลด/เลือดออก/ซีด/อายุมาก). (แนวข้อสอบ NLE2)", "id": "set3-1"}, {"topic": "GI/Hepatology", "q": "Which alarm feature in a patient with dyspepsia mandates upper endoscopy?", "choices": ["Age < 30", "Weight loss, dysphagia, GI bleeding, or anemia", "Occasional bloating", "Symptoms after coffee", "Family history of GERD"], "ans": 1, "exp": "Alarm features ที่ต้อง endoscopy: น้ำหนักลด, กลืนลำบาก/เจ็บ, เลือดออก (melena/hematemesis)/ซีด, อาเจียนเรื้อรัง, คลำก้อน, อายุ ≥ 50 เริ่มใหม่, ประวัติมะเร็งในครอบครัว.", "id": "set3-2"}, {"topic": "GI/Hepatology", "q": "A patient with a duodenal ulcer tests positive for H. pylori. What is the appropriate treatment?", "choices": ["PPI alone", "Triple/quadruple therapy (PPI + antibiotics) to eradicate H. pylori", "Antacids only", "Surgery", "H2 blocker alone"], "ans": 1, "exp": "PUD จาก H. pylori รักษาด้วย eradication therapy (PPI + amoxicillin + clarithromycin หรือ bismuth quadruple 14 วัน) + PPI. ยืนยันการกำจัดด้วย urea breath test/stool antigen หลังหยุดยา.", "id": "set3-3"}, {"topic": "GI/Hepatology", "q": "Which is the most appropriate non-invasive test to confirm H. pylori eradication after treatment?", "choices": ["Serology (antibody)", "Urea breath test or stool antigen", "Rapid urease during endoscopy", "Culture", "Random antibody titer"], "ans": 1, "exp": "ยืนยันการกำจัด H. pylori ด้วย urea breath test หรือ stool antigen (non-invasive, สะท้อน active infection). Serology ยังบวกได้แม้หายแล้วจึงไม่เหมาะยืนยันการกำจัด. หยุด PPI ≥ 2 สัปดาห์ก่อนตรวจ.", "id": "set3-4"}, {"topic": "GI/Hepatology", "q": "A patient presents with sudden severe epigastric pain, a rigid abdomen, and free air under the diaphragm on upright CXR. What is the diagnosis?", "choices": ["Acute pancreatitis", "Perforated peptic ulcer", "Acute cholecystitis", "Appendicitis", "Gastroenteritis"], "ans": 1, "exp": "ปวดท้องเฉียบพลันรุนแรง + peritonitis + free air ใต้ diaphragm = perforated peptic ulcer. รักษาผ่าตัด (simple closure + omental/Graham patch) + resuscitation + IV PPI/antibiotics.", "id": "set3-5"}, {"topic": "GI/Hepatology", "q": "A patient with cirrhosis presents with hematemesis. Besides resuscitation, which combination is appropriate for suspected variceal bleeding?", "choices": ["PPI alone", "Vasoactive drug (octreotide/terlipressin) + prophylactic antibiotic + endoscopic band ligation", "Beta-blocker infusion", "Tranexamic acid alone", "Observation"], "ans": 1, "exp": "Variceal bleeding: vasoactive (octreotide/terlipressin) + prophylactic antibiotic (ceftriaxone — ลด SBP/mortality) + endoscopic variceal ligation. ป้องกันซ้ำด้วย NSBB + EVL.", "id": "set3-6"}, {"topic": "GI/Hepatology", "q": "In an actively bleeding cirrhotic patient, why are prophylactic antibiotics given?", "choices": ["To treat SBP only", "They reduce bacterial infection, rebleeding, and mortality", "To prevent hepatic encephalopathy directly", "To treat the varices", "No proven benefit"], "ans": 1, "exp": "ผู้ป่วย cirrhosis ที่มี GI bleeding ให้ prophylactic antibiotic (ceftriaxone) ลดการติดเชื้อ (รวม SBP), ลด rebleeding และลด mortality — เป็นมาตรฐานการดูแล.", "id": "set3-7"}, {"topic": "GI/Hepatology", "q": "A patient with an upper GI bleed is stable with Hb 8. What transfusion strategy is preferred?", "choices": ["Liberal, keep Hb > 10", "Restrictive (transfuse to target Hb ~7)", "Transfuse only if Hb < 5", "No transfusion ever", "Whole blood only"], "ans": 1, "exp": "UGIB ใช้ restrictive transfusion strategy (เป้า Hb ~7, หรือ ~8 ในโรคหัวใจ) ให้ผลลัพธ์ดีกว่า liberal (โดยเฉพาะ variceal — การให้เลือดเกินเพิ่ม portal pressure/rebleeding).", "id": "set3-8"}, {"topic": "GI/Hepatology", "q": "A cirrhotic patient with ascites develops fever and abdominal pain; ascitic fluid PMN is 320/mm³. What is the diagnosis and treatment?", "choices": ["Secondary peritonitis; surgery", "Spontaneous bacterial peritonitis; cefotaxime", "Tuberculous peritonitis; anti-TB", "Malignant ascites; chemotherapy", "Pancreatic ascites; octreotide"], "ans": 1, "exp": "Ascitic fluid PMN ≥ 250 = spontaneous bacterial peritonitis (SBP). รักษาด้วย cefotaxime + IV albumin (ลด hepatorenal). ป้องกันซ้ำด้วย norfloxacin ในกลุ่มเสี่ยง.", "id": "set3-9"}, {"topic": "GI/Hepatology", "q": "A cirrhotic patient becomes confused with asterixis after constipation. What is the first-line treatment for hepatic encephalopathy?", "choices": ["Protein restriction long-term", "Lactulose (± rifaximin) and treat precipitants", "Sedation", "Benzodiazepine", "Diuretic"], "ans": 1, "exp": "Hepatic encephalopathy รักษาด้วย lactulose (เป้าถ่าย 2–3 ครั้ง/วัน ลด ammonia) ± rifaximin + หา/แก้ precipitant (ท้องผูก, เลือดออก, ติดเชื้อ, electrolyte, ยา sedative). ไม่จำกัดโปรตีนระยะยาว.", "id": "set3-10"}, {"topic": "GI/Hepatology", "q": "How is the serum-ascites albumin gradient (SAAG) used?", "choices": ["SAAG ≥ 1.1 g/dL indicates portal hypertension", "SAAG < 1.1 indicates portal hypertension", "SAAG measures infection", "SAAG measures malignancy", "SAAG is not useful"], "ans": 0, "exp": "SAAG = serum albumin − ascites albumin. ≥ 1.1 g/dL บ่งชี้ portal hypertension (cirrhosis, HF, Budd-Chiari); < 1.1 บ่งชี้สาเหตุอื่น (malignancy, TB, nephrotic, pancreatic).", "id": "set3-11"}, {"topic": "GI/Hepatology", "q": "A patient with chronic hepatitis B and cirrhosis needs HCC surveillance. What is the recommended approach?", "choices": ["CT abdomen yearly", "Ultrasound ± AFP every 6 months", "Endoscopy yearly", "No surveillance", "MRI monthly"], "ans": 1, "exp": "ผู้ป่วย cirrhosis หรือ HBV เสี่ยง HCC ควร surveillance ด้วย ultrasound ± AFP ทุก 6 เดือน. รอยโรคสงสัยยืนยันด้วย triple-phase CT/MRI (arterial enhancement + washout).", "id": "set3-12"}, {"topic": "GI/Hepatology", "q": "A patient has HBsAg positive, anti-HBc IgG positive, HBeAg positive, and high HBV DNA. What does this indicate?", "choices": ["Immunity from vaccination", "Chronic active hepatitis B with high infectivity", "Resolved infection", "Acute HAV", "Window period"], "ans": 1, "exp": "HBsAg + high HBV DNA + HBeAg = chronic active HBV ที่ติดต่อง่าย. Anti-HBs เดี่ยว = ภูมิจากวัคซีน; anti-HBc IgM = acute; anti-HBs + anti-HBc = หายและมีภูมิ. รักษา antiviral (tenofovir/entecavir) เมื่อเข้าเกณฑ์.", "id": "set3-13"}, {"topic": "GI/Hepatology", "q": "A person has anti-HBs positive but anti-HBc negative. What does this indicate?", "choices": ["Chronic infection", "Immunity from vaccination", "Acute infection", "Resolved natural infection", "Window period"], "ans": 1, "exp": "Anti-HBs positive + anti-HBc negative = ภูมิจากวัคซีน (ไม่เคยติดเชื้อธรรมชาติ). ถ้าเคยติดเชื้อแล้วหาย จะมีทั้ง anti-HBs + anti-HBc positive. (แนวข้อสอบ NLE2)", "id": "set3-14"}, {"topic": "GI/Hepatology", "q": "A patient with chronic hepatitis C (genotype-agnostic) should be offered which treatment with >95% cure?", "choices": ["Interferon + ribavirin", "Direct-acting antivirals (DAA)", "Lifelong lamivudine", "No treatment", "Corticosteroids"], "ans": 1, "exp": "Chronic HCV รักษาด้วย direct-acting antivirals (DAA) ระยะสั้น 8–12 สัปดาห์ หายกว่า 95% (SVR). Interferon เป็นของเดิมที่เลิกใช้แล้ว.", "id": "set3-15"}, {"topic": "GI/Hepatology", "q": "A patient develops jaundice, dark urine, and RUQ pain 3 weeks after starting a herbal weight-loss supplement; viral panel negative. Which test is most critical initially?", "choices": ["Lipid profile", "Liver function tests", "Creatinine", "TSH", "CBC only"], "ans": 1, "exp": "สงสัย drug/herb-induced liver injury — ตรวจ liver function tests (AST/ALT/bilirubin/ALP) เพื่อประเมินอวัยวะที่ถูกกระทบและรูปแบบ (hepatocellular vs cholestatic). หยุด agent ต้นเหตุ. (แนวข้อสอบ NLE2)", "id": "set3-16"}, {"topic": "GI/Hepatology", "q": "A patient meets 2 of 3 criteria for acute pancreatitis. What is the cornerstone of early management?", "choices": ["Prophylactic antibiotics for all", "Aggressive IV fluid resuscitation and analgesia with early enteral feeding", "Immediate surgery", "NPO for 2 weeks", "Immediate ERCP for all"], "ans": 1, "exp": "Acute pancreatitis รักษาด้วย aggressive IV fluid (goal-directed), analgesia, early enteral feeding. ไม่ให้ prophylactic antibiotic (ให้เมื่อ infected necrosis); ERCP เฉพาะเมื่อมี cholangitis/นิ่วอุดตัน.", "id": "set3-17"}, {"topic": "GI/Hepatology", "q": "Which are the two most common causes of acute pancreatitis?", "choices": ["Trauma and drugs", "Gallstones and alcohol", "Hyperlipidemia and mumps", "Scorpion sting and ERCP", "Autoimmune and idiopathic"], "ans": 1, "exp": "สาเหตุที่พบบ่อยที่สุดของ acute pancreatitis คือ gallstones และ alcohol. อื่นๆ (GET SMASHED): hyperTG, ERCP, drugs, trauma, mumps, autoimmune, scorpion. ตรวจ lipase > 3 เท่า + imaging.", "id": "set3-18"}, {"topic": "GI/Hepatology", "q": "A patient has painless obstructive jaundice with a palpable non-tender gallbladder (Courvoisier sign). What is the most concerning diagnosis?", "choices": ["Gallstone in cystic duct", "Pancreatic head / periampullary carcinoma", "Acute hepatitis", "Gilbert syndrome", "Hemolysis"], "ans": 1, "exp": "Courvoisier sign (ถุงน้ำดีโตคลำได้ ไม่เจ็บ + jaundice) บ่งชี้ malignant obstruction (pancreatic head/periampullary CA) มากกว่านิ่ว. ประเมินด้วย imaging (CT/MRCP/EUS); Whipple ถ้า resectable.", "id": "set3-19"}, {"topic": "GI/Hepatology", "q": "A patient with progressive dysphagia to solids then liquids, weight loss, and a history of smoking/alcohol most likely has:", "choices": ["Achalasia", "Esophageal carcinoma", "GERD", "Esophageal web", "Diffuse esophageal spasm"], "ans": 1, "exp": "Progressive dysphagia (solids → liquids) + น้ำหนักลด + สูบบุหรี่/เหล้า = esophageal carcinoma (upper/mid = SCC). Achalasia มัก dysphagia ต่อทั้ง solid+liquid ตั้งแต่ต้นและไม่ค่อยน้ำหนักลดเร็ว.", "id": "set3-20"}, {"topic": "GI/Hepatology", "q": "A patient has dysphagia to both solids and liquids; barium shows a dilated esophagus with a 'bird's beak' narrowing at the GE junction. What is the diagnosis?", "choices": ["Esophageal cancer", "Achalasia", "GERD stricture", "Schatzki ring", "Zenker diverticulum"], "ans": 1, "exp": "Dysphagia ต่อทั้ง solid+liquid + bird's beak (dilated esophagus, narrow GE junction) = achalasia (LES ไม่คลาย + aperistalsis). ยืนยันด้วย manometry; รักษา pneumatic dilatation/Heller myotomy/POEM. (แนวข้อสอบ NLE2)", "id": "set3-21"}, {"topic": "GI/Hepatology", "q": "A young patient has chronic bloody diarrhea, tenesmus, and continuous inflammation from the rectum proximally limited to the mucosa on colonoscopy. What is the diagnosis?", "choices": ["Crohn disease", "Ulcerative colitis", "Ischemic colitis", "Amoebic colitis", "Celiac disease"], "ans": 1, "exp": "Continuous inflammation จาก rectum ขึ้นไป, จำกัดที่ mucosa, bloody diarrhea = ulcerative colitis. Crohn = skip lesions, transmural, ทุกส่วนของ GI, fistula/granuloma.", "id": "set3-22"}, {"topic": "GI/Hepatology", "q": "Which feature is characteristic of Crohn disease rather than ulcerative colitis?", "choices": ["Continuous colonic involvement", "Transmural skip lesions with fistulas and granulomas", "Limited to rectum/colon", "Bloody diarrhea always", "No small bowel involvement"], "ans": 1, "exp": "Crohn: transmural, skip lesions, ได้ทุกส่วน (mouth-anus), fistula/stricture/perianal disease, non-caseating granuloma. UC: continuous, mucosal, จำกัด colon เริ่มจาก rectum.", "id": "set3-23"}, {"topic": "GI/Hepatology", "q": "A 35-year-old returning traveler has bloody, foul diarrhea; stool shows motile trophozoites with ingested RBCs. What is the treatment?", "choices": ["Ciprofloxacin", "Metronidazole (then a luminal agent)", "Ceftriaxone", "Albendazole", "Vancomycin"], "ans": 1, "exp": "Trophozoite ที่กิน RBC = Entamoeba histolytica (amoebic dysentery/liver abscess). รักษาด้วย metronidazole/tinidazole ตามด้วย luminal agent (paromomycin/diloxanide) กำจัด cyst. (แนวข้อสอบ NLE2)", "id": "set3-24"}, {"topic": "GI/Hepatology", "q": "A patient develops profuse watery diarrhea after recent antibiotic use; stool tests positive for C. difficile toxin. What is the first-line treatment?", "choices": ["Metronidazole IV", "Oral vancomycin or fidaxomicin", "Loperamide", "Ciprofloxacin", "Probiotics only"], "ans": 1, "exp": "C. difficile infection รักษา first-line ด้วย oral vancomycin หรือ fidaxomicin (metronidazole เป็นทางเลือกรองในรายไม่รุนแรงที่เข้าถึงยาหลักไม่ได้). หยุด antibiotic ต้นเหตุ; หลีกเลี่ยง antimotility.", "id": "set3-25"}, {"topic": "GI/Hepatology", "q": "A patient has chronic diarrhea, weight loss, iron deficiency, and a rash (dermatitis herpetiformis); anti-tissue transglutaminase is positive. What is the diagnosis?", "choices": ["Crohn disease", "Celiac disease", "Tropical sprue", "Lactose intolerance", "Whipple disease"], "ans": 1, "exp": "Malabsorption + anti-tTG positive + dermatitis herpetiformis = celiac disease. ยืนยันด้วย duodenal biopsy (villous atrophy); รักษาด้วย gluten-free diet.", "id": "set3-26"}, {"topic": "GI/Hepatology", "q": "A patient has right lower quadrant pain migrating from the periumbilical area, anorexia, and low-grade fever with McBurney tenderness. What is the diagnosis?", "choices": ["Gastroenteritis", "Acute appendicitis", "Diverticulitis", "Cholecystitis", "Mesenteric adenitis"], "ans": 1, "exp": "ปวด periumbilical แล้วย้ายมา RLQ (McBurney) + anorexia + ไข้ต่ำ = acute appendicitis. ยืนยัน US/CT; รักษา appendectomy (uncomplicated ที่ยืนยันด้วย CT อาจใช้ antibiotics-first ในบางราย).", "id": "set3-27"}, {"topic": "GI/Hepatology", "q": "An elderly patient has left lower quadrant pain, fever, and a CT showing sigmoid diverticula with pericolic inflammation. What is the diagnosis?", "choices": ["Appendicitis", "Acute diverticulitis", "Ulcerative colitis", "Ischemic colitis", "Colon cancer"], "ans": 1, "exp": "LLQ pain + ไข้ + sigmoid diverticula + pericolic fat stranding = acute diverticulitis. Uncomplicated รักษา bowel rest ± antibiotics; complicated (abscess/perforation) → drainage/surgery.", "id": "set3-28"}, {"topic": "GI/Hepatology", "q": "A 55-year-old has iron-deficiency anemia and change in bowel habits. What is the essential investigation?", "choices": ["Upper endoscopy only", "Colonoscopy to exclude colorectal cancer", "CT abdomen only", "Stool culture", "Reassurance"], "ans": 1, "exp": "IDA + เปลี่ยนแปลงการขับถ่ายในผู้ใหญ่ ≥ 45–50 ปี ต้อง colonoscopy เพื่อตัด colorectal cancer (เลือดออกเรื้อรัง). Right-sided CA มัก present ด้วย anemia/occult bleeding.", "id": "set3-29"}, {"topic": "GI/Hepatology", "q": "At what age should average-risk adults begin colorectal cancer screening according to current recommendations?", "choices": ["40", "45", "50", "60", "65"], "ans": 1, "exp": "USPSTF 2021 ลดอายุเริ่มคัดกรอง colorectal cancer เป็น 45 ปี (จากเดิม 50) ในคนความเสี่ยงปกติ — colonoscopy ทุก 10 ปี หรือ FIT ทุกปี.", "id": "set3-30"}, {"topic": "GI/Hepatology", "q": "A patient with cirrhosis has AKI unresponsive to volume with bland urine sediment. Which is a key treatment for hepatorenal syndrome?", "choices": ["Loop diuretic", "Terlipressin (or noradrenaline) plus albumin", "Dopamine", "NSAID", "Nephrotoxic antibiotics"], "ans": 1, "exp": "Hepatorenal syndrome รักษาด้วย vasoconstrictor (terlipressin หรือ noradrenaline) + albumin เพื่อเพิ่ม effective circulating volume; แก้ precipitant; ปลูกถ่ายตับเป็น definitive.", "id": "set3-31"}, {"topic": "GI/Hepatology", "q": "A patient has episodic upper abdominal pain after fatty meals with a positive Murphy sign and fever. Ultrasound shows a thickened gallbladder wall with stones. What is the diagnosis?", "choices": ["Biliary colic", "Acute cholecystitis", "Ascending cholangitis", "Pancreatitis", "Hepatitis"], "ans": 1, "exp": "RUQ pain + Murphy sign + ไข้ + gallstone + wall thickening = acute cholecystitis. รักษา NPO, IV fluid/antibiotics, analgesia + laparoscopic cholecystectomy (early). Biliary colic ไม่มีไข้/อักเสบ.", "id": "set3-32"}, {"topic": "GI/Hepatology", "q": "A patient has fever, jaundice, and RUQ pain (Charcot triad). What is the diagnosis and key intervention?", "choices": ["Cholecystitis; cholecystectomy", "Ascending cholangitis; biliary decompression (ERCP) + antibiotics", "Hepatitis; supportive", "Pancreatitis; fluids", "Liver abscess; drainage"], "ans": 1, "exp": "Charcot triad (fever + jaundice + RUQ pain) = ascending cholangitis (มัก choledocholithiasis). ต้อง IV antibiotics + biliary decompression (ERCP) ด่วน. Reynolds pentad (+ hypotension + confusion) = รุนแรง.", "id": "set3-33"}, {"topic": "GI/Hepatology", "q": "A patient with alcoholic liver disease has an AST:ALT ratio of about 2:1 and both are moderately elevated (< 300). What does this suggest?", "choices": ["Viral hepatitis", "Alcoholic hepatitis", "Ischemic hepatitis", "Autoimmune hepatitis", "Biliary obstruction"], "ans": 1, "exp": "AST:ALT > 2:1 กับ transaminase สูงปานกลาง (มัก < 300) เข้าได้กับ alcoholic liver disease/hepatitis. Viral hepatitis มัก ALT > AST และสูงมากได้.", "id": "set3-34"}, {"topic": "GI/Hepatology", "q": "A young woman has amenorrhea, high transaminases, positive ANA/anti-smooth muscle antibody, and high IgG. What is the diagnosis?", "choices": ["Viral hepatitis", "Autoimmune hepatitis", "Wilson disease", "Hemochromatosis", "Primary biliary cholangitis"], "ans": 1, "exp": "Autoimmune hepatitis: หญิงสาว, transaminase สูง, ANA/anti-smooth muscle Ab positive, IgG สูง. ยืนยันด้วย biopsy (interface hepatitis); รักษาด้วย corticosteroid ± azathioprine.", "id": "set3-35"}, {"topic": "GI/Hepatology", "q": "A young patient has liver disease, neuropsychiatric symptoms, and Kayser-Fleischer rings. What is the diagnosis?", "choices": ["Hemochromatosis", "Wilson disease", "Alpha-1 antitrypsin deficiency", "Autoimmune hepatitis", "Hepatitis B"], "ans": 1, "exp": "Wilson disease (copper สะสม): liver disease + neuropsychiatric + Kayser-Fleischer rings; ceruloplasmin ต่ำ, urinary copper สูง. รักษาด้วย chelator (penicillamine/trientine) + zinc.", "id": "set3-36"}, {"topic": "GI/Hepatology", "q": "A patient has bronze skin, diabetes, arthralgia, and elevated ferritin/transferrin saturation. What is the diagnosis?", "choices": ["Wilson disease", "Hereditary hemochromatosis", "Porphyria", "Alcoholic liver disease", "Hepatitis C"], "ans": 1, "exp": "Hereditary hemochromatosis (iron overload, HFE mutation): bronze diabetes + arthralgia + hepatomegaly/HCC risk; ferritin + transferrin saturation สูง. รักษาด้วย phlebotomy.", "id": "set3-37"}, {"topic": "GI/Hepatology", "q": "A patient has watery diarrhea, and stool osmotic gap is high, improving with fasting. What type of diarrhea is this?", "choices": ["Secretory", "Osmotic", "Inflammatory", "Infectious", "Fatty"], "ans": 1, "exp": "Osmotic diarrhea (เช่น lactose intolerance, laxative) มี stool osmotic gap สูง และดีขึ้นเมื่ออดอาหาร. Secretory diarrhea (เช่น cholera, VIPoma) ไม่หยุดเมื่ออดอาหารและ gap ต่ำ.", "id": "set3-38"}, {"topic": "GI/Hepatology", "q": "A patient has recurrent peptic ulcers in unusual locations with diarrhea and very high gastrin. What is the diagnosis?", "choices": ["Common PUD", "Zollinger-Ellison syndrome (gastrinoma)", "H. pylori infection", "GERD", "Menetrier disease"], "ans": 1, "exp": "แผลหลายตำแหน่ง/ตำแหน่งผิดปกติ + diarrhea + gastrin สูงมาก = Zollinger-Ellison syndrome (gastrinoma) มักสัมพันธ์ MEN1. ยืนยันด้วย secretin stimulation test.", "id": "set3-39"}, {"topic": "GI/Hepatology", "q": "A patient with severe acute pancreatitis develops persistent fever and clinical deterioration at 2 weeks; CT shows gas in a necrotic collection. What does this indicate?", "choices": ["Pseudocyst", "Infected pancreatic necrosis", "Splenic vein thrombosis", "Resolving pancreatitis", "Ascites"], "ans": 1, "exp": "ไข้ต่อเนื่อง + gas ใน necrotic collection = infected pancreatic necrosis → ให้ antibiotics + drainage/necrosectomy (step-up). Prophylactic antibiotic ไม่แนะนำ แต่ให้เมื่อมีการติดเชื้อยืนยัน.", "id": "set3-40"}, {"topic": "GI/Hepatology", "q": "A patient presents with hematochezia; after resuscitation, which is the most common cause of significant lower GI bleeding in older adults?", "choices": ["Hemorrhoids", "Diverticulosis", "Anal fissure", "Ischemic colitis", "Infectious colitis"], "ans": 1, "exp": "สาเหตุ LGIB ที่มีนัยสำคัญในผู้สูงอายุที่พบบ่อยคือ diverticulosis (และ angiodysplasia). ประเมินด้วย colonoscopy หลัง resuscitation; หา malignancy ด้วย.", "id": "set3-41"}, {"topic": "GI/Hepatology", "q": "A patient with cirrhosis has no prior variceal bleeding but endoscopy shows large esophageal varices. What is appropriate primary prophylaxis?", "choices": ["No treatment", "Non-selective beta-blocker (or endoscopic band ligation)", "PPI", "Antibiotics", "TIPS"], "ans": 1, "exp": "Primary prophylaxis ของ variceal bleeding ใน large varices = non-selective beta-blocker (propranolol/carvedilol) หรือ endoscopic variceal ligation. TIPS ใช้ในรายเลือดออกซ้ำ/ดื้อ.", "id": "set3-42"}, {"topic": "GI/Hepatology", "q": "A patient has chronic epigastric pain, steatorrhea, and new diabetes with pancreatic calcifications. What is the diagnosis?", "choices": ["Acute pancreatitis", "Chronic pancreatitis", "Pancreatic cancer", "Gallstones", "Celiac disease"], "ans": 1, "exp": "ปวดเรื้อรัง + steatorrhea (exocrine insufficiency) + DM (endocrine) + pancreatic calcification = chronic pancreatitis (มักจากแอลกอฮอล์). รักษาด้วย pancreatic enzyme replacement, คุมปวด, งดเหล้า.", "id": "set3-43"}, {"topic": "GI/Hepatology", "q": "A patient with a right-lobe liver abscess and recent travel/dysentery, positive amoebic serology. What is the treatment?", "choices": ["Surgical resection", "Metronidazole then a luminal agent", "Ceftriaxone alone", "Percutaneous drainage first-line always", "Albendazole"], "ans": 1, "exp": "Amoebic liver abscess (Entamoeba histolytica, มัก lobe ขวา) รักษาด้วย metronidazole ตามด้วย luminal agent. Drainage สงวนไว้เมื่อใหญ่มาก/ไม่ตอบสนอง/สงสัย pyogenic.", "id": "set3-44"}, {"topic": "GI/Hepatology", "q": "A patient with obstructive jaundice has a dilated common bile duct with a stone on MRCP. What is the appropriate intervention?", "choices": ["Cholecystectomy first", "ERCP with stone extraction", "Observation", "Antibiotics only", "Whipple procedure"], "ans": 1, "exp": "Choledocholithiasis (นิ่วใน CBD) รักษาด้วย ERCP + sphincterotomy/stone extraction; ตามด้วย cholecystectomy ถ้ามี gallstone. ถ้ามี cholangitis ต้อง decompress ด่วน.", "id": "set3-45"}, {"topic": "GI/Hepatology", "q": "A patient develops acute severe abdominal pain out of proportion to exam findings, with a history of AF; lactate is rising. What is the diagnosis?", "choices": ["Peptic ulcer", "Acute mesenteric ischemia", "Diverticulitis", "Pancreatitis", "Gastroenteritis"], "ans": 1, "exp": "ปวดท้องรุนแรงเกินกว่าตรวจพบ (pain out of proportion) + AF (embolic source) + lactate สูง = acute mesenteric ischemia (มัก SMA embolism). ต้อง CT angiography + revascularization ด่วน; delay = bowel necrosis.", "id": "set3-46"}, {"topic": "GI/Hepatology", "q": "A patient with Barrett esophagus is at increased risk of which malignancy?", "choices": ["Squamous cell carcinoma", "Esophageal adenocarcinoma", "Gastric lymphoma", "Small bowel carcinoid", "Pancreatic cancer"], "ans": 1, "exp": "Barrett esophagus (intestinal metaplasia จาก chronic GERD) เพิ่มเสี่ยง esophageal adenocarcinoma (lower third). เฝ้าระวังด้วย endoscopy + biopsy หา dysplasia.", "id": "set3-47"}, {"topic": "GI/Hepatology", "q": "A patient with jaundice has predominantly elevated unconjugated (indirect) bilirubin with normal LFTs and no hemolysis, worse with fasting/stress. What is the likely diagnosis?", "choices": ["Gilbert syndrome", "Viral hepatitis", "Biliary obstruction", "Cirrhosis", "Pancreatic cancer"], "ans": 0, "exp": "Indirect hyperbilirubinemia ที่ LFT ปกติ ไม่มี hemolysis, เป็นมากเวลาอด/เครียด = Gilbert syndrome (UGT1A1 ลดลง) — benign ไม่ต้องรักษา.", "id": "set3-48"}, {"topic": "GI/Hepatology", "q": "A patient with alcohol use disorder takes paracetamol 8 tabs/day for a week and presents with markedly elevated transaminases (AST/ALT in thousands). What is the mechanism of injury?", "choices": ["Cholestasis", "Hepatotoxic NAPQI accumulation with glutathione depletion", "Viral cytopathic effect", "Autoimmune", "Ischemia only"], "ans": 1, "exp": "Paracetamol เกินขนาด (ยิ่งในผู้ดื่มสุรา/อดอาหาร) สร้าง NAPQI มากขึ้นและ glutathione พร่อง → centrilobular hepatic necrosis (transaminase สูงเป็นพัน). รักษาด้วย N-acetylcysteine ตาม nomogram/เร็วที่สุด. (แนวข้อสอบ NLE2)", "id": "set3-49"}, {"topic": "GI/Hepatology", "q": "A patient presents with acute liver failure from paracetamol overdose. What is the specific antidote?", "choices": ["Naloxone", "N-acetylcysteine", "Flumazenil", "Vitamin K", "Fomepizole"], "ans": 1, "exp": "Paracetamol toxicity รักษาด้วย N-acetylcysteine (เติม glutathione precursor) ยิ่งให้เร็วยิ่งดี (ภายใน 8 ชม.). ประเมินด้วย paracetamol level + Rumack-Matthew nomogram; ดู King's College criteria สำหรับ transplant.", "id": "set3-50"}, {"topic": "GI/Hepatology", "q": "A patient has chronic constipation alternating with diarrhea, abdominal pain relieved by defecation, and normal investigations with no alarm features. What is the diagnosis?", "choices": ["Colorectal cancer", "Irritable bowel syndrome", "Ulcerative colitis", "Celiac disease", "Diverticulitis"], "ans": 1, "exp": "ปวดท้องเรื้อรังสัมพันธ์การขับถ่าย + เปลี่ยนความถี่/ลักษณะอุจจาระ โดยไม่มี alarm feature และตรวจปกติ = irritable bowel syndrome (Rome criteria). รักษาตามอาการ + diet (low-FODMAP) + ให้ความมั่นใจ.", "id": "set3-51"}, {"topic": "Hematology", "q": "A patient has microcytic hypochromic anemia with low ferritin and high RDW. What is the diagnosis and next step?", "choices": ["Thalassemia; Hb typing", "Iron deficiency anemia; find source of blood loss", "Anemia of chronic disease; treat inflammation", "Sideroblastic anemia; B6", "Lead poisoning; chelation"], "ans": 1, "exp": "Microcytic + ferritin ต่ำ = iron deficiency anemia. ในผู้ใหญ่ต้องหาสาเหตุเสียเลือด (GI → endoscopy; menorrhagia ในหญิง). รักษาด้วย ferrous + แก้สาเหตุ.", "id": "set3-52"}, {"topic": "Hematology", "q": "A Southeast Asian woman has microcytic anemia with NORMAL ferritin, target cells, basophilic stippling, and 'golf ball' inclusions on brilliant cresyl blue stain. What is the diagnosis?", "choices": ["Iron deficiency anemia", "Hemoglobin H disease", "Hereditary spherocytosis", "Megaloblastic anemia", "Autoimmune hemolytic anemia"], "ans": 1, "exp": "Microcytic ที่ ferritin ปกติ + target cell + HbH inclusion (golf ball ด้วย supravital stain) = Hemoglobin H disease (alpha-thalassemia, 3-gene deletion). ห้ามให้ธาตุเหล็กพร่ำเพรื่อ. (แนวข้อสอบ NLE2)", "id": "set3-53"}, {"topic": "Hematology", "q": "How can iron deficiency anemia be distinguished from thalassemia trait when both are microcytic?", "choices": ["RDW and ferritin (low in IDA, normal/high ferritin in thalassemia)", "MCV only", "Reticulocyte only", "WBC count", "Platelet count"], "ans": 0, "exp": "IDA: ferritin ต่ำ, RDW กว้าง, Mentzer index (MCV/RBC) > 13. Thalassemia trait: ferritin ปกติ/สูง, RDW ปกติ, RBC count สูง, Mentzer < 13, ยืนยันด้วย Hb typing.", "id": "set3-54"}, {"topic": "Hematology", "q": "A patient with rheumatoid arthritis has normocytic anemia, low serum iron, low TIBC, and high ferritin. What is the diagnosis?", "choices": ["Iron deficiency anemia", "Anemia of chronic disease", "Thalassemia", "Hemolytic anemia", "B12 deficiency"], "ans": 1, "exp": "Anemia of chronic disease/inflammation: iron ต่ำ, TIBC ต่ำ, ferritin สูง (acute phase, hepcidin สูง). ต่างจาก IDA ที่ TIBC สูง ferritin ต่ำ. รักษาที่โรคต้นเหตุ.", "id": "set3-55"}, {"topic": "Hematology", "q": "A patient has macrocytic anemia with hypersegmented neutrophils and neurological symptoms (paresthesia, ataxia). What is the deficiency?", "choices": ["Folate", "Vitamin B12 (cobalamin)", "Iron", "Vitamin C", "Vitamin K"], "ans": 1, "exp": "Macrocytic + hypersegmented neutrophils + neuro (subacute combined degeneration) = B12 deficiency. Folate deficiency ให้ภาพ megaloblastic เหมือนกันแต่ไม่มี neuro. ให้ B12 ก่อน folate เพื่อไม่บดบัง neuro.", "id": "set3-56"}, {"topic": "Hematology", "q": "A patient of Thai descent develops acute hemolysis after taking an antimalarial or eating fava beans; blood smear shows bite cells and Heinz bodies. What is the diagnosis?", "choices": ["Hereditary spherocytosis", "G6PD deficiency", "Autoimmune hemolytic anemia", "Thalassemia", "Sickle cell disease"], "ans": 1, "exp": "Hemolysis หลังยา/ถั่วปากอ้า/ติดเชื้อ + bite cells + Heinz bodies (X-linked) = G6PD deficiency (พบบ่อยในไทย). หลีกเลี่ยง oxidative triggers; ตรวจ G6PD level หลัง acute episode (อาจปกติลวงช่วง hemolysis).", "id": "set3-57"}, {"topic": "Hematology", "q": "A patient has anemia with high reticulocytes, high LDH, high indirect bilirubin, low haptoglobin, and a positive direct Coombs test. What is the diagnosis?", "choices": ["Iron deficiency", "Autoimmune hemolytic anemia", "Thalassemia", "Aplastic anemia", "Anemia of chronic disease"], "ans": 1, "exp": "Hemolysis markers (retic สูง, LDH สูง, indirect bili สูง, haptoglobin ต่ำ) + direct Coombs positive = autoimmune hemolytic anemia. Warm (IgG) vs cold (IgM). รักษา warm AIHA ด้วย corticosteroid. (แนวข้อสอบ NLE2)", "id": "set3-58"}, {"topic": "Hematology", "q": "A patient with anemia has spherocytes on smear, a negative Coombs test, splenomegaly, and a family history; osmotic fragility is increased. What is the diagnosis?", "choices": ["Autoimmune hemolytic anemia", "Hereditary spherocytosis", "G6PD deficiency", "Thalassemia", "Sickle cell"], "ans": 1, "exp": "Spherocytes + Coombs negative + ประวัติครอบครัว + osmotic fragility เพิ่ม = hereditary spherocytosis (membrane defect). ต่างจาก AIHA (Coombs positive). รักษา folate ± splenectomy ในรายรุนแรง.", "id": "set3-59"}, {"topic": "Hematology", "q": "A patient receiving packed red cells develops fever, chills, back pain, hypotension, and dark urine 15 minutes into transfusion. What is the diagnosis and immediate action?", "choices": ["Febrile non-hemolytic; slow the rate", "Acute hemolytic (ABO mismatch); stop transfusion immediately", "TACO; diuretic", "Allergic; antihistamine", "TRALI; ventilate"], "ans": 1, "exp": "อาการเฉียบพลัน (ไข้ ปวดหลัง hypotension hemoglobinuria) = acute hemolytic transfusion reaction (ABO incompatibility). หยุดให้เลือดทันที, IV fluid รักษาไต, ตรวจซ้ำ. (แนวข้อสอบ NLE2)", "id": "set3-60"}, {"topic": "Hematology", "q": "A patient develops dyspnea and bilateral pulmonary infiltrates within 6 hours of transfusion, with normal cardiac filling. What is the diagnosis?", "choices": ["TACO", "Transfusion-related acute lung injury (TRALI)", "Anaphylaxis", "Acute hemolysis", "Febrile reaction"], "ans": 1, "exp": "Non-cardiogenic pulmonary edema ภายใน 6 ชม.หลังให้เลือด (donor antibody ต่อ leukocyte) = TRALI. ต่างจาก TACO (volume overload, cardiogenic). รักษาแบบ supportive/ventilation; TACO ใช้ diuretic.", "id": "set3-61"}, {"topic": "Hematology", "q": "A stable patient needs platelet transfusion prophylaxis. At what platelet count is prophylactic transfusion generally indicated?", "choices": ["< 100,000", "< 50,000", "< 10,000 (or < 50,000 if bleeding/procedure)", "< 150,000", "Never prophylactically"], "ans": 2, "exp": "Platelet transfusion เชิงป้องกันเมื่อ < 10,000 (เสี่ยงเลือดออกเอง); ให้ที่ < 50,000 ถ้ามีเลือดออก/ก่อนหัตถการ; < 100,000 สำหรับ neurosurgery/ตา.", "id": "set3-62"}, {"topic": "Hematology", "q": "A patient has isolated thrombocytopenia with mucocutaneous bleeding, normal WBC/Hb, and a normal-sized spleen; other causes excluded. What is the diagnosis?", "choices": ["TTP", "Immune thrombocytopenic purpura (ITP)", "DIC", "Aplastic anemia", "Leukemia"], "ans": 1, "exp": "Isolated thrombocytopenia (line อื่นปกติ) + mucocutaneous bleeding + exclude สาเหตุอื่น = ITP (autoimmune). รักษาเมื่อเลือดออก/นับต่ำมากด้วย corticosteroid/IVIG.", "id": "set3-63"}, {"topic": "Hematology", "q": "A patient with sepsis has bleeding from venipuncture sites; labs show prolonged PT/aPTT, low fibrinogen, high D-dimer, low platelets, and schistocytes. What is the diagnosis?", "choices": ["ITP", "Disseminated intravascular coagulation (DIC)", "TTP", "Hemophilia", "Vitamin K deficiency"], "ans": 1, "exp": "Consumptive coagulopathy (PT/aPTT ยาว, fibrinogen ต่ำ, D-dimer สูง, platelet ต่ำ, schistocyte) ในภาวะ sepsis = DIC. รักษาที่สาเหตุ + component (FFP/cryo/platelet) ตามการเลือดออก.", "id": "set3-64"}, {"topic": "Hematology", "q": "A patient has microangiopathic hemolytic anemia, thrombocytopenia, fever, neurologic changes, and renal involvement with very low ADAMTS13. What is the treatment?", "choices": ["Platelet transfusion", "Plasma exchange (plasmapheresis)", "Corticosteroid alone", "Heparin", "Observation"], "ans": 1, "exp": "TTP (pentad: MAHA + thrombocytopenia + fever + neuro + renal; ADAMTS13 ต่ำ) รักษาด้วย plasma exchange ด่วน ± steroid/rituximab. ห้ามให้ platelet transfusion (ยกเว้นเลือดออกคุกคามชีวิต) เพราะเพิ่ม thrombosis.", "id": "set3-65"}, {"topic": "Hematology", "q": "A boy has recurrent hemarthrosis and deep muscle bleeds; aPTT is prolonged, PT normal, and factor VIII is low. What is the diagnosis?", "choices": ["Hemophilia A", "von Willebrand disease", "Vitamin K deficiency", "ITP", "Hemophilia B"], "ans": 0, "exp": "Hemarthrosis/deep bleeding + isolated prolonged aPTT + factor VIII ต่ำ (X-linked) = hemophilia A. Factor IX ต่ำ = hemophilia B. รักษาด้วย factor replacement.", "id": "set3-66"}, {"topic": "Hematology", "q": "A patient has mucosal/skin bleeding, prolonged bleeding time, prolonged aPTT, and low ristocetin cofactor activity. What is the diagnosis?", "choices": ["Hemophilia A", "von Willebrand disease", "ITP", "DIC", "Glanzmann thrombasthenia"], "ans": 1, "exp": "vWD (โรคเลือดออกทางพันธุกรรมที่พบบ่อยสุด): mucocutaneous bleeding + platelet-type + aPTT อาจยาว (vWF พา factor VIII) + ristocetin cofactor ต่ำ. รักษา desmopressin/vWF concentrate.", "id": "set3-67"}, {"topic": "Hematology", "q": "A patient on heparin develops a drop in platelets 5–10 days after starting, with new thrombosis. What is the diagnosis and action?", "choices": ["DIC; give heparin", "Heparin-induced thrombocytopenia; stop heparin and start a non-heparin anticoagulant", "ITP; steroid", "TTP; plasma exchange", "Normal; continue"], "ans": 1, "exp": "HIT (platelet ลด > 50% วันที่ 5–10 + thrombosis, anti-PF4 antibody) — หยุด heparin ทุกชนิดทันที และเปลี่ยนเป็น non-heparin anticoagulant (argatroban/fondaparinux/DOAC). ห้ามให้ platelet/warfarin เดี่ยวช่วงเฉียบพลัน.", "id": "set3-68"}, {"topic": "Hematology", "q": "A patient has prolonged PT with normal aPTT and bleeding; this improves with vitamin K. Which factor is affected earliest?", "choices": ["Factor VIII", "Factor VII (extrinsic pathway)", "Factor IX", "Fibrinogen", "Factor XIII"], "ans": 1, "exp": "Isolated prolonged PT = extrinsic pathway (factor VII มี half-life สั้นสุด จึงเสียก่อนใน vitamin K deficiency/warfarin/liver disease). aPTT = intrinsic (VIII, IX).", "id": "set3-69"}, {"topic": "Hematology", "q": "An elderly patient has fatigue, bone pain, anemia, hypercalcemia, renal failure, and lytic bone lesions. Serum protein electrophoresis shows an M-spike. What is the diagnosis?", "choices": ["Chronic lymphocytic leukemia", "Multiple myeloma", "Lymphoma", "Metastatic carcinoma", "MGUS"], "ans": 1, "exp": "CRAB (hyperCalcemia, Renal failure, Anemia, Bone lytic lesions) + M-protein + plasma cells = multiple myeloma. ตรวจ serum/urine electrophoresis, free light chain, bone marrow. (แนวข้อสอบ NLE2)", "id": "set3-70"}, {"topic": "Hematology", "q": "In multiple myeloma, urine testing classically reveals which protein?", "choices": ["Albumin", "Bence Jones protein (free light chains)", "Myoglobin", "Hemoglobin", "Transferrin"], "ans": 1, "exp": "Multiple myeloma หลั่ง free light chains ที่ตรวจพบในปัสสาวะเป็น Bence Jones protein (urine dipstick มัก negative เพราะจับ albumin เป็นหลัก → ต้อง electrophoresis). (แนวข้อสอบ NLE2)", "id": "set3-71"}, {"topic": "Hematology", "q": "A young adult has painless cervical lymphadenopathy, fever, night sweats, weight loss, and Reed-Sternberg cells on biopsy. What is the diagnosis?", "choices": ["Non-Hodgkin lymphoma", "Hodgkin lymphoma", "Tuberculous lymphadenitis", "CLL", "Reactive lymphadenopathy"], "ans": 1, "exp": "Painless lymphadenopathy + B symptoms + Reed-Sternberg cells = Hodgkin lymphoma (แพร่แบบต่อเนื่อง, พยากรณ์ดี). Staging ด้วย PET/CT; รักษา chemo (ABVD) ± RT.", "id": "set3-72"}, {"topic": "Hematology", "q": "A child presents with pallor, bruising, fever, and bone pain; blood shows > 20% lymphoblasts. What is the most likely diagnosis?", "choices": ["Acute myeloid leukemia", "Acute lymphoblastic leukemia", "Chronic myeloid leukemia", "Aplastic anemia", "ITP"], "ans": 1, "exp": "เด็ก + bone marrow failure (ซีด/เลือดออก/ติดเชื้อ) + lymphoblasts > 20% = acute lymphoblastic leukemia (ALL, พบบ่อยในเด็ก). AML พบผู้ใหญ่ (Auer rods). เป็นภาวะเร่งด่วน.", "id": "set3-73"}, {"topic": "Hematology", "q": "An adult with fatigue and gum infiltration has a bone marrow with myeloblasts containing Auer rods. What is the diagnosis?", "choices": ["ALL", "Acute myeloid leukemia", "CML", "CLL", "Myelofibrosis"], "ans": 1, "exp": "Auer rods ใน myeloblasts = acute myeloid leukemia. APL (AML-M3, t(15;17)) เสี่ยง DIC รักษาด้วย ATRA. เป็นภาวะเร่งด่วน.", "id": "set3-74"}, {"topic": "Hematology", "q": "A middle-aged patient has marked leukocytosis with all granulocyte stages and a Philadelphia chromosome (BCR-ABL). What is the treatment?", "choices": ["Chemotherapy only", "Tyrosine kinase inhibitor (imatinib)", "Splenectomy", "Observation", "Steroids"], "ans": 1, "exp": "CML (Philadelphia chromosome, BCR-ABL, leukocytosis + all maturation stages, basophilia, splenomegaly) รักษาด้วย tyrosine kinase inhibitor (imatinib/dasatinib) — เปลี่ยน prognosis อย่างมาก.", "id": "set3-75"}, {"topic": "Hematology", "q": "An elderly patient has lymphocytosis with smudge cells on smear and mature-appearing lymphocytes. What is the diagnosis?", "choices": ["ALL", "Chronic lymphocytic leukemia", "CML", "Hodgkin lymphoma", "Reactive lymphocytosis"], "ans": 1, "exp": "ผู้สูงอายุ + mature lymphocytosis + smudge cells = chronic lymphocytic leukemia (CLL). มักดำเนินโรคช้า; รักษาเมื่อมีอาการ/cytopenia/rapid progression.", "id": "set3-76"}, {"topic": "Hematology", "q": "A patient with polycythemia has elevated hematocrit, low erythropoietin, splenomegaly, and a JAK2 mutation. What is the diagnosis and a key treatment?", "choices": ["Secondary polycythemia; oxygen", "Polycythemia vera; therapeutic phlebotomy + aspirin", "Relative polycythemia; hydration", "Dehydration; fluids", "CML; imatinib"], "ans": 1, "exp": "Polycythemia vera (JAK2 V617F, EPO ต่ำ, splenomegaly) รักษาด้วย phlebotomy (เป้า Hct < 45%) + low-dose aspirin ± hydroxyurea ในรายเสี่ยงสูง. เสี่ยง thrombosis.", "id": "set3-77"}, {"topic": "Hematology", "q": "A patient with cancer on chemotherapy develops fever and an absolute neutrophil count < 500. What is the immediate management?", "choices": ["Oral antibiotics next day", "Empiric broad-spectrum IV antibiotics within 1 hour", "G-CSF only", "Antifungal only", "Observation"], "ans": 1, "exp": "Febrile neutropenia เป็นภาวะฉุกเฉิน — ให้ empiric broad-spectrum IV antibiotic (คลุม Pseudomonas เช่น piperacillin-tazobactam/cefepime/carbapenem) ภายใน 1 ชม.หลังเจาะ culture.", "id": "set3-78"}, {"topic": "Hematology", "q": "A patient starting chemotherapy for a bulky lymphoma develops hyperkalemia, hyperphosphatemia, hyperuricemia, and hypocalcemia. What is the diagnosis and prevention?", "choices": ["DIC; heparin", "Tumor lysis syndrome; hydration + allopurinol/rasburicase", "SIADH; fluid restriction", "Hypercalcemia; bisphosphonate", "Sepsis; antibiotics"], "ans": 1, "exp": "Tumor lysis syndrome (high K/PO4/uric acid, low Ca) หลัง chemo tumor ใหญ่. ป้องกัน/รักษาด้วย aggressive hydration + allopurinol (หรือ rasburicase ในรายเสี่ยงสูง) + แก้ electrolyte.", "id": "set3-79"}, {"topic": "Hematology", "q": "A patient with pancytopenia has a hypocellular bone marrow with no abnormal cells or fibrosis. What is the diagnosis?", "choices": ["Leukemia", "Aplastic anemia", "Myelodysplastic syndrome", "Myelofibrosis", "Megaloblastic anemia"], "ans": 1, "exp": "Pancytopenia + hypocellular marrow (ไม่มี blast/fibrosis) = aplastic anemia (idiopathic/ยา/ไวรัส/toxin). รักษาด้วย immunosuppression (ATG+ciclosporin) หรือ stem cell transplant; supportive transfusion.", "id": "set3-80"}, {"topic": "Hematology", "q": "An older patient has macrocytic anemia and cytopenias with dysplastic cells and ring sideroblasts in marrow. What is the diagnosis?", "choices": ["Aplastic anemia", "Myelodysplastic syndrome", "AML", "B12 deficiency", "Thalassemia"], "ans": 1, "exp": "Cytopenia + dysplasia (± ring sideroblasts) ในผู้สูงอายุ = myelodysplastic syndrome (clonal, เสี่ยงเปลี่ยนเป็น AML). รักษาตามความเสี่ยง (supportive, ESA, hypomethylating agent, transplant).", "id": "set3-81"}, {"topic": "Hematology", "q": "A pregnant woman with unprovoked DVT needs anticoagulation. Which agent is preferred?", "choices": ["Warfarin", "Low-molecular-weight heparin", "DOAC", "Aspirin", "No treatment"], "ans": 1, "exp": "ในการตั้งครรภ์ใช้ LMWH (ไม่ผ่านรก, ปลอดภัย). Warfarin เป็น teratogen; DOAC หลีกเลี่ยงในการตั้งครรภ์/ให้นม (ข้อมูลจำกัด).", "id": "set3-82"}, {"topic": "Hematology", "q": "A patient with a first provoked DVT (after surgery, now resolved) should receive anticoagulation for how long?", "choices": ["6 weeks", "3 months", "Indefinitely", "1 year always", "No treatment"], "ans": 1, "exp": "VTE ที่ provoked จากปัจจัยชั่วคราว (ผ่าตัด) รักษา 3 เดือน. Unprovoked หรือ persistent risk (มะเร็ง/thrombophilia) พิจารณา anticoagulation ต่อเนื่องระยะยาว.", "id": "set3-83"}, {"topic": "Hematology", "q": "A patient with active cancer develops VTE. Which anticoagulant class has strong evidence and is commonly preferred?", "choices": ["Warfarin", "LMWH or a DOAC (edoxaban/apixaban/rivaroxaban)", "Aspirin", "No treatment", "IVC filter alone"], "ans": 1, "exp": "Cancer-associated VTE ใช้ LMWH หรือ DOAC (edoxaban/apixaban/rivaroxaban) ได้ผลดีกว่า warfarin. ระวัง DOAC ใน GI/GU malignancy (เลือดออก) — เลือกตามผู้ป่วย.", "id": "set3-84"}, {"topic": "Hematology", "q": "A patient with recurrent unprovoked thromboses and miscarriages has prolonged aPTT that does not correct with mixing, plus positive anticardiolipin antibodies. What is the diagnosis?", "choices": ["Hemophilia", "Antiphospholipid syndrome", "vWD", "DIC", "Protein C deficiency"], "ans": 1, "exp": "Recurrent thrombosis + pregnancy loss + lupus anticoagulant (aPTT ไม่ correct เมื่อ mix) + anticardiolipin/anti-β2GP1 = antiphospholipid syndrome. รักษาด้วย anticoagulation (warfarin) ระยะยาว.", "id": "set3-85"}, {"topic": "Hematology", "q": "A patient has anemia, jaundice, splenomegaly, and a peripheral smear with sickle-shaped cells during a painful crisis. What is the mainstay of acute management?", "choices": ["Iron supplementation", "Analgesia, hydration, oxygen (and treat precipitant)", "Splenectomy immediately", "Exchange transfusion for all pain", "Chelation"], "ans": 1, "exp": "Sickle cell vaso-occlusive crisis: analgesia (มัก opioid), hydration, oxygen, รักษา infection/precipitant. Hydroxyurea ลดความถี่ crisis; exchange transfusion ในภาวะรุนแรง (stroke, acute chest, priapism).", "id": "set3-86"}, {"topic": "Hematology", "q": "A blood smear shows target cells, and Hb electrophoresis shows increased HbA2 in a mildly microcytic patient. What is the diagnosis?", "choices": ["Iron deficiency", "Beta-thalassemia trait", "Alpha-thalassemia", "Sideroblastic anemia", "Lead poisoning"], "ans": 1, "exp": "Microcytosis เล็กน้อย + target cells + HbA2 สูง (> 3.5%) = beta-thalassemia trait. RBC count มักสูง, ferritin ปกติ. ให้คำปรึกษาพันธุกรรม; ห้ามให้ธาตุเหล็กถ้าไม่ขาดจริง.", "id": "set3-87"}, {"topic": "Hematology", "q": "A patient needs urgent warfarin reversal due to major bleeding. What is appropriate?", "choices": ["Vitamin K only", "Prothrombin complex concentrate (PCC) + IV vitamin K", "FFP alone slowly", "Protamine", "Platelet transfusion"], "ans": 1, "exp": "Major bleeding on warfarin: ให้ 4-factor prothrombin complex concentrate (PCC) + IV vitamin K (FFP ถ้าไม่มี PCC). Protamine ใช้ reverse heparin; idarucizumab reverse dabigatran; andexanet reverse anti-Xa DOAC.", "id": "set3-88"}, {"topic": "Hematology", "q": "A patient has anemia with a low reticulocyte count and normal MCV. What does the low reticulocyte indicate?", "choices": ["Adequate marrow response", "Inadequate marrow production (hypoproliferative)", "Active hemolysis", "Recent bleeding", "Iron overload"], "ans": 1, "exp": "Reticulocyte count ต่ำในภาวะ anemia = marrow ตอบสนองไม่พอ (hypoproliferative: CKD/EPO ต่ำ, ACD, aplastic, marrow infiltration). Reticulocyte สูง = hemolysis/blood loss (marrow ตอบสนองดี).", "id": "set3-89"}, {"topic": "Hematology", "q": "A patient develops warm autoimmune hemolytic anemia. What is the first-line treatment?", "choices": ["Splenectomy", "Corticosteroids", "Rituximab first", "Plasma exchange", "Iron"], "ans": 1, "exp": "Warm AIHA (IgG, spherocytes, direct Coombs positive) รักษา first-line ด้วย corticosteroid; rituximab/splenectomy เป็น second-line. หา secondary cause (lymphoma, SLE, ยา).", "id": "set3-90"}, {"topic": "Hematology", "q": "A patient has cold agglutinin disease with hemolysis worse in cold. Which antibody type mediates this?", "choices": ["IgG (warm)", "IgM (cold)", "IgA", "IgE", "IgD"], "ans": 1, "exp": "Cold agglutinin disease เกิดจาก IgM ที่จับ RBC ในอุณหภูมิเย็น → complement-mediated hemolysis. สัมพันธ์ Mycoplasma/EBV/lymphoma. รักษาหลีกเลี่ยงความเย็น + รักษาสาเหตุ (steroid ได้ผลน้อยกว่า warm).", "id": "set3-91"}, {"topic": "Hematology", "q": "A patient has a normocytic anemia, rouleaux formation, elevated ESR, and back pain. Which malignancy should be suspected?", "choices": ["Leukemia", "Multiple myeloma", "Lymphoma", "Polycythemia vera", "CML"], "ans": 1, "exp": "Rouleaux (จาก M-protein) + ESR สูง + back/bone pain + anemia = multiple myeloma. ตรวจ serum/urine protein electrophoresis + free light chains + skeletal survey/MRI.", "id": "set3-92"}, {"topic": "Hematology", "q": "A patient with splenomegaly and a 'dry tap' on bone marrow aspiration with teardrop cells on smear likely has:", "choices": ["CLL", "Primary myelofibrosis", "ITP", "Iron deficiency", "Aplastic anemia"], "ans": 1, "exp": "Dry tap (marrow fibrosis) + teardrop (dacrocytes) + splenomegaly (extramedullary hematopoiesis) = primary myelofibrosis (JAK2). รักษา JAK inhibitor (ruxolitinib), supportive, transplant ในรายเหมาะสม.", "id": "set3-93"}, {"topic": "Hematology", "q": "A patient develops petechiae and thrombocytopenia after starting a new drug; counts recover after stopping it. What is the mechanism?", "choices": ["Aplastic anemia", "Drug-induced immune thrombocytopenia", "DIC", "TTP", "Splenic sequestration"], "ans": 1, "exp": "Thrombocytopenia ที่ฟื้นหลังหยุดยา = drug-induced immune thrombocytopenia (เช่น quinine, sulfa, vancomycin, heparin). จัดการโดยหยุดยาต้นเหตุ.", "id": "set3-94"}, {"topic": "Hematology", "q": "A patient with iron deficiency anemia is treated with oral iron. When should the reticulocyte count begin to rise if therapy is effective?", "choices": ["Within hours", "Within about 5–7 days", "After 3 months", "It never rises", "Only with IV iron"], "ans": 1, "exp": "หลังเริ่ม iron ที่ได้ผล reticulocyte จะเริ่มขึ้นภายใน ~5–7 วัน และ Hb ค่อยขึ้นในสัปดาห์ถัดไป; ให้ต่อ 3–6 เดือนเพื่อเติม iron store. ถ้าไม่ตอบสนองให้ทบทวนการวินิจฉัย/การดูดซึม/เลือดออกต่อเนื่อง.", "id": "set3-95"}, {"topic": "Hematology", "q": "Which vaccination timing is critical for a patient scheduled for elective splenectomy?", "choices": ["After surgery only", "Encapsulated-organism vaccines (pneumococcal, Hib, meningococcal) ≥ 2 weeks before surgery", "No vaccines needed", "Only influenza", "Only after infection"], "ans": 1, "exp": "ก่อน splenectomy ควรให้วัคซีนต่อ encapsulated organisms (pneumococcus, Hib, meningococcus) อย่างน้อย 2 สัปดาห์ก่อนผ่าตัด เพื่อลดเสี่ยง overwhelming post-splenectomy infection; ให้ prophylactic antibiotic ในบางราย.", "id": "set3-96"}, {"topic": "Hematology", "q": "A patient has a hemoglobin of 6 g/dL with active bleeding and hemodynamic instability. What is the most appropriate transfusion decision?", "choices": ["Withhold transfusion", "Transfuse packed red cells to restore oxygen delivery", "Give platelets only", "Give FFP only", "Give crystalloid only"], "ans": 1, "exp": "Anemia รุนแรงที่มีเลือดออก + hemodynamic instability = ให้ PRC เพื่อเพิ่ม oxygen-carrying capacity (พร้อม resuscitation + หยุดเลือด). เกณฑ์ restrictive (Hb 7) ใช้กับผู้ป่วยคงที่.", "id": "set3-97"}, {"topic": "Hematology", "q": "A patient has isolated prolonged aPTT that fully corrects on a 1:1 mixing study. What does this suggest?", "choices": ["A factor inhibitor", "A factor deficiency (e.g., VIII, IX, XI)", "Lupus anticoagulant", "DIC", "Normal variant"], "ans": 1, "exp": "aPTT ยาวที่ correct เมื่อ mix 1:1 = factor deficiency (เติม factor จาก normal plasma แล้วปกติ). ถ้าไม่ correct = inhibitor (เช่น lupus anticoagulant หรือ factor inhibitor).", "id": "set3-98"}, {"topic": "Hematology", "q": "A patient with beta-thalassemia major on chronic transfusions is at risk of which complication requiring monitoring?", "choices": ["Iron deficiency", "Iron overload (hemosiderosis) requiring chelation", "Vitamin B12 excess", "Hypocoagulability", "Polycythemia"], "ans": 1, "exp": "Thalassemia major ที่รับเลือดเรื้อรังเสี่ยง iron overload (หัวใจ/ตับ/ต่อมไร้ท่อ) — ต้องติดตาม ferritin/MRI T2* และให้ iron chelation (deferasirox/deferoxamine).", "id": "set3-99"}, {"topic": "Hematology", "q": "A patient has anemia and is found to have colon cancer as the bleeding source. Which anemia morphology is most expected?", "choices": ["Macrocytic", "Microcytic hypochromic (iron deficiency)", "Normocytic with high reticulocytes", "Megaloblastic", "Hemolytic"], "ans": 1, "exp": "เลือดออกเรื้อรังจาก colon cancer → chronic blood loss → iron deficiency anemia (microcytic hypochromic). IDA ในผู้ใหญ่ต้องหาสาเหตุ GI เสมอ.", "id": "set3-100"}]}, {"id": "set4", "title": "ชุดที่ 4 — Infectious Disease + Rheumatology", "questions": [{"topic": "Infectious disease", "q": "A patient with suspected sepsis is being managed. According to current bundles, which should be done first alongside cultures?", "choices": ["Delay antibiotics until cultures result", "Obtain blood cultures then give broad-spectrum antibiotics early (within 1 h in shock) + IV fluids", "Give antipyretics only", "Start vasopressors before fluids", "Steroids for all"], "ans": 1, "exp": "Sepsis: เจาะ hemoculture ก่อน แล้วให้ empiric broad-spectrum antibiotic เร็ว (ภายใน 1 ชม.ใน septic shock) + IV crystalloid + วัด lactate + source control. SSC 2026 เน้น balanced crystalloid และประเมิน fluid responsiveness.", "id": "set4-1"}, {"topic": "Infectious disease", "q": "A febrile patient in septic shock remains hypotensive after adequate fluid resuscitation. What is the first-line vasopressor?", "choices": ["Dopamine", "Norepinephrine", "Epinephrine", "Phenylephrine", "Vasopressin alone"], "ans": 1, "exp": "Septic shock ที่ยัง hypotensive หลัง fluid ให้ norepinephrine เป็น first-line vasopressor (เป้า MAP ≥ 65). เพิ่ม vasopressin/epinephrine เป็นตัวที่สอง; SSC 2026 อนุญาตเริ่ม norepinephrine ทาง peripheral ได้.", "id": "set4-2"}, {"topic": "Infectious disease", "q": "A patient with fever, headache, neck stiffness, and photophobia has CSF with high neutrophils, high protein, and low glucose. What is the diagnosis and immediate treatment?", "choices": ["Viral meningitis; supportive", "Bacterial meningitis; ceftriaxone + vancomycin (± ampicillin) with dexamethasone", "TB meningitis; anti-TB", "Fungal; amphotericin", "Migraine; analgesia"], "ans": 1, "exp": "CSF neutrophil สูง + protein สูง + glucose ต่ำ = bacterial meningitis. ให้ empiric ceftriaxone + vancomycin (± ampicillin ถ้าเสี่ยง Listeria) + dexamethasone ก่อน/พร้อม ATB. อย่ารอผลถ้าต้องเลื่อน CT.", "id": "set4-3"}, {"topic": "Infectious disease", "q": "When should a CT head be performed before lumbar puncture in suspected meningitis?", "choices": ["Always", "Focal neurological deficit, papilledema, immunocompromise, seizure, or reduced consciousness", "Never", "Only if febrile", "Only in children"], "ans": 1, "exp": "ทำ CT ก่อน LP เมื่อมี focal deficit, papilledema, immunocompromised, seizure ใหม่, หรือ GCS ลด (เสี่ยง herniation). ในกรณีนี้อย่า delay antibiotic — ให้ ATB + dexamethasone ก่อนแล้วค่อย LP.", "id": "set4-4"}, {"topic": "Infectious disease", "q": "An HIV patient with CD4 count 120 should receive prophylaxis against which opportunistic infection?", "choices": ["Cryptococcus", "Pneumocystis jirovecii (co-trimoxazole)", "MAC", "CMV", "Toxoplasma only"], "ans": 1, "exp": "CD4 < 200 → ให้ co-trimoxazole prophylaxis กัน PCP (และ toxoplasma เมื่อ < 100 + IgG positive). CD4 < 50 พิจารณา MAC prophylaxis (แนวทางปัจจุบันเน้นเริ่ม ART เร็วมากกว่า).", "id": "set4-5"}, {"topic": "Infectious disease", "q": "What is the recommended first-line antiretroviral regimen for most treatment-naive adults with HIV?", "choices": ["Zidovudine-based", "A dolutegravir (integrase inhibitor)-based regimen (e.g., TDF/3TC/DTG)", "Efavirenz + 2 NRTI only", "Protease inhibitor monotherapy", "No treatment until CD4 < 200"], "ans": 1, "exp": "First-line ART = dolutegravir (INSTI)-based เช่น TDF/3TC/DTG; เริ่มเร็ว (rapid start) โดยไม่รอ CD4. แนวคิด U=U. ระวัง DTG กับ antacid/Ca/Fe/Zn (เว้นระยะ).", "id": "set4-6"}, {"topic": "Infectious disease", "q": "A patient with HIV (CD4 50) has headache, fever, and a positive serum cryptococcal antigen with high opening pressure on LP. What is the treatment?", "choices": ["Fluconazole alone", "Amphotericin B + flucytosine induction, then fluconazole; manage raised ICP", "Ceftriaxone", "Acyclovir", "Anti-TB"], "ans": 1, "exp": "Cryptococcal meningitis ใน HIV: induction ด้วย amphotericin B + flucytosine แล้ว consolidation/maintenance fluconazole + จัดการ raised intracranial pressure (serial LP). เริ่ม ART หลังไปสักระยะเพื่อลด IRIS.", "id": "set4-7"}, {"topic": "Infectious disease", "q": "A returning traveler from an endemic area has cyclical fever, chills, and anemia; thick and thin blood films are ordered. What is the purpose of each film?", "choices": ["Thick to detect parasites, thin to speciate/quantify", "Both identical", "Thick for speciation only", "Thin for detection only", "Neither is useful"], "ans": 0, "exp": "Malaria: thick film (sensitive, ตรวจหาเชื้อ) + thin film (speciate + quantify parasitemia). P. falciparum รุนแรง (cerebral, ไตวาย, hypoglycemia) → artesunate IV. (แนวข้อสอบ NLE2)", "id": "set4-8"}, {"topic": "Infectious disease", "q": "A patient has severe P. falciparum malaria with impaired consciousness and high parasitemia. What is the treatment of choice?", "choices": ["Oral chloroquine", "IV artesunate", "Oral doxycycline", "Primaquine alone", "Supportive only"], "ans": 1, "exp": "Severe falciparum malaria รักษาด้วย IV artesunate (ดีกว่า quinine) + supportive; ตามด้วย full oral ACT course. Primaquine ใช้กำจัด hypnozoite ใน vivax/ovale (ตรวจ G6PD ก่อน).", "id": "set4-9"}, {"topic": "Infectious disease", "q": "A rice-farmer presents with fever, severe calf myalgia, conjunctival suffusion, jaundice, and acute kidney injury after wading in floodwater. What is the diagnosis?", "choices": ["Dengue", "Leptospirosis", "Scrub typhus", "Melioidosis", "Malaria"], "ans": 1, "exp": "ประวัติลุยน้ำ/นา + ไข้ + ปวดน่อง + conjunctival suffusion + ตัวเหลือง + ไตวาย (Weil disease) = leptospirosis. รักษาด้วย penicillin/doxycycline/ceftriaxone; ระวัง Jarisch-Herxheimer.", "id": "set4-10"}, {"topic": "Infectious disease", "q": "A febrile patient from a rural area has an eschar (painless ulcer with black crust) and regional lymphadenopathy. What is the diagnosis and treatment?", "choices": ["Dengue; supportive", "Scrub typhus; doxycycline", "Leptospirosis; penicillin", "Malaria; artesunate", "Typhoid; ceftriaxone"], "ans": 1, "exp": "ไข้ + eschar (แผลบุหรี่จี้) + lymphadenopathy = scrub typhus (Orientia tsutsugamushi). ตอบสนองเร็วต่อ doxycycline (azithromycin เป็นทางเลือก). Eschar เป็น clue สำคัญ.", "id": "set4-11"}, {"topic": "Infectious disease", "q": "A diabetic farmer from northeastern Thailand has community-acquired sepsis with multiple abscesses; culture grows a bipolar 'safety pin' gram-negative bacillus. What is the diagnosis?", "choices": ["Melioidosis (Burkholderia pseudomallei)", "Tuberculosis", "Leptospirosis", "Typhoid", "Anthrax"], "ans": 0, "exp": "Melioidosis (Burkholderia pseudomallei, ดิน/น้ำอีสาน, เบาหวานเสี่ยง): sepsis + abscess หลายอวัยวะ, bipolar staining. รักษา intensive ด้วย ceftazidime/meropenem แล้ว eradication ด้วย co-trimoxazole นาน.", "id": "set4-12"}, {"topic": "Infectious disease", "q": "A patient has high fever for 5 days, retro-orbital pain, myalgia, and a positive tourniquet test with low WBC and platelets. During defervescence, what is the key concern?", "choices": ["Secondary bacterial infection", "Plasma leakage/shock and bleeding (critical phase of dengue)", "Recovery is guaranteed", "Hyperglycemia", "Renal stone"], "ans": 1, "exp": "Dengue: ช่วงไข้ลด (defervescence, วันที่ 4–6) เป็น critical phase — เสี่ยง plasma leakage/shock และเลือดออก. เฝ้าระวัง warning signs, ให้ isotonic fluid ระวัง over/under, ห้าม NSAID/ASA.", "id": "set4-13"}, {"topic": "Infectious disease", "q": "Which are recognized dengue warning signs indicating risk of progression to severe disease?", "choices": ["Rash only", "Abdominal pain, persistent vomiting, mucosal bleeding, lethargy, hepatomegaly, rising Hct with falling platelets", "High fever alone", "Headache only", "Myalgia only"], "ans": 1, "exp": "Dengue warning signs (WHO): ปวดท้อง/กดเจ็บ, อาเจียนต่อเนื่อง, มีน้ำรั่ว, เลือดออกเยื่อบุ, ซึม/กระสับกระส่าย, ตับโต > 2 ซม., Hct เพิ่ม + platelet ลดเร็ว → ต้อง admit/เฝ้าใกล้ชิด.", "id": "set4-14"}, {"topic": "Infectious disease", "q": "A patient has sustained high fever, relative bradycardia, abdominal pain, and rose spots after travel; blood culture grows Salmonella Typhi. What is the treatment?", "choices": ["Metronidazole", "Ceftriaxone or azithromycin", "Vancomycin", "Doxycycline", "Penicillin"], "ans": 1, "exp": "Enteric (typhoid) fever: ไข้สูงต่อเนื่อง + relative bradycardia + rose spots; hemoculture ยืนยัน. รักษาด้วย ceftriaxone หรือ azithromycin (ระวัง fluoroquinolone resistance).", "id": "set4-15"}, {"topic": "Infectious disease", "q": "A young adult has fever, severe joint pain in the hands/wrists, maculopapular rash after mosquito exposure; the arthralgia is debilitating and prolonged. What is the most likely diagnosis?", "choices": ["Dengue", "Chikungunya", "Malaria", "Zika", "Typhoid"], "ans": 1, "exp": "ไข้ + ปวดข้อรุนแรง (โดยเฉพาะข้อเล็ก) เด่นและยืดเยื้อ + ผื่น หลังยุงกัด = chikungunya. Dengue ปวดกล้ามเนื้อ/กระบอกตาเด่นกว่า; Zika มักอาการน้อย + ผื่น/เยื่อบุตาแดง. (แนวข้อสอบ NLE2)", "id": "set4-16"}, {"topic": "Infectious disease", "q": "A patient develops a seizure and CT shows multiple small calcified brain lesions without edema; he is from a pork-consuming rural area. What is the etiology?", "choices": ["Toxoplasmosis", "Neurocysticercosis (Taenia solium)", "CNS lymphoma", "TB granuloma", "Metastasis"], "ans": 1, "exp": "Calcified brain lesions หลายจุด + seizure ในพื้นที่ระบาด/กินหมูดิบ = neurocysticercosis (Taenia solium). รักษาตาม stage: albendazole/praziquantel + steroid + antiseizure (ระวังในระยะ active/มี edema). (แนวข้อสอบ NLE2)", "id": "set4-17"}, {"topic": "Infectious disease", "q": "An HIV patient (CD4 80) has ring-enhancing brain lesions and positive Toxoplasma serology. What is the initial treatment?", "choices": ["Acyclovir", "Pyrimethamine + sulfadiazine (+ leucovorin)", "Amphotericin", "Ceftriaxone", "Anti-TB"], "ans": 1, "exp": "Ring-enhancing lesions ใน HIV (CD4 < 100) + Toxoplasma IgG positive → รักษา empiric toxoplasmic encephalitis ด้วย pyrimethamine + sulfadiazine + leucovorin. ถ้าไม่ตอบสนอง คิดถึง CNS lymphoma (biopsy).", "id": "set4-18"}, {"topic": "Infectious disease", "q": "A patient has cellulitis with rapidly spreading erythema, pain out of proportion, bullae, crepitus, and systemic toxicity. What is the diagnosis and treatment?", "choices": ["Simple cellulitis; oral antibiotics", "Necrotizing fasciitis; urgent surgical debridement + broad-spectrum antibiotics (+ clindamycin)", "Erysipelas; penicillin", "Abscess; drainage only", "Contact dermatitis; steroid"], "ans": 1, "exp": "Necrotizing fasciitis: ปวดเกินกว่าที่เห็น + bullae/crepitus + systemic toxicity เป็นภาวะฉุกเฉิน — surgical debridement ด่วน + broad-spectrum antibiotic (คลุม anaerobe/GAS) + clindamycin (ลด toxin). LRINEC score ช่วยประเมิน.", "id": "set4-19"}, {"topic": "Infectious disease", "q": "A patient has a localized skin abscess with fluctuance. What is the primary treatment?", "choices": ["Antibiotics alone", "Incision and drainage (± antibiotics)", "Warm compress only", "Corticosteroid", "Antifungal"], "ans": 1, "exp": "Skin abscess รักษาหลักด้วย incision and drainage; ให้ antibiotic เพิ่มเมื่อมี cellulitis รอบข้าง, systemic sign, immunocompromised, หรือหลายตำแหน่ง (คลุม MRSA ตามความเสี่ยง).", "id": "set4-20"}, {"topic": "Infectious disease", "q": "A patient with fever, new murmur, and Janeway lesions has infective endocarditis. Which empiric consideration is important for IV drug users?", "choices": ["Only viridans strep", "Cover Staphylococcus aureus (right-sided endocarditis common)", "Only enterococci", "No antibiotics", "Only fungal"], "ans": 1, "exp": "IV drug users มัก right-sided endocarditis จาก Staphylococcus aureus (tricuspid, septic pulmonary emboli). Empiric ต้องคลุม S. aureus (รวม MRSA). Viridans strep พบใน native valve subacute; enterococci ใน GI/GU.", "id": "set4-21"}, {"topic": "Infectious disease", "q": "A patient with prolonged fever > 3 weeks and no diagnosis after initial work-up has FUO. Which categories should be systematically considered?", "choices": ["Only malignancy", "Infection, malignancy, autoimmune/connective tissue disease, and miscellaneous", "Only infection", "Only drug fever", "Psychogenic only"], "ans": 1, "exp": "FUO (> 38.3°C, > 3 สัปดาห์, หาไม่พบหลังตรวจเบื้องต้น) — พิจารณา 4 กลุ่ม: infection (TB, abscess, IE), malignancy (lymphoma), autoimmune/CTD (SLE, adult Still, GCA), และ miscellaneous (drug fever, DVT). ประวัติ+ตรวจซ้ำสำคัญ.", "id": "set4-22"}, {"topic": "Infectious disease", "q": "A patient steps on a nail and later develops lockjaw, risus sardonicus, and muscle spasms. What is the diagnosis?", "choices": ["Rabies", "Tetanus", "Botulism", "Meningitis", "Strychnine poisoning"], "ans": 1, "exp": "Puncture wound + trismus (lockjaw) + risus sardonicus + spasm = tetanus (Clostridium tetani, tetanospasmin). รักษา wound care + metronidazole + tetanus immunoglobulin + ควบคุม spasm (benzodiazepine) + vaccine.", "id": "set4-23"}, {"topic": "Infectious disease", "q": "A patient bitten by a stray dog with an unknown vaccination status. What is the appropriate post-exposure management for rabies (category III)?", "choices": ["Wound care only", "Thorough wound washing + rabies vaccine + rabies immunoglobulin", "Antibiotics only", "Observe the patient", "Vaccine only if symptoms appear"], "ans": 1, "exp": "Rabies category III (bite/แผลเลือดออก/เยื่อบุ): ล้างแผลด้วยน้ำสบู่ทันที + rabies vaccine + rabies immunoglobulin (infiltrate รอบแผล) + พิจารณา tetanus/antibiotic. Rabies เมื่อมีอาการแล้วเสียชีวิตเกือบ 100%.", "id": "set4-24"}, {"topic": "Infectious disease", "q": "A young sexually active woman has dysuria, purulent cervical discharge; NAAT is positive for Neisseria gonorrhoeae. What is recommended treatment (also covering common co-infection)?", "choices": ["Penicillin", "Ceftriaxone (+ treat Chlamydia with doxycycline/azithromycin)", "Metronidazole", "Ciprofloxacin alone", "Acyclovir"], "ans": 1, "exp": "Gonorrhea รักษาด้วย ceftriaxone IM + คลุม Chlamydia (doxycycline หรือ azithromycin) เพราะ co-infection บ่อย. รักษาคู่นอน + คัดกรอง STI อื่น (HIV/syphilis).", "id": "set4-25"}, {"topic": "Infectious disease", "q": "A patient has a painless genital ulcer (chancre) with a positive dark-field/serology. What is the treatment for primary syphilis?", "choices": ["Ceftriaxone", "Benzathine penicillin G", "Doxycycline only for all", "Azithromycin routinely", "Metronidazole"], "ans": 1, "exp": "Primary syphilis (painless chancre, Treponema pallidum): รักษาด้วย benzathine penicillin G IM single dose; doxycycline เป็นทางเลือกในผู้แพ้ penicillin (ยกเว้นตั้งครรภ์/neurosyphilis ต้อง desensitize).", "id": "set4-26"}, {"topic": "Infectious disease", "q": "A patient with genital vesicles and painful ulcers on an erythematous base has recurrent episodes; Tzanck smear shows multinucleated giant cells. What is the diagnosis and treatment?", "choices": ["Syphilis; penicillin", "Genital herpes (HSV); acyclovir", "Chancroid; azithromycin", "Granuloma inguinale; doxycycline", "LGV; doxycycline"], "ans": 1, "exp": "Painful grouped vesicles/ulcers + recurrence + multinucleated giant cells = genital herpes (HSV). รักษาด้วย acyclovir/valacyclovir (episodic หรือ suppressive). Syphilis ให้ ulcer ไม่เจ็บ.", "id": "set4-27"}, {"topic": "Infectious disease", "q": "A patient develops watery diarrhea and vomiting after a buffet; symptoms began within hours and resolve within a day. What is the most likely mechanism?", "choices": ["Invasive bacterial infection", "Preformed toxin (e.g., Staphylococcus aureus/Bacillus cereus)", "Viral hepatitis", "Parasitic infection", "C. difficile"], "ans": 1, "exp": "อาการเร็ว (1–6 ชม.) หลังกินอาหาร + อาเจียนเด่น + หายไว = preformed toxin (S. aureus, B. cereus). รักษาแบบ supportive (rehydration); ไม่ต้อง antibiotic.", "id": "set4-28"}, {"topic": "Infectious disease", "q": "A patient develops descending flaccid paralysis, diplopia, dysphagia, and dry mouth after eating home-canned food. What is the diagnosis?", "choices": ["Guillain-Barré", "Botulism", "Myasthenia gravis", "Tetanus", "Stroke"], "ans": 1, "exp": "Descending symmetric flaccid paralysis + bulbar/autonomic (diplopia, dry mouth) หลังอาหารกระป๋อง/หมักเอง = botulism (Clostridium botulinum toxin). รักษาด้วย antitoxin + supportive/ventilation.", "id": "set4-29"}, {"topic": "Infectious disease", "q": "A patient with prosthetic material or endocarditis risk needs antibiotic prophylaxis before which procedure (per current guidelines)?", "choices": ["All dental cleanings for everyone", "High-risk cardiac conditions before dental procedures involving gingival manipulation", "All colonoscopies", "All catheterizations", "Never indicated"], "ans": 1, "exp": "Antibiotic prophylaxis ก่อนหัตถการทันตกรรม (ที่ manipulate gingiva/mucosa) ให้เฉพาะกลุ่มเสี่ยงสูง (prosthetic valve, ประวัติ IE, congenital heart บางชนิด, transplant valvulopathy) เท่านั้น.", "id": "set4-30"}, {"topic": "Infectious disease", "q": "A patient with cough > 2 weeks, weight loss, and night sweats has a positive sputum Xpert MTB/RIF showing rifampicin resistance. What does this indicate?", "choices": ["Drug-susceptible TB", "Rifampicin-resistant TB requiring a second-line/shorter MDR regimen", "Latent TB", "Non-tuberculous mycobacteria", "Contamination"], "ans": 1, "exp": "Xpert MTB/RIF ที่พบ rifampicin resistance บ่งชี้ RR/MDR-TB — ต้องส่ง DST เพิ่มและเริ่มสูตร second-line (เช่น BPaLM 6 เดือน: bedaquiline, pretomanid, linezolid, moxifloxacin) ตามแนวทาง.", "id": "set4-31"}, {"topic": "Infectious disease", "q": "A patient starting anti-TB therapy develops tingling in the feet. Which drug is responsible and how is it prevented?", "choices": ["Rifampicin; steroid", "Isoniazid; give pyridoxine (vitamin B6)", "Ethambutol; give vitamin A", "Pyrazinamide; allopurinol", "Streptomycin; magnesium"], "ans": 1, "exp": "Isoniazid ทำให้ peripheral neuropathy จากการรบกวน pyridoxine metabolism — ป้องกัน/รักษาด้วย pyridoxine (vitamin B6) โดยเฉพาะในกลุ่มเสี่ยง (DM, สุรา, ตั้งครรภ์, CKD, HIV).", "id": "set4-32"}, {"topic": "Infectious disease", "q": "A close contact of an active pulmonary TB case has a positive tuberculin skin test but a normal CXR and no symptoms. What is the management?", "choices": ["Full 4-drug TB treatment", "Treat latent TB infection (e.g., isoniazid, or short-course 3HP)", "No treatment", "Repeat test in 5 years", "Antibiotics for 5 days"], "ans": 1, "exp": "Latent TB infection (positive test, ไม่มีอาการ, CXR ปกติ) — หลังตัด active disease ให้ latent TB treatment (isoniazid 6–9 เดือน หรือ 3HP rifapentine+isoniazid รายสัปดาห์ 3 เดือน) ลดการกลายเป็น active.", "id": "set4-33"}, {"topic": "Infectious disease", "q": "A hospitalized patient develops a central-line-associated bloodstream infection. Besides antibiotics, what is a key management step?", "choices": ["Increase fluid only", "Source control: remove the infected catheter", "Add steroids", "Give antipyretics only", "Continue the line"], "ans": 1, "exp": "CLABSI: source control สำคัญ — remove infected catheter (โดยเฉพาะ S. aureus/Candida/Pseudomonas) + antibiotic ตามเชื้อ. Source control เป็นหลักการสำคัญของการรักษาการติดเชื้อทุกชนิด.", "id": "set4-34"}, {"topic": "Infectious disease", "q": "A young adult has sore throat, posterior cervical lymphadenopathy, splenomegaly, and atypical lymphocytes; a heterophile (Monospot) test is positive. What is the diagnosis?", "choices": ["Streptococcal pharyngitis", "Infectious mononucleosis (EBV)", "Diphtheria", "HIV seroconversion", "CMV only"], "ans": 1, "exp": "Sore throat + posterior cervical nodes + splenomegaly + atypical lymphocytes + Monospot positive = infectious mononucleosis (EBV). หลีกเลี่ยง contact sport (เสี่ยง splenic rupture); เลี่ยง amoxicillin (ผื่น).", "id": "set4-35"}, {"topic": "Infectious disease", "q": "A patient with animal (dog/cat) bite wound needs antibiotic prophylaxis. Which agent covers Pasteurella and oral flora?", "choices": ["Azithromycin", "Amoxicillin-clavulanate", "Ciprofloxacin alone", "Metronidazole alone", "Vancomycin"], "ans": 1, "exp": "Bite wounds (Pasteurella multocida, anaerobe, oral flora) → amoxicillin-clavulanate เป็น first-line prophylaxis/treatment + wound care + ประเมิน tetanus/rabies.", "id": "set4-36"}, {"topic": "Infectious disease", "q": "A patient presents with fever and a petechial/purpuric rash that is rapidly spreading with hypotension. Which diagnosis must be treated immediately?", "choices": ["Viral exanthem", "Meningococcemia (Neisseria meningitidis)", "Dengue only", "Contact dermatitis", "Drug rash"], "ans": 1, "exp": "ไข้ + petechial/purpuric rash แพร่เร็ว + hypotension = meningococcemia (fulminant) — ให้ ceftriaxone ทันที + resuscitation; แจ้ง infection control + prophylaxis ผู้สัมผัสใกล้ชิด.", "id": "set4-37"}, {"topic": "Infectious disease", "q": "A patient with community-acquired pneumonia is found to have Legionella. Which clue and treatment are relevant?", "choices": ["Bradycardia, hyponatremia, diarrhea; treat with a macrolide or fluoroquinolone", "Rusty sputum; penicillin", "Currant-jelly sputum; ceftriaxone", "No specific clue", "Treat with metronidazole"], "ans": 0, "exp": "Legionella: pneumonia + hyponatremia + diarrhea + relative bradycardia + สัมผัสน้ำ/แอร์; ตรวจ urine antigen. รักษาด้วย macrolide (azithromycin) หรือ respiratory fluoroquinolone.", "id": "set4-38"}, {"topic": "Infectious disease", "q": "A pregnant woman is found to have asymptomatic bacteriuria. Why should it be treated?", "choices": ["It is never treated", "To reduce risk of pyelonephritis and preterm birth", "Only to relieve symptoms", "To prevent diabetes", "No clear reason"], "ans": 1, "exp": "Asymptomatic bacteriuria ในหญิงตั้งครรภ์ต้องรักษา (ตามผล culture, ยาที่ปลอดภัย) เพื่อลด pyelonephritis และผลลัพธ์การตั้งครรภ์ไม่ดี (preterm/low birth weight).", "id": "set4-39"}, {"topic": "Infectious disease", "q": "A patient with fever and right upper quadrant pain has a single large liver abscess; aspiration grows Klebsiella pneumoniae. What is appropriate management?", "choices": ["Observation", "Antibiotics + percutaneous drainage", "Metronidazole alone always", "Surgery only", "Antifungal"], "ans": 1, "exp": "Pyogenic liver abscess (มัก Klebsiella/enteric, biliary source) รักษาด้วย antibiotics + percutaneous drainage (โดยเฉพาะ abscess ใหญ่). ต่างจาก amoebic ที่ตอบสนอง metronidazole โดยมัก drainage เมื่อจำเป็น.", "id": "set4-40"}, {"topic": "Infectious disease", "q": "A patient develops an IRIS reaction after starting ART. What is IRIS?", "choices": ["Drug allergy", "Immune reconstitution inflammatory syndrome — worsening of an underlying infection as immunity recovers", "ART failure", "New HIV infection", "Normal response"], "ans": 1, "exp": "IRIS = อาการของการติดเชื้อฉวยโอกาสแย่ลง/ปรากฏชัดหลังเริ่ม ART เพราะภูมิฟื้น (พบใน TB, cryptococcus). จัดการรักษาการติดเชื้อต่อ + ต้าน inflammation (steroid ในบางราย); มัก ไม่หยุด ART.", "id": "set4-41"}, {"topic": "Infectious disease", "q": "A healthcare worker sustains a needlestick from an HIV-positive source. What is the appropriate action?", "choices": ["Observe only", "Start HIV post-exposure prophylaxis (PEP) as soon as possible + baseline testing", "Give vaccine", "Give immunoglobulin only", "No action needed"], "ans": 1, "exp": "Needlestick จากแหล่ง HIV+: เริ่ม PEP (3-drug ART) เร็วที่สุด (ภายในชั่วโมง-72 ชม.) นาน 28 วัน + baseline/follow-up testing (HIV/HBV/HCV) + ประเมิน HBV prophylaxis.", "id": "set4-42"}, {"topic": "Infectious disease", "q": "A patient with severe sepsis of unclear source. Which principle is essential besides antibiotics and fluids?", "choices": ["Delay imaging", "Identify and control the source (drain abscess, remove infected device, relieve obstruction)", "Avoid cultures", "Steroids for all", "Antipyretics only"], "ans": 1, "exp": "Source control (ระบายหนอง, เอาอุปกรณ์ติดเชื้อออก, แก้ obstruction เช่น obstructed biliary/urinary) เป็นหัวใจของการรักษา sepsis ควบคู่ antibiotic + resuscitation; ถ้าไม่ควบคุมแหล่ง ยาจะไม่ได้ผล.", "id": "set4-43"}, {"topic": "Infectious disease", "q": "A patient has recurrent oral thrush and esophageal candidiasis without another cause. What underlying condition should be tested for?", "choices": ["Diabetes only", "HIV infection", "Iron deficiency", "Hypothyroidism", "Vitamin C deficiency"], "ans": 1, "exp": "Esophageal candidiasis / recurrent thrush เป็น AIDS-defining/immunocompromise clue — ควรตรวจ HIV (และประเมิน DM, corticosteroid, ยากดภูมิ). รักษา candidiasis ด้วย fluconazole.", "id": "set4-44"}, {"topic": "Infectious disease", "q": "A patient develops fever and a diffuse erythematous rash with desquamation, hypotension, and multiorgan involvement associated with tampon use. What is the diagnosis?", "choices": ["Anaphylaxis", "Toxic shock syndrome (Staphylococcus aureus)", "Dengue", "Scarlet fever", "Kawasaki disease"], "ans": 1, "exp": "Toxic shock syndrome (S. aureus superantigen TSST-1): ไข้ + diffuse rash + desquamation (ฝ่ามือ/เท้า) + hypotension + multiorgan + สัมพันธ์ tampon/wound. รักษา remove source + fluids + antibiotic (clindamycin ลด toxin + anti-staph).", "id": "set4-45"}, {"topic": "Infectious disease", "q": "A patient from an area with poor sanitation has acute watery 'rice-water' stools with rapid dehydration. What is the priority treatment?", "choices": ["Antibiotics first", "Aggressive fluid/electrolyte replacement (ORS/IV)", "Antimotility agent", "Observation", "Antifungal"], "ans": 1, "exp": "Cholera (rice-water stool, dehydration เร็ว): หัวใจคือ rapid fluid/electrolyte replacement (ORS หรือ IV) ป้องกันช็อก; antibiotic (doxycycline/azithromycin) ลดระยะเวลา/ปริมาณอุจจาระเป็นตัวเสริม.", "id": "set4-46"}, {"topic": "Infectious disease", "q": "A patient with HIV has CD4 30 and painless progressive visual loss; funduscopy shows hemorrhages and exudates ('pizza pie'). What is the diagnosis?", "choices": ["Toxoplasma retinitis", "CMV retinitis", "Cryptococcal", "HSV keratitis", "Diabetic retinopathy"], "ans": 1, "exp": "CD4 < 50 + retinitis (hemorrhage + exudate, pizza-pie) = CMV retinitis. รักษาด้วย ganciclovir/valganciclovir + เริ่ม/optimize ART. ต้องรีบเพื่อรักษาการมองเห็น.", "id": "set4-47"}, {"topic": "Infectious disease", "q": "Which patient should receive influenza antiviral (oseltamivir) treatment even beyond 48 hours ideally as early as possible?", "choices": ["Healthy adult with mild symptoms", "Hospitalized or high-risk patient with influenza", "Anyone with a cold", "Only children", "No one"], "ans": 1, "exp": "Oseltamivir ให้ประโยชน์สูงสุดภายใน 48 ชม. แต่ยังแนะนำในผู้ป่วยที่ admit/รุนแรง/กลุ่มเสี่ยงสูง (ตั้งครรภ์, โรคเรื้อรัง, สูงอายุ) แม้เกิน 48 ชม. Healthy mild case มักไม่จำเป็น.", "id": "set4-48"}, {"topic": "Infectious disease", "q": "A patient with pyelonephritis and an obstructing ureteric stone with pus remains septic despite antibiotics. What is the essential intervention?", "choices": ["Increase antibiotic dose only", "Urgent urinary decompression (stent/nephrostomy) — source control", "More IV fluids only", "Observation", "Antifungal"], "ans": 1, "exp": "Obstructed infected urinary system (pyonephrosis) เป็น urologic emergency — ต้อง decompress ด่วน (ureteric stent หรือ percutaneous nephrostomy) ควบคู่ antibiotic. Antibiotic เดี่ยวไม่พอถ้าไม่ระบายแหล่งติดเชื้อ.", "id": "set4-49"}, {"topic": "Infectious disease", "q": "A patient has a chronic non-healing ulcer with 'sulfur granules' draining from a jaw/neck sinus tract. What is the diagnosis?", "choices": ["Tuberculosis", "Actinomycosis", "Nocardiosis", "Melioidosis", "Sporotrichosis"], "ans": 1, "exp": "Sulfur granules + chronic draining sinus (มัก cervicofacial หลังทำฟัน) = actinomycosis (Actinomyces israelii). รักษาด้วย penicillin ขนาดสูงระยะยาว ± surgical drainage.", "id": "set4-50"}, {"topic": "Infectious disease", "q": "A patient with fever, headache, and altered mental status has CSF lymphocytic pleocytosis with normal glucose; MRI shows temporal lobe involvement. What is the likely diagnosis and treatment?", "choices": ["Bacterial meningitis; ceftriaxone", "Herpes simplex encephalitis; IV acyclovir", "TB meningitis; anti-TB", "Cryptococcal; amphotericin", "Migraine; analgesia"], "ans": 1, "exp": "Encephalitis + temporal lobe involvement + lymphocytic CSF (glucose ปกติ) = HSV encephalitis. เริ่ม IV acyclovir ทันที (อย่ารอผล PCR) เพราะการรักษาเร็วลดการตาย/พิการ.", "id": "set4-51"}, {"topic": "Infectious disease", "q": "A patient traveling develops profuse watery diarrhea without blood or high fever ('traveler's diarrhea'). What is the most common cause and management?", "choices": ["Entamoeba; metronidazole", "Enterotoxigenic E. coli; oral rehydration ± azithromycin/fluoroquinolone if moderate-severe", "C. difficile; vancomycin", "Rotavirus; vaccine", "Cholera; IV only"], "ans": 1, "exp": "Traveler's diarrhea ส่วนใหญ่จาก enterotoxigenic E. coli (ETEC). หลักคือ oral rehydration; antibiotic (azithromycin/fluoroquinolone) เมื่อปานกลาง-รุนแรง; loperamide เสริมได้ถ้าไม่มีเลือด/ไข้สูง.", "id": "set4-52"}, {"topic": "Rheumatology", "q": "A young woman has a malar rash, photosensitivity, oral ulcers, arthritis, and proteinuria. Which antibodies are most specific for the diagnosis?", "choices": ["ANA only", "Anti-dsDNA and anti-Smith", "Rheumatoid factor", "Anti-CCP", "Anti-histone"], "ans": 1, "exp": "อาการหลายระบบ = SLE. ANA sensitive (คัดกรอง) แต่ anti-dsDNA และ anti-Smith จำเพาะสุด. Anti-dsDNA สัมพันธ์ lupus nephritis/activity; complement ต่ำเวลากำเริบ.", "id": "set4-53"}, {"topic": "Rheumatology", "q": "Which medication should essentially all SLE patients receive unless contraindicated?", "choices": ["Cyclophosphamide", "Hydroxychloroquine", "Methotrexate", "Rituximab", "Azathioprine"], "ans": 1, "exp": "Hydroxychloroquine เป็นยาพื้นฐานสำหรับ SLE ทุกราย (ลดกำเริบ, ปกป้องอวัยวะ, ปรับ prognosis). เพิ่ม steroid/immunosuppressant ตามความรุนแรง/nephritis. ต้องตรวจตาเป็นระยะ.", "id": "set4-54"}, {"topic": "Rheumatology", "q": "A patient develops a lupus-like syndrome (arthralgia, serositis) after long-term hydralazine or procainamide; anti-histone antibody is positive. What is the diagnosis?", "choices": ["Systemic lupus erythematosus", "Drug-induced lupus", "Rheumatoid arthritis", "Sjogren syndrome", "Scleroderma"], "ans": 1, "exp": "Drug-induced lupus (hydralazine, procainamide, isoniazid): arthralgia/serositis, anti-histone positive, มัก spares kidney/CNS, หายเมื่อหยุดยา. ต่าง SLE ที่ anti-dsDNA/Smith positive.", "id": "set4-55"}, {"topic": "Rheumatology", "q": "A patient has symmetric small-joint polyarthritis (MCP, PIP, wrists) with > 1 hour of morning stiffness. Which antibody is most specific?", "choices": ["ANA", "Rheumatoid factor", "Anti-CCP", "Anti-dsDNA", "Anti-Ro"], "ans": 2, "exp": "RA: symmetric small-joint arthritis + morning stiffness > 1 ชม. Anti-CCP จำเพาะกว่า RF (RF พบได้ในโรคอื่น). ESR/CRP ประเมิน activity; X-ray = erosion/joint space narrowing.", "id": "set4-56"}, {"topic": "Rheumatology", "q": "What is the first-line disease-modifying agent for rheumatoid arthritis?", "choices": ["NSAIDs", "Methotrexate", "Prednisolone long-term", "Rituximab", "Paracetamol"], "ans": 1, "exp": "RA ควรเริ่ม DMARD เร็ว โดย methotrexate เป็น first-line (± bridging steroid). ถ้าไม่ตอบสนอง เพิ่ม/เปลี่ยนเป็น biologic (anti-TNF) หรือ JAK inhibitor. NSAID/steroid คุมอาการเท่านั้น.", "id": "set4-57"}, {"topic": "Rheumatology", "q": "A patient has acute monoarthritis of the first MTP joint that is red, hot, and exquisitely tender. Synovial fluid shows needle-shaped negatively birefringent crystals. What is the diagnosis?", "choices": ["Pseudogout", "Gout", "Septic arthritis", "Rheumatoid arthritis", "Reactive arthritis"], "ans": 1, "exp": "Podagra (MTP1) + needle-shaped negatively birefringent MSU crystals = gout. รักษาเฉียบพลันด้วย NSAID/colchicine/steroid. ไม่เริ่ม/หยุด urate-lowering ระหว่างกำเริบ.", "id": "set4-58"}, {"topic": "Rheumatology", "q": "What is the goal serum urate when starting urate-lowering therapy (allopurinol) for recurrent gout?", "choices": ["< 8 mg/dL", "< 6 mg/dL", "< 10 mg/dL", "No target", "< 2 mg/dL"], "ans": 1, "exp": "Urate-lowering therapy (allopurinol/febuxostat) เป้า serum urate < 6 mg/dL (< 5 ถ้ามี tophi). เริ่มขนาดต่ำค่อยเพิ่ม + prophylaxis (colchicine/NSAID) ช่วงเริ่มเพื่อกัน flare.", "id": "set4-59"}, {"topic": "Rheumatology", "q": "A patient's synovial fluid shows rhomboid-shaped positively birefringent crystals with chondrocalcinosis on X-ray. What is the diagnosis?", "choices": ["Gout", "Calcium pyrophosphate deposition disease (pseudogout)", "Septic arthritis", "Osteoarthritis", "Reactive arthritis"], "ans": 1, "exp": "Rhomboid, positively birefringent crystals + chondrocalcinosis = CPPD (pseudogout). มักโดนข้อใหญ่ (knee, wrist); สัมพันธ์ hyperparathyroidism, hemochromatosis, hypomagnesemia.", "id": "set4-60"}, {"topic": "Rheumatology", "q": "A patient has an acutely hot, swollen, painful single joint with fever. What is the most important immediate step?", "choices": ["Start allopurinol", "Joint aspiration (arthrocentesis) for Gram stain/culture and start empiric antibiotics", "NSAIDs and discharge", "MRI first", "Physiotherapy"], "ans": 1, "exp": "Acute monoarthritis + ไข้ = ต้องตัด septic arthritis เสมอ — ทำ arthrocentesis (cell count, Gram stain, culture, crystals) ด่วน แล้วเริ่ม empiric antibiotic + joint drainage. Septic arthritis เป็นภาวะฉุกเฉิน (ทำลายข้อ).", "id": "set4-61"}, {"topic": "Rheumatology", "q": "The most common organism causing septic arthritis in adults is:", "choices": ["Neisseria gonorrhoeae", "Staphylococcus aureus", "Streptococcus pneumoniae", "E. coli", "Pseudomonas"], "ans": 1, "exp": "Septic arthritis ในผู้ใหญ่ส่วนใหญ่เกิดจาก Staphylococcus aureus. ในผู้ใหญ่วัยเจริญพันธุ์ที่ active ทางเพศ ให้คิดถึง Neisseria gonorrhoeae (มักหลายข้อ + tenosynovitis + ผื่น).", "id": "set4-62"}, {"topic": "Rheumatology", "q": "An older woman has bilateral knee pain worse with activity, relieved by rest, with bony enlargement (Heberden/Bouchard nodes) and no systemic symptoms. What is the diagnosis?", "choices": ["Rheumatoid arthritis", "Osteoarthritis", "Gout", "SLE", "Septic arthritis"], "ans": 1, "exp": "Osteoarthritis: ปวดข้อเมื่อใช้งาน ดีขึ้นเมื่อพัก, ข้อฝืดเช้าสั้น (< 30 นาที), Heberden (DIP)/Bouchard (PIP) nodes, ไม่มี systemic inflammation. รักษา exercise, ลดน้ำหนัก, paracetamol/NSAID, ข้อเทียมเมื่อรุนแรง.", "id": "set4-63"}, {"topic": "Rheumatology", "q": "A young man has chronic inflammatory low back pain (better with exercise, worse with rest), reduced spinal mobility, and sacroiliitis; HLA-B27 positive. What is the diagnosis?", "choices": ["Mechanical back pain", "Ankylosing spondylitis", "Osteoarthritis", "Disc herniation", "Osteoporosis"], "ans": 1, "exp": "Inflammatory back pain (ดีขึ้นเมื่อขยับ, ตอนเช้าฝืด) + sacroiliitis + HLA-B27 = ankylosing spondylitis (bamboo spine). รักษา NSAID + exercise; anti-TNF/IL-17 ในรายดื้อ.", "id": "set4-64"}, {"topic": "Rheumatology", "q": "A patient develops arthritis, urethritis, and conjunctivitis after a GI/GU infection. What is the diagnosis?", "choices": ["Rheumatoid arthritis", "Reactive arthritis", "Gout", "Psoriatic arthritis", "Septic arthritis"], "ans": 1, "exp": "Reactive arthritis (asymmetric oligoarthritis + urethritis + conjunctivitis) หลังติดเชื้อ GI (Salmonella/Shigella/Campylobacter) หรือ GU (Chlamydia); HLA-B27 สัมพันธ์. รักษา NSAID; รักษาเชื้อต้นเหตุ.", "id": "set4-65"}, {"topic": "Rheumatology", "q": "A patient with psoriasis develops asymmetric arthritis with dactylitis ('sausage digit') and nail pitting. What is the diagnosis?", "choices": ["Rheumatoid arthritis", "Psoriatic arthritis", "Gout", "Osteoarthritis", "Reactive arthritis"], "ans": 1, "exp": "Psoriatic arthritis: arthritis + psoriasis + dactylitis + nail changes (pitting, onycholysis), อาจโดน DIP; X-ray pencil-in-cup. รักษา NSAID, DMARD (methotrexate), biologic (anti-TNF/IL-17).", "id": "set4-66"}, {"topic": "Rheumatology", "q": "A woman has Raynaud phenomenon, skin thickening, dysphagia, and pulmonary involvement; anti-Scl-70 is positive. What is the diagnosis?", "choices": ["SLE", "Systemic sclerosis (scleroderma)", "Rheumatoid arthritis", "Dermatomyositis", "Sjogren syndrome"], "ans": 1, "exp": "Systemic sclerosis: skin thickening + Raynaud + GERD/dysphagia + ILD/PAH. Diffuse (anti-Scl-70) vs limited/CREST (anti-centromere). ระวัง scleroderma renal crisis (รักษา ACEI).", "id": "set4-67"}, {"topic": "Rheumatology", "q": "A scleroderma patient develops malignant hypertension and acute kidney injury (renal crisis). What is the treatment of choice?", "choices": ["Beta-blocker", "ACE inhibitor", "Calcium channel blocker", "Diuretic", "Steroid"], "ans": 1, "exp": "Scleroderma renal crisis (HT รุนแรง + AKI + MAHA) รักษาด้วย ACE inhibitor (captopril) เป็นตัวเลือกหลัก แม้ Cr สูง. หลีกเลี่ยง high-dose steroid ซึ่งกระตุ้น renal crisis.", "id": "set4-68"}, {"topic": "Rheumatology", "q": "A patient has dry eyes and dry mouth (sicca) with positive anti-Ro (SSA)/anti-La (SSB). What is the diagnosis?", "choices": ["SLE", "Sjogren syndrome", "Rheumatoid arthritis", "Scleroderma", "Sarcoidosis"], "ans": 1, "exp": "Sjogren syndrome: keratoconjunctivitis sicca + xerostomia + anti-Ro/La; ยืนยันด้วย Schirmer test/lip biopsy. เสี่ยง lymphoma (MALT). รักษาตามอาการ (น้ำตาเทียม, pilocarpine).", "id": "set4-69"}, {"topic": "Rheumatology", "q": "A patient has proximal muscle weakness, elevated CK, and a heliotrope rash with Gottron papules. What is the diagnosis?", "choices": ["Polymyositis", "Dermatomyositis", "Polymyalgia rheumatica", "Myasthenia gravis", "Fibromyalgia"], "ans": 1, "exp": "Proximal muscle weakness + CK สูง + heliotrope rash + Gottron papules = dermatomyositis. สัมพันธ์ malignancy (ควรคัดกรองมะเร็ง). รักษาด้วย corticosteroid ± immunosuppressant.", "id": "set4-70"}, {"topic": "Rheumatology", "q": "An older patient has new bilateral temporal headache, jaw claudication, scalp tenderness, and a markedly elevated ESR. What is the immediate treatment to prevent blindness?", "choices": ["NSAIDs", "High-dose corticosteroid immediately (before biopsy)", "Methotrexate", "Observation", "Antibiotics"], "ans": 1, "exp": "Giant cell (temporal) arteritis: ปวดขมับ + jaw claudication + ESR สูง เสี่ยงตาบอด (anterior ischemic optic neuropathy) — ให้ high-dose corticosteroid ทันทีโดยไม่รอ temporal artery biopsy. สัมพันธ์ polymyalgia rheumatica.", "id": "set4-71"}, {"topic": "Rheumatology", "q": "An older patient has bilateral shoulder and hip girdle pain and stiffness with a high ESR but normal CK and no true weakness. What is the diagnosis?", "choices": ["Polymyositis", "Polymyalgia rheumatica", "Fibromyalgia", "Rheumatoid arthritis", "Hypothyroid myopathy"], "ans": 1, "exp": "Polymyalgia rheumatica: ปวด/ฝืด shoulder+hip girdle, ESR สูง, CK ปกติ, ไม่มี weakness จริง. ตอบสนองดีต่อ low-dose prednisolone. สัมพันธ์ GCA (เฝ้าระวังอาการตา).", "id": "set4-72"}, {"topic": "Rheumatology", "q": "A young Asian/Middle-Eastern patient has recurrent painful oral and genital ulcers with uveitis. What is the diagnosis?", "choices": ["SLE", "Behcet disease", "Reactive arthritis", "Crohn disease", "Herpes"], "ans": 1, "exp": "Behcet disease: recurrent oral + genital ulcers + uveitis (± skin lesions, pathergy). รักษาตามอวัยวะที่โดน (colchicine, steroid, immunosuppressant/biologic).", "id": "set4-73"}, {"topic": "Rheumatology", "q": "A patient has palpable purpura, abdominal pain, arthralgia, and hematuria after a URI; biopsy shows IgA deposition. What is the diagnosis?", "choices": ["ITP", "IgA vasculitis (Henoch-Schonlein purpura)", "Meningococcemia", "SLE", "Cryoglobulinemia"], "ans": 1, "exp": "IgA vasculitis (HSP, พบในเด็ก): palpable purpura (ขาส่วนล่าง) + abdominal pain + arthritis + IgA nephropathy. มัก self-limited; supportive ± steroid ในรายรุนแรง.", "id": "set4-74"}, {"topic": "Rheumatology", "q": "A patient has asthma, eosinophilia, and vasculitis with mononeuritis multiplex; p-ANCA may be positive. What is the diagnosis?", "choices": ["Granulomatosis with polyangiitis", "Eosinophilic granulomatosis with polyangiitis (Churg-Strauss)", "Polyarteritis nodosa", "Giant cell arteritis", "Takayasu"], "ans": 1, "exp": "Asthma + eosinophilia + vasculitis (mononeuritis multiplex) = eosinophilic granulomatosis with polyangiitis (Churg-Strauss), p-ANCA/MPO. รักษาด้วย corticosteroid ± immunosuppressant.", "id": "set4-75"}, {"topic": "Rheumatology", "q": "A middle-aged man has systemic vasculitis with renal and GI involvement, hypertension, and is hepatitis B associated; ANCA is typically negative and there is no glomerulonephritis with pulmonary hemorrhage. What is the diagnosis?", "choices": ["Granulomatosis with polyangiitis", "Polyarteritis nodosa", "Microscopic polyangiitis", "Giant cell arteritis", "Behcet"], "ans": 1, "exp": "Polyarteritis nodosa (PAN): medium-vessel vasculitis, สัมพันธ์ HBV, โดนไต (renal artery, ไม่ใช่ GN)/GI/ผิวหนัง/เส้นประสาท, ANCA negative, spares ปอด. รักษา steroid ± cyclophosphamide (+ antiviral ถ้า HBV).", "id": "set4-76"}, {"topic": "Rheumatology", "q": "A young Asian woman has arm claudication, unequal pulses/blood pressures, and bruits over large arteries. What is the diagnosis?", "choices": ["Giant cell arteritis", "Takayasu arteritis", "Polyarteritis nodosa", "Buerger disease", "Kawasaki"], "ans": 1, "exp": "Takayasu arteritis ('pulseless disease'): large-vessel vasculitis ในหญิงเอเชียอายุน้อย — ชีพจร/ความดันไม่เท่ากัน, bruit, claudication แขน. รักษาด้วย corticosteroid ± immunosuppressant.", "id": "set4-77"}, {"topic": "Rheumatology", "q": "A patient has widespread chronic musculoskeletal pain, fatigue, poor sleep, and multiple tender points but normal inflammatory markers and imaging. What is the diagnosis?", "choices": ["Polymyalgia rheumatica", "Fibromyalgia", "Rheumatoid arthritis", "SLE", "Hypothyroidism"], "ans": 1, "exp": "Fibromyalgia: ปวดกล้ามเนื้อทั่วตัวเรื้อรัง + เหนื่อยล้า + นอนไม่ดี + tender points โดย inflammatory markers/imaging ปกติ. รักษาด้วยออกกำลัง, ปรับการนอน, ยา (duloxetine, pregabalin, amitriptyline).", "id": "set4-78"}, {"topic": "Rheumatology", "q": "A patient with SLE has recurrent arterial/venous thrombosis and pregnancy losses with positive lupus anticoagulant. What is the diagnosis and long-term treatment?", "choices": ["Deep vein thrombosis; short anticoagulation", "Antiphospholipid syndrome; long-term anticoagulation", "ITP; steroids", "TTP; plasma exchange", "Factor V Leiden; aspirin"], "ans": 1, "exp": "Antiphospholipid syndrome (thrombosis + pregnancy loss + antiphospholipid antibody, อาจ secondary ต่อ SLE) รักษาด้วย long-term anticoagulation (warfarin) หลัง thrombosis; ในตั้งครรภ์ใช้ heparin + aspirin.", "id": "set4-79"}, {"topic": "Rheumatology", "q": "A patient has Raynaud phenomenon alone with no other features; nailfold capillaroscopy is normal and antibodies negative. What is the classification and management?", "choices": ["Secondary Raynaud; treat underlying", "Primary Raynaud phenomenon; conservative measures ± calcium channel blocker", "Systemic sclerosis; immunosuppression", "Buerger disease; stop smoking", "Vasculitis; steroids"], "ans": 1, "exp": "Primary Raynaud (ไม่มีโรคพื้นฐาน, capillaroscopy/serology ปกติ) รักษาด้วยหลีกเลี่ยงความเย็น/บุหรี่ ± dihydropyridine CCB (nifedipine). Secondary (systemic sclerosis, SLE) ต้องหาและรักษาโรคพื้นฐาน.", "id": "set4-80"}, {"topic": "Rheumatology", "q": "A patient with rheumatoid arthritis, splenomegaly, and neutropenia has which syndrome?", "choices": ["Sjogren", "Felty syndrome", "Caplan syndrome", "Still disease", "Sweet syndrome"], "ans": 1, "exp": "Felty syndrome = RA + splenomegaly + neutropenia (เสี่ยงติดเชื้อ). Caplan = RA + pneumoconiosis; adult Still = ไข้สูง + ผื่นสีแซลมอน + arthritis + ferritin สูงมาก.", "id": "set4-81"}, {"topic": "Rheumatology", "q": "A young adult has daily high spiking fevers, an evanescent salmon-colored rash, arthritis, and a very high ferritin with negative RF/ANA. What is the diagnosis?", "choices": ["SLE", "Adult-onset Still disease", "Rheumatoid arthritis", "Reactive arthritis", "Sepsis"], "ans": 1, "exp": "Adult-onset Still disease: quotidian fever + salmon rash + arthritis + leukocytosis + ferritin สูงมาก, RF/ANA negative. เป็น diagnosis of exclusion; รักษาด้วย NSAID/steroid ± IL-1/IL-6 inhibitor.", "id": "set4-82"}, {"topic": "Rheumatology", "q": "A patient on long-term corticosteroids for a rheumatic disease needs prophylaxis against which complication?", "choices": ["Hyperkalemia", "Osteoporosis (calcium/vitamin D ± bisphosphonate) and GI ulcer risk", "Hypoglycemia", "Bradycardia", "Hyperthyroidism"], "ans": 1, "exp": "Long-term steroid เสี่ยง glucocorticoid-induced osteoporosis — ให้ calcium/vitamin D ± bisphosphonate; ระวัง hyperglycemia, HT, infection, PUD (โดยเฉพาะร่วม NSAID), adrenal suppression (ห้ามหยุดกะทันหัน).", "id": "set4-83"}, {"topic": "Rheumatology", "q": "A patient starting methotrexate for RA should also receive which supplement to reduce side effects?", "choices": ["Vitamin D", "Folic acid", "Iron", "Vitamin B12", "Calcium"], "ans": 1, "exp": "Methotrexate ให้ folic acid ร่วมเพื่อลด mucositis/GI/hepatotoxicity/cytopenia. ติดตาม CBC/LFT; หลีกเลี่ยงในตั้งครรภ์ (teratogen) และระวังใน renal impairment.", "id": "set4-84"}, {"topic": "Rheumatology", "q": "Before starting a biologic anti-TNF agent, screening for which latent infection is essential?", "choices": ["HIV only", "Latent tuberculosis (and hepatitis B)", "Malaria", "Dengue", "Syphilis"], "ans": 1, "exp": "ก่อนเริ่ม anti-TNF ต้องคัดกรอง latent TB (TST/IGRA + CXR) และ hepatitis B (เสี่ยง reactivation) เพราะ anti-TNF เพิ่มความเสี่ยงติดเชื้อฉวยโอกาส/reactivation.", "id": "set4-85"}, {"topic": "Rheumatology", "q": "A patient with gout has a flare while on stable allopurinol. What should be done with the allopurinol?", "choices": ["Stop it", "Continue it and treat the flare separately", "Double the dose immediately", "Switch to colchicine only", "Stop urate-lowering forever"], "ans": 1, "exp": "ระหว่าง gout flare ไม่ควรหยุด (หรือเริ่ม) urate-lowering therapy ที่ใช้อยู่เดิม — ให้คงยาไว้และรักษา flare แยก (NSAID/colchicine/steroid) เพราะการเปลี่ยนระดับ urate กระตุ้น flare.", "id": "set4-86"}, {"topic": "Rheumatology", "q": "A patient with lupus nephritis class IV needs induction therapy. Which regimen is appropriate?", "choices": ["Hydroxychloroquine alone", "Corticosteroid plus mycophenolate mofetil or cyclophosphamide", "NSAID", "Methotrexate", "Antibiotics"], "ans": 1, "exp": "Proliferative lupus nephritis (class III/IV) induction ด้วย high-dose corticosteroid + mycophenolate mofetil หรือ cyclophosphamide (± belimumab/voclosporin). ทุกรายให้ hydroxychloroquine + คุมความดัน/proteinuria.", "id": "set4-87"}, {"topic": "Rheumatology", "q": "A patient has osteoarthritis of the knee. What is the recommended first-line management?", "choices": ["Opioids", "Exercise, weight loss, and topical/oral NSAID or paracetamol", "Immediate joint replacement", "Long-term steroids", "Colchicine"], "ans": 1, "exp": "OA เข่า first-line = exercise/strengthening, ลดน้ำหนัก, และ analgesia (topical NSAID, paracetamol/oral NSAID). Intra-articular steroid ช่วงกำเริบ; joint replacement เมื่อรุนแรง/ล้มเหลวจากการรักษาอนุรักษ์.", "id": "set4-88"}, {"topic": "Rheumatology", "q": "A patient with an acute gout flare has CKD and cannot take NSAIDs. What is an appropriate alternative?", "choices": ["High-dose NSAID anyway", "Colchicine (dose-adjusted) or corticosteroid", "Allopurinol to abort the flare", "Aspirin", "Febuxostat to abort"], "ans": 1, "exp": "ใน gout flare ที่มี CKD/ห้าม NSAID ใช้ colchicine (ปรับขนาดตาม renal) หรือ corticosteroid (oral/intra-articular). Urate-lowering (allopurinol/febuxostat) ไม่ใช้ abort flare.", "id": "set4-89"}, {"topic": "Rheumatology", "q": "A patient has a positive ANA at low titer but no symptoms. How should this be interpreted?", "choices": ["Definitely has lupus", "A low-titer ANA can be nonspecific; correlate clinically (many healthy people are positive)", "Start immunosuppression", "Ignore all future symptoms", "Repeat weekly"], "ans": 1, "exp": "ANA titer ต่ำพบได้ในคนปกติและโรคอื่น — ไม่จำเพาะ; ต้องแปลผลร่วมอาการทางคลินิก. ตรวจ specific antibody (anti-dsDNA/Smith) เมื่อสงสัย SLE. ไม่เริ่มรักษาเพียงเพราะ ANA บวก.", "id": "set4-90"}, {"topic": "Rheumatology", "q": "A patient with granulomatosis with polyangiitis (GPA) has upper airway, lung, and kidney disease with c-ANCA. What is induction treatment?", "choices": ["NSAIDs", "Corticosteroid + rituximab or cyclophosphamide", "Antibiotics only", "Colchicine", "Methotrexate alone"], "ans": 1, "exp": "GPA (ANCA-associated vasculitis) รุนแรง (ไต/ปอด) induction ด้วย corticosteroid + rituximab หรือ cyclophosphamide; maintenance ด้วย rituximab/azathioprine. คัดกรอง infection ก่อน immunosuppress.", "id": "set4-91"}, {"topic": "Rheumatology", "q": "A patient with rheumatoid arthritis is at increased risk of which extra-articular/systemic complication?", "choices": ["Reduced cardiovascular risk", "Accelerated atherosclerosis/cardiovascular disease and cervical spine (atlantoaxial) instability", "Hyperthyroidism", "Polycythemia", "Hypercalcemia"], "ans": 1, "exp": "RA เพิ่มความเสี่ยง cardiovascular disease (inflammation เร่ง atherosclerosis) และ atlantoaxial subluxation (ระวังตอน intubation/ผ่าตัด). ควบคุมโรค + ประเมิน CV risk.", "id": "set4-92"}, {"topic": "Rheumatology", "q": "A patient has an acute swollen knee; aspiration shows WBC 80,000 with neutrophil predominance and no crystals. What is the most likely diagnosis?", "choices": ["Osteoarthritis", "Septic arthritis", "Gout", "Reactive arthritis", "Hemarthrosis"], "ans": 1, "exp": "Synovial WBC สูงมาก (> 50,000, มัก > 50–100k) neutrophil เด่น ไม่มี crystal = septic arthritis จนกว่าจะพิสูจน์เป็นอื่น — ต้อง culture + antibiotic + drainage ด่วน. Crystal disease อาจ WBC สูงได้แต่มี crystal.", "id": "set4-93"}, {"topic": "Rheumatology", "q": "A patient with dermatomyositis is diagnosed. What additional evaluation is important, especially in adults?", "choices": ["Bone density only", "Age-appropriate malignancy screening", "Echocardiogram only", "No further work-up", "Thyroid only"], "ans": 1, "exp": "Dermatomyositis (และ polymyositis) ในผู้ใหญ่สัมพันธ์ occult malignancy — ต้องทำ age-appropriate cancer screening (และตามอาการ) เพราะอาจเป็น paraneoplastic.", "id": "set4-94"}, {"topic": "Rheumatology", "q": "A patient develops gout tophi and chronic arthropathy. What long-term strategy prevents joint damage?", "choices": ["NSAIDs only during flares", "Sustained urate-lowering therapy to target (< 5–6 mg/dL) with flare prophylaxis", "Colchicine only", "Dietary change alone", "Surgery for all"], "ans": 1, "exp": "Chronic tophaceous gout ต้องใช้ urate-lowering therapy ต่อเนื่องจนถึงเป้า (< 5–6 mg/dL เพื่อละลาย tophi) + prophylaxis ช่วงเริ่ม + ปรับ lifestyle. การรักษาเฉพาะ flare ไม่ป้องกันความเสียหายข้อ.", "id": "set4-95"}, {"topic": "Rheumatology", "q": "A patient with SLE plans pregnancy. Which drug is safe to continue and which is contraindicated?", "choices": ["Continue methotrexate", "Continue hydroxychloroquine; stop methotrexate/mycophenolate/cyclophosphamide", "Stop all drugs", "Continue mycophenolate", "Start warfarin routinely"], "ans": 1, "exp": "ในตั้งครรภ์ SLE: hydroxychloroquine ปลอดภัยและควรใช้ต่อ (ลด flare); methotrexate/mycophenolate/cyclophosphamide เป็น teratogen ต้องหยุด/เปลี่ยน (azathioprine ใช้ได้). วางแผนช่วงโรคสงบ.", "id": "set4-96"}, {"topic": "Rheumatology", "q": "A patient with reactive arthritis or spondyloarthritis has which associated genetic marker?", "choices": ["HLA-DR4", "HLA-B27", "HLA-DQ2", "HLA-B51", "HLA-DR3"], "ans": 1, "exp": "Spondyloarthritis group (ankylosing spondylitis, reactive, psoriatic, IBD-associated) สัมพันธ์ HLA-B27. (HLA-DR4 → RA; HLA-B51 → Behcet; HLA-DQ2 → celiac).", "id": "set4-97"}, {"topic": "Rheumatology", "q": "A patient presents with acute anterior uveitis (painful red eye, photophobia). Which systemic association should be considered?", "choices": ["Osteoarthritis", "HLA-B27-associated spondyloarthritis (and other systemic diseases)", "Fibromyalgia", "Gout", "Osteoporosis"], "ans": 1, "exp": "Acute anterior uveitis สัมพันธ์ HLA-B27 spondyloarthritis (ankylosing spondylitis, IBD, reactive, psoriatic) รวมถึง sarcoidosis/Behcet. ต้องส่งจักษุแพทย์ด่วน + ประเมินโรคระบบ.", "id": "set4-98"}, {"topic": "Rheumatology", "q": "A patient with long-standing RA develops amyloidosis. Which type and consequence should be considered?", "choices": ["AL amyloid; cardiac", "AA (secondary) amyloid from chronic inflammation; nephrotic-range proteinuria/renal failure", "No amyloid risk", "Beta-2 microglobulin only", "Localized only"], "ans": 1, "exp": "Chronic inflammatory disease (RA, IBD, chronic infection) เสี่ยง AA (secondary) amyloidosis จาก serum amyloid A → มัก renal involvement (proteinuria/nephrotic). ควบคุม inflammation เป็นการป้องกัน.", "id": "set4-99"}, {"topic": "Rheumatology", "q": "A patient with vasculitis affecting the kidneys and lungs (pulmonary-renal syndrome) has p-ANCA/MPO without granulomas. What is the diagnosis?", "choices": ["Granulomatosis with polyangiitis", "Microscopic polyangiitis", "Goodpasture", "Polyarteritis nodosa", "Behcet"], "ans": 1, "exp": "Microscopic polyangiitis: small-vessel vasculitis, pulmonary-renal syndrome (RPGN + alveolar hemorrhage), p-ANCA/MPO positive, ไม่มี granuloma (ต่าง GPA). รักษา steroid + rituximab/cyclophosphamide.", "id": "set4-100"}]}, {"id": "set5", "title": "ชุดที่ 5 — Neurology + Integrated", "questions": [{"topic": "Neurology", "q": "A 26-year-old woman has recurrent unilateral throbbing headaches lasting 12–24 hours with nausea, photophobia, and phonophobia; the neurological exam is normal. What is the most likely diagnosis?", "choices": ["Tension-type headache", "Cluster headache", "Trigeminal neuralgia", "Migraine", "Giant cell arteritis"], "ans": 3, "exp": "ปวดศีรษะข้างเดียว ตุบๆ + คลื่นไส้ + กลัวแสง/เสียง + exam ปกติ = migraine. รักษาเฉียบพลันด้วย NSAID/triptan; ป้องกันด้วย propranolol/topiramate/amitriptyline เมื่อบ่อย. (แนวข้อสอบ NLE2)", "id": "set5-1"}, {"topic": "Neurology", "q": "A patient has the sudden 'worst headache of my life' (thunderclap); CT may be negative early. What is the next step if CT is non-diagnostic?", "choices": ["Discharge", "Lumbar puncture looking for xanthochromia (subarachnoid hemorrhage)", "MRI spine", "Reassurance", "Antibiotics"], "ans": 1, "exp": "Thunderclap headache = สงสัย subarachnoid hemorrhage. ถ้า CT ปกติ (โดยเฉพาะหลัง 6 ชม.) ทำ LP หา xanthochromia/RBC. ยืนยัน aneurysm ด้วย CT/DSA angiography.", "id": "set5-2"}, {"topic": "Neurology", "q": "A patient presents within 2 hours of acute left-sided weakness and facial droop; CT shows no hemorrhage and BP is 170/90. What is the appropriate treatment?", "choices": ["Aspirin only", "IV thrombolysis (alteplase or tenecteplase) if no contraindication", "Immediate anticoagulation", "Observation", "Nifedipine to lower BP rapidly"], "ans": 1, "exp": "Acute ischemic stroke ภายใน 4.5 ชม. + CT ไม่มีเลือดออก + ไม่มีข้อห้าม → IV thrombolysis (alteplase 0.9 หรือ tenecteplase 0.25 mg/kg — class I). ถ้า BP > 185/110 ต้องลดก่อน. พิจารณา thrombectomy ถ้า LVO.", "id": "set5-3"}, {"topic": "Neurology", "q": "A stroke patient with a large-vessel occlusion presents at 8 hours with salvageable tissue on perfusion imaging. What is appropriate?", "choices": ["No further treatment", "Mechanical thrombectomy (extended window up to 24 h)", "Thrombolysis only", "Immediate anticoagulation", "Craniectomy"], "ans": 1, "exp": "AHA/ASA 2026: mechanical thrombectomy ขยายถึง 24 ชม.ในผู้ป่วย LVO ที่ advanced imaging (CTP/MRI) แสดง salvageable tissue (DAWN/DEFUSE-3). เป็นการเปลี่ยนแปลงสำคัญจากเดิม ~6 ชม.", "id": "set5-4"}, {"topic": "Neurology", "q": "A patient with acute ischemic stroke who is NOT eligible for thrombolysis should receive which within 48 hours?", "choices": ["Warfarin", "Aspirin (antiplatelet)", "Heparin infusion", "No treatment", "Thrombolysis anyway"], "ans": 1, "exp": "Stroke ที่ไม่ได้ยาละลายลิ่ม ให้ aspirin ภายใน 24–48 ชม. Early anticoagulation ไม่แนะนำ routine (เสี่ยง hemorrhagic transformation) แม้มี AF (เริ่มภายหลังตามขนาด infarct).", "id": "set5-5"}, {"topic": "Neurology", "q": "A seizing patient has been convulsing for more than 5 minutes. What is the first-line drug?", "choices": ["IV phenytoin", "IV/IM benzodiazepine (lorazepam/diazepam/midazolam)", "IV valproate", "Propofol", "Levetiracetam"], "ans": 1, "exp": "Status epilepticus (ชัก > 5 นาที/ไม่ฟื้นระหว่างชัก): first-line = benzodiazepine (lorazepam IV, midazolam IM). จากนั้น load ด้วย levetiracetam/phenytoin/valproate; หา/แก้สาเหตุ (น้ำตาล, Na, ติดเชื้อ). ดูแล ABC.", "id": "set5-6"}, {"topic": "Neurology", "q": "A patient develops ascending symmetric weakness and areflexia days after a diarrheal illness; CSF shows high protein with normal cells. What is the diagnosis and treatment?", "choices": ["Myasthenia gravis; pyridostigmine", "Guillain-Barre syndrome; IVIG or plasma exchange", "Stroke; thrombolysis", "Botulism; antitoxin", "Multiple sclerosis; steroid"], "ans": 1, "exp": "Ascending symmetric weakness + areflexia + albuminocytologic dissociation หลังติดเชื้อ (Campylobacter) = Guillain-Barre. รักษาด้วย IVIG หรือ plasma exchange; เฝ้าระวังการหายใจ (FVC) + autonomic instability. ไม่ใช้ steroid.", "id": "set5-7"}, {"topic": "Neurology", "q": "A patient has fatigable weakness with ptosis and diplopia worsening through the day; anti-AChR antibodies are positive. What is the diagnosis?", "choices": ["Guillain-Barre", "Myasthenia gravis", "Lambert-Eaton syndrome", "Multiple sclerosis", "Motor neuron disease"], "ans": 1, "exp": "Fatigable weakness (ptosis, diplopia แย่ตอนเย็น/ใช้งาน) + anti-AChR = myasthenia gravis. รักษาด้วย pyridostigmine + immunosuppression; ตรวจ thymoma (CT chest). ระวัง myasthenic crisis (หายใจล้มเหลว).", "id": "set5-8"}, {"topic": "Neurology", "q": "A patient with myasthenia gravis develops respiratory distress and severe weakness (myasthenic crisis). What is the treatment?", "choices": ["Increase pyridostigmine only", "Airway support + IVIG or plasma exchange (and treat precipitant)", "Steroids alone", "Antibiotics only", "Observation"], "ans": 1, "exp": "Myasthenic crisis (หายใจล้มเหลว) ต้อง secure airway/ventilate + IVIG หรือ plasma exchange + รักษา precipitant (ติดเชื้อ/ยา). ระวังยาที่กระตุ้น (aminoglycoside, beta-blocker).", "id": "set5-9"}, {"topic": "Neurology", "q": "A young woman has episodes of optic neuritis and limb weakness separated in time and space; MRI shows white-matter lesions. What is the diagnosis?", "choices": ["Stroke", "Multiple sclerosis", "Guillain-Barre", "Myasthenia gravis", "Migraine"], "ans": 1, "exp": "MS: CNS demyelination หลายตำแหน่ง หลายช่วงเวลา (optic neuritis, weakness, sensory, INO); MRI = periventricular white-matter lesions; CSF oligoclonal bands. รักษา acute relapse ด้วย steroid; disease-modifying therapy ระยะยาว.", "id": "set5-10"}, {"topic": "Neurology", "q": "An elderly patient has a resting tremor, bradykinesia, rigidity, and postural instability. What is the diagnosis?", "choices": ["Essential tremor", "Parkinson disease", "Cerebellar disease", "Huntington disease", "Wilson disease"], "ans": 1, "exp": "Parkinson disease: resting tremor (pill-rolling) + bradykinesia + rigidity (cogwheel) + postural instability, asymmetric onset. รักษาด้วย levodopa/carbidopa, dopamine agonist. Essential tremor เป็น action tremor (ดีขึ้นด้วยแอลกอฮอล์/propranolol).", "id": "set5-11"}, {"topic": "Neurology", "q": "A patient has trigeminal neuralgia with brief electric-shock-like facial pain triggered by touch. What is the first-line medication?", "choices": ["Paracetamol", "Carbamazepine", "Opioids", "Gabapentin only", "Amitriptyline"], "ans": 1, "exp": "Trigeminal neuralgia (paroxysmal electric-shock facial pain ตาม trigeminal) first-line = carbamazepine (หรือ oxcarbazepine). ผ่าตัด microvascular decompression ในรายดื้อยา.", "id": "set5-12"}, {"topic": "Neurology", "q": "A patient with a cluster headache has severe unilateral periorbital pain with ipsilateral lacrimation and rhinorrhea in bouts. What is the acute treatment?", "choices": ["Oral triptan", "High-flow oxygen and/or subcutaneous sumatriptan", "Paracetamol", "Carbamazepine", "Antibiotics"], "ans": 1, "exp": "Cluster headache: ปวดรอบตาข้างเดียวรุนแรง + autonomic (น้ำตา/คัดจมูก) เป็นชุด. รักษาเฉียบพลันด้วย high-flow oxygen 100% และ/หรือ SC sumatriptan; ป้องกันด้วย verapamil.", "id": "set5-13"}, {"topic": "Neurology", "q": "A patient has a peripheral facial (Bell) palsy affecting the forehead. What distinguishes it from a central (stroke) facial palsy?", "choices": ["Central spares the forehead; peripheral involves the forehead", "No difference", "Peripheral spares the forehead", "Both spare the forehead", "Both involve the forehead equally"], "ans": 0, "exp": "Peripheral (LMN, Bell) palsy โดนทั้งใบหน้ารวมหน้าผาก; central (UMN, stroke) spares forehead (เพราะ bilateral cortical innervation ส่วนบน). Bell palsy รักษาด้วย corticosteroid (± antiviral) เร็ว + eye care.", "id": "set5-14"}, {"topic": "Neurology", "q": "A patient with new headache, papilledema, and focal deficit should be evaluated for what before lumbar puncture?", "choices": ["Nothing", "Space-occupying lesion/raised ICP with neuroimaging (CT/MRI)", "Blood glucose only", "ECG", "Chest X-ray"], "ans": 1, "exp": "Headache + papilledema + focal deficit = สงสัย raised ICP/mass — ต้อง neuroimaging (CT/MRI) ก่อน LP เพื่อเลี่ยง herniation. หาสาเหตุ (tumor, abscess, hemorrhage).", "id": "set5-15"}, {"topic": "Neurology", "q": "A patient develops a sudden severe headache with neck stiffness and photophobia but no fever; CT confirms blood in the subarachnoid space. What is the most common underlying cause?", "choices": ["Hypertensive bleed", "Ruptured berry (saccular) aneurysm", "AV malformation only", "Trauma only", "Tumor"], "ans": 1, "exp": "Non-traumatic subarachnoid hemorrhage ส่วนใหญ่จาก ruptured saccular (berry) aneurysm. ต้อง CT/DSA angiography หา aneurysm + secure (coiling/clipping) + ป้องกัน vasospasm (nimodipine).", "id": "set5-16"}, {"topic": "Neurology", "q": "A diabetic patient has burning, tingling, and numbness in a stocking distribution. What is the pattern and a first-line drug?", "choices": ["Radiculopathy; surgery", "Distal symmetric polyneuropathy; pregabalin/gabapentin or duloxetine", "Mononeuritis; steroid", "Myopathy; statin", "Plexopathy; observation"], "ans": 1, "exp": "Diabetic distal symmetric polyneuropathy (stocking-glove) รักษา neuropathic pain ด้วย pregabalin/gabapentin, duloxetine, หรือ TCA. คุมน้ำตาล + ดูแลเท้าเพื่อป้องกันแผล.", "id": "set5-17"}, {"topic": "Neurology", "q": "A patient has an acute ischemic stroke with atrial fibrillation. When is anticoagulation typically started?", "choices": ["Immediately (within hours)", "After a delay based on infarct size (to reduce hemorrhagic transformation)", "Never", "Only warfarin same day", "Only if bleeding"], "ans": 1, "exp": "ใน cardioembolic stroke (AF) การเริ่ม anticoagulation ล่าช้าตามขนาด infarct (เช่น '1-3-6-12 day rule') เพื่อลด hemorrhagic transformation. ระยะเฉียบพลันให้ aspirin ก่อน.", "id": "set5-18"}, {"topic": "Neurology", "q": "A patient has a lacunar stroke presenting as pure motor hemiparesis. Which vessels/mechanism are typically involved?", "choices": ["Large-artery embolism", "Small-vessel (lipohyalinosis) occlusion, often from chronic hypertension", "Venous thrombosis", "Cardioembolism", "Vasculitis"], "ans": 1, "exp": "Lacunar infarcts (pure motor, pure sensory, ataxic hemiparesis) เกิดจาก small-vessel disease (lipohyalinosis) สัมพันธ์ chronic HT/DM. ป้องกันด้วยคุมปัจจัยเสี่ยง + antiplatelet.", "id": "set5-19"}, {"topic": "Neurology", "q": "A comatose patient with pinpoint pupils, slow shallow breathing (RR 6), and evidence of IV drug use should receive which antidote?", "choices": ["Flumazenil", "Naloxone", "Atropine", "Glucose only", "Thiamine only"], "ans": 1, "exp": "Pinpoint pupils + respiratory depression + IVDU = opioid overdose → naloxone (opioid antagonist) + airway/ventilation support. (แนวข้อสอบ NLE2)", "id": "set5-20"}, {"topic": "Neurology", "q": "A patient presents with vertigo, and you need to distinguish peripheral from central causes. Which finding suggests a central (dangerous) cause?", "choices": ["Fatigable horizontal nystagmus", "Direction-changing or vertical nystagmus, and other neurologic signs", "Positive Dix-Hallpike with brief vertigo", "Improves with Epley maneuver", "Tinnitus and hearing loss"], "ans": 1, "exp": "Central vertigo: nystagmus เปลี่ยนทิศ/แนวตั้ง, ไม่ fatigable, มี neuro signs อื่น (dysarthria, ataxia, diplopia), HINTS exam abnormal → นึกถึง posterior stroke. Peripheral (BPPV/vestibular neuritis) มัก fatigable + Epley ช่วย.", "id": "set5-21"}, {"topic": "Neurology", "q": "A patient with a brain abscess (ring-enhancing lesion with edema) and fever. Besides antibiotics, what is often required?", "choices": ["Nothing", "Neurosurgical drainage/aspiration for diagnosis and treatment", "Thrombolysis", "Anticoagulation", "Chemotherapy"], "ans": 1, "exp": "Brain abscess (ring-enhancing + edema + fever + source เช่น หูชั้นกลาง/ฟัน/endocarditis) มักต้อง neurosurgical aspiration + prolonged antibiotics ตามเชื้อ + จัดการ raised ICP.", "id": "set5-22"}, {"topic": "Neurology", "q": "A patient with wrist drop after prolonged pressure on the arm has which nerve palsy?", "choices": ["Median nerve", "Radial nerve", "Ulnar nerve", "Axillary nerve", "Musculocutaneous"], "ans": 1, "exp": "Wrist drop (extensor weakness) จากการกดทับที่ spiral groove (Saturday night palsy) = radial nerve palsy. Median → carpal tunnel; ulnar → claw hand/clumsy grip.", "id": "set5-23"}, {"topic": "Neurology", "q": "A patient with delirium is acutely confused with fluctuating attention. What is the most important first step?", "choices": ["Sedate immediately", "Identify and treat the underlying cause (infection, metabolic, drugs, hypoxia)", "Start antipsychotic long-term", "Physical restraints as first-line", "Discharge"], "ans": 1, "exp": "Delirium (acute, fluctuating attention/consciousness) เป็นภาวะเฉียบพลันจากสาเหตุกาย — หาและแก้สาเหตุ (UTI/pneumonia, electrolyte, ยา, hypoxia, ถอนสุรา). จัดการสิ่งแวดล้อม; ยาเป็นทางเลือกสุดท้ายเมื่อจำเป็น.", "id": "set5-24"}, {"topic": "Neurology", "q": "An alcoholic patient develops confusion, ophthalmoplegia, and ataxia. What is the diagnosis and treatment?", "choices": ["Stroke; thrombolysis", "Wernicke encephalopathy; IV thiamine", "Delirium tremens; benzodiazepine", "Hepatic encephalopathy; lactulose", "Hypoglycemia; glucose only"], "ans": 1, "exp": "Wernicke encephalopathy (confusion + ophthalmoplegia + ataxia) จาก thiamine deficiency — ให้ IV thiamine ทันที (ก่อน glucose). ถ้าไม่รักษาอาจเป็น Korsakoff (memory ถาวร).", "id": "set5-25"}, {"topic": "Misc", "q": "A patient in shock has cold clammy extremities, JVP elevated, and pulmonary edema after an MI. What type of shock is this?", "choices": ["Hypovolemic", "Cardiogenic", "Distributive (septic)", "Obstructive", "Anaphylactic"], "ans": 1, "exp": "หลัง MI + pump failure (JVP สูง, pulmonary edema, cold extremities) = cardiogenic shock. รักษาด้วย inotrope/vasopressor + แก้สาเหตุ (revascularization); mechanical support ในรายรุนแรง.", "id": "set5-26"}, {"topic": "Misc", "q": "A patient with fever and hypotension has warm extremities and a wide pulse pressure with a high cardiac output. What type of shock is this?", "choices": ["Cardiogenic", "Distributive (septic)", "Hypovolemic", "Obstructive", "Neurogenic only"], "ans": 1, "exp": "Distributive (septic) shock: vasodilation → warm extremities, wide pulse pressure, high/normal CO, low SVR. รักษาด้วย fluid + norepinephrine + antibiotics + source control.", "id": "set5-27"}, {"topic": "Misc", "q": "A trauma patient has distended neck veins, hypotension, and muffled heart sounds. What is the diagnosis and treatment?", "choices": ["Tension pneumothorax; needle decompression", "Cardiac tamponade; pericardiocentesis", "Hemorrhagic shock; transfusion", "Septic shock; antibiotics", "Neurogenic shock; vasopressor"], "ans": 1, "exp": "Beck triad (hypotension + distended neck veins + muffled heart sounds) = cardiac tamponade (obstructive shock). รักษาด้วย pericardiocentesis/pericardial window. Tension pneumothorax ก็ทำให้ neck vein distend แต่มี absent breath sound + tracheal deviation.", "id": "set5-28"}, {"topic": "Misc", "q": "A patient develops urticaria, wheeze, and hypotension minutes after a drug. What is the first-line treatment?", "choices": ["IV hydrocortisone", "Intramuscular adrenaline (epinephrine)", "IV antihistamine", "Nebulized salbutamol only", "IV fluids only"], "ans": 1, "exp": "Anaphylaxis รักษาลำดับแรกด้วย IM adrenaline ที่ต้นขาด้านนอกทันที + จัดท่า + O2 + IV fluid; antihistamine/steroid เป็น adjunct. หยุด trigger; สังเกตอาการ biphasic.", "id": "set5-29"}, {"topic": "Misc", "q": "At what age should average-risk adults begin colorectal cancer screening (a commonly tested prevention point)?", "choices": ["40", "45", "50", "55", "60"], "ans": 1, "exp": "USPSTF 2021 แนะนำเริ่มคัดกรอง colorectal cancer อายุ 45 ปีในคนความเสี่ยงปกติ (colonoscopy ทุก 10 ปี หรือ FIT ทุกปี).", "id": "set5-30"}, {"topic": "Misc", "q": "Which cancer screening is recommended for a woman in her 30s (cervical cancer)?", "choices": ["No screening", "Pap smear ± HPV testing at recommended intervals", "Mammogram only", "Colonoscopy", "CA-125"], "ans": 1, "exp": "Cervical cancer screening: Pap smear ± HPV testing ตามช่วงอายุ (มักเริ่ม 25–30, HPV-based เป็นหลักในช่วง 30–65). วัคซีน HPV เป็นการป้องกันปฐมภูมิ.", "id": "set5-31"}, {"topic": "Misc", "q": "A terminally ill patient has severe cancer pain. According to the WHO analgesic ladder and modern practice, how should opioids be used?", "choices": ["Avoid opioids", "Titrate opioids to effect for moderate-severe pain, with laxatives for constipation", "Only paracetamol", "Only when death is imminent", "Fixed low dose regardless of pain"], "ans": 1, "exp": "Cancer pain ปานกลาง-รุนแรง ใช้ opioid titrate ตามอาการ (ไม่มี ceiling สำหรับ pure agonist) + ให้ laxative ป้องกันท้องผูก + จัดการ breakthrough pain. เป้าคือคุณภาพชีวิต ไม่ใช่เร่ง/ชะลอความตาย.", "id": "set5-32"}, {"topic": "Misc", "q": "Which framework is used for delivering bad news to patients?", "choices": ["ABCDE", "SPIKES", "FAST", "SAMPLE", "AMPLE"], "ans": 1, "exp": "SPIKES: Setting, Perception, Invitation, Knowledge, Emotion (empathy), Strategy/Summary — ใช้สื่อสารข่าวร้ายอย่างเป็นระบบและเห็นอกเห็นใจ.", "id": "set5-33"}, {"topic": "Misc", "q": "A patient presents with a pearly, telangiectatic papule on the face that occasionally bleeds. What is the most likely diagnosis?", "choices": ["Squamous cell carcinoma", "Basal cell carcinoma", "Melanoma", "Seborrheic keratosis", "Actinic keratosis"], "ans": 1, "exp": "Pearly papule + telangiectasia + occasional bleeding บนใบหน้า (sun-exposed) = basal cell carcinoma (พบบ่อยสุด, โตช้า, metastasis น้อย). รักษาด้วย excision. (แนวข้อสอบ NLE2)", "id": "set5-34"}, {"topic": "Misc", "q": "A pigmented skin lesion shows Asymmetry, irregular Border, Color variation, Diameter > 6 mm, and Evolution. What should be done?", "choices": ["Reassure", "Excisional biopsy to exclude melanoma", "Cryotherapy blindly", "Topical steroid", "Observe for 1 year"], "ans": 1, "exp": "ABCDE ที่ผิดปกติ = สงสัย melanoma → excisional biopsy (full thickness) เพื่อวินิจฉัยและวัด Breslow thickness (กำหนด prognosis/wide excision margin + SLNB).", "id": "set5-35"}, {"topic": "Misc", "q": "A 20-year-old has a single 'herald patch' followed by a 'Christmas tree' distribution of scaly oval plaques on the trunk. What is the diagnosis?", "choices": ["Tinea corporis", "Secondary syphilis", "Pityriasis rosea", "Psoriasis", "Atopic dermatitis"], "ans": 2, "exp": "Herald patch ตามด้วยผื่นรูปไข่เรียงตาม cleavage lines (Christmas tree) = pityriasis rosea (self-limited). ควรตัด secondary syphilis ออกถ้ามีปัจจัยเสี่ยง (โดนฝ่ามือ/เท้า). (แนวข้อสอบ NLE2)", "id": "set5-36"}, {"topic": "Misc", "q": "A patient develops a target-shaped (iris) lesions and mucosal involvement after a drug or infection. What is the diagnosis?", "choices": ["Urticaria", "Erythema multiforme (± Stevens-Johnson if severe)", "Pityriasis rosea", "Psoriasis", "Eczema"], "ans": 1, "exp": "Target/iris lesions = erythema multiforme (มัก HSV/ยา); ถ้ามี mucosal + skin detachment มากขึ้น → Stevens-Johnson syndrome/TEN (หยุดยาต้นเหตุ + supportive/burn-unit care).", "id": "set5-37"}, {"topic": "Misc", "q": "A patient on a new drug (e.g., allopurinol, sulfa, anticonvulsant) develops fever, rash, and skin sloughing with positive Nikolsky sign. What is the diagnosis and first step?", "choices": ["Cellulitis; antibiotics", "Stevens-Johnson syndrome/TEN; stop the offending drug and supportive care", "Psoriasis; steroid", "Eczema; emollient", "Urticaria; antihistamine"], "ans": 1, "exp": "SJS/TEN (fever + mucocutaneous + epidermal detachment, Nikolsky positive) เป็นภาวะฉุกเฉิน — หยุดยาต้นเหตุทันที + supportive care (fluid, wound, temperature) ใน burn/ICU; ประเมิน SCORTEN.", "id": "set5-38"}, {"topic": "Misc", "q": "Which ECG/electrolyte pattern is seen in hyperkalemia?", "choices": ["U waves and flat T", "Peaked T waves, widened QRS, then sine wave", "Prolonged QT", "Delta wave", "Osborn wave"], "ans": 1, "exp": "Hyperkalemia: peaked T → PR ยาว/P หาย → wide QRS → sine wave → arrest. Hypokalemia: U wave, flat T, ST depression. รักษา hyperK: calcium → insulin/glucose/salbutamol → removal.", "id": "set5-39"}, {"topic": "Misc", "q": "A patient with vomiting and nasogastric suction develops which acid-base disorder?", "choices": ["Metabolic acidosis", "Metabolic alkalosis (hypochloremic, hypokalemic)", "Respiratory acidosis", "Respiratory alkalosis", "No change"], "ans": 1, "exp": "เสีย HCl จากการอาเจียน/NG suction → hypochloremic hypokalemic metabolic alkalosis (chloride-responsive). รักษาด้วย isotonic saline + KCl.", "id": "set5-40"}, {"topic": "Misc", "q": "A patient with a suspected drug overdose is unconscious. Which is part of the initial 'coma cocktail'/approach for reversible causes?", "choices": ["Antibiotics", "Check glucose (give dextrose if low), thiamine, and consider naloxone", "Immediate CT only", "Steroids", "Diuretics"], "ans": 1, "exp": "ผู้ป่วยหมดสติไม่ทราบสาเหตุ: ABC + ตรวจ/แก้ hypoglycemia (dextrose + thiamine), พิจารณา naloxone ถ้าสงสัย opioid, ประเมิน toxidrome + neuroimaging ตามข้อบ่งชี้.", "id": "set5-41"}, {"topic": "Misc", "q": "A patient with a high fever, muscle rigidity, altered mental status, and autonomic instability after starting an antipsychotic has which condition?", "choices": ["Serotonin syndrome", "Neuroleptic malignant syndrome", "Malignant hyperthermia", "Thyroid storm", "Heat stroke"], "ans": 1, "exp": "Neuroleptic malignant syndrome (หลัง antipsychotic/dopamine blocker): hyperthermia + lead-pipe rigidity + altered mental status + autonomic instability + CK สูง. หยุดยา + cooling + supportive ± dantrolene/bromocriptine.", "id": "set5-42"}, {"topic": "Misc", "q": "A patient on an SSRI plus another serotonergic drug develops agitation, hyperreflexia, clonus, and hyperthermia. What is the diagnosis?", "choices": ["Neuroleptic malignant syndrome", "Serotonin syndrome", "Malignant hyperthermia", "Anticholinergic toxicity", "Sepsis"], "ans": 1, "exp": "Serotonin syndrome: agitation + neuromuscular hyperactivity (clonus, hyperreflexia — เด่นที่ขา) + autonomic + hyperthermia, onset เร็วหลังเพิ่ม serotonergic. หยุดยา + supportive ± cyproheptadine. ต่าง NMS ที่ rigidity/bradyreflexia และ onset ช้า.", "id": "set5-43"}, {"topic": "Misc", "q": "A patient with organophosphate poisoning has salivation, lacrimation, urination, defecation, miosis, and bradycardia. What is the antidote?", "choices": ["Naloxone", "Atropine (± pralidoxime)", "Flumazenil", "Physostigmine", "Glucagon"], "ans": 1, "exp": "Organophosphate (cholinergic/SLUDGE + miosis + bronchorrhea/bradycardia) รักษาด้วย atropine (block muscarinic) + pralidoxime (reactivate acetylcholinesterase) + decontamination + airway.", "id": "set5-44"}, {"topic": "Misc", "q": "A previously healthy young adult collapses; ECG shows a shockable rhythm. What is the immediate priority?", "choices": ["IV access first", "High-quality CPR and early defibrillation", "Intubation first", "Give amiodarone first", "Check history first"], "ans": 1, "exp": "Cardiac arrest ด้วย shockable rhythm (VF/pVT): หัวใจของการรักษาคือ high-quality CPR + early defibrillation (ยิ่งเร็วยิ่งรอด) + epinephrine/amiodarone ตาม ACLS; หา reversible causes (H's & T's).", "id": "set5-45"}, {"topic": "Misc", "q": "A patient with chronic anticholinergic overdose is 'hot as a hare, dry as a bone, red as a beet, mad as a hatter, blind as a bat'. Which finding fits?", "choices": ["Miosis and salivation", "Mydriasis, dry skin, urinary retention, delirium, tachycardia", "Bradycardia and sweating", "Pinpoint pupils", "Bronchorrhea"], "ans": 1, "exp": "Anticholinergic toxidrome: mydriasis, dry/flushed skin, hyperthermia, urinary retention, delirium, tachycardia (ตรงข้าม cholinergic). รักษา supportive ± physostigmine ในบางราย.", "id": "set5-46"}, {"topic": "Misc", "q": "A palliative patient near end of life has distressing dyspnea. Which is appropriate for symptom relief?", "choices": ["Withhold all medication", "Low-dose opioids (± anxiolytic) titrated for dyspnea", "Only oxygen regardless", "Aggressive diuresis for all", "Antibiotics for all"], "ans": 1, "exp": "Dyspnea ในผู้ป่วยระยะท้ายบรรเทาด้วย low-dose opioid (titrate) ± anxiolytic + จัดท่า/พัดลม/oxygen ตามอาการ. เป้าหมายคือความสบาย (comfort) ตาม goals of care.", "id": "set5-47"}, {"topic": "Misc", "q": "A patient has a decision-making capacity question. Which four elements are assessed for capacity?", "choices": ["Age, education, wealth, family", "Understanding, appreciation, reasoning, and communicating a choice", "Only understanding", "Only the physician's opinion", "Diagnosis only"], "ans": 1, "exp": "Decision-making capacity ประเมิน 4 องค์ประกอบ: understanding, appreciation, reasoning, และ ability to communicate a choice. Capacity เป็นเรื่องเฉพาะการตัดสินใจและอาจเปลี่ยนตามเวลา.", "id": "set5-48"}, {"topic": "Mixed/Integrated", "q": "A patient with COPD presents drowsy after receiving high-flow oxygen; ABG shows pH 7.25, PaCO2 80, HCO3 34. What is the best intervention?", "choices": ["Increase oxygen further", "Non-invasive ventilation (BiPAP) and controlled oxygen", "Give bicarbonate", "Sedate the patient", "Diuretics"], "ans": 1, "exp": "Acute-on-chronic hypercapnic respiratory failure ใน COPD → NIV (BiPAP) + O2 แบบควบคุม (เป้า SpO2 88–92%). O2 สูงเกินลด hypoxic drive/เพิ่ม V/Q mismatch ทำให้ CO2 คั่ง.", "id": "set5-49"}, {"topic": "Mixed/Integrated", "q": "A patient with diabetes has an A1c of 9%, BP 150/90, and albuminuria. Which single drug addresses both renal protection and could be added for cardiovascular/renal benefit?", "choices": ["Amlodipine", "ACE inhibitor/ARB (and add SGLT2 inhibitor)", "Beta-blocker", "Hydralazine", "Thiazide only"], "ans": 1, "exp": "เบาหวาน + HT + albuminuria: ACEI/ARB เป็นแกน (ลด proteinuria/ชะลอไต + คุมความดัน) และเพิ่ม SGLT2i เพื่อ CV/renal protection. คุม A1c/lipid ร่วม.", "id": "set5-50"}, {"topic": "Mixed/Integrated", "q": "A patient presents with confusion, Na 110, and seizures. What is the most appropriate immediate treatment?", "choices": ["Rapid full correction with normal saline", "Hypertonic (3%) saline with careful, limited correction", "Fluid restriction alone", "Desmopressin", "Dialysis"], "ans": 1, "exp": "Severe symptomatic hyponatremia (seizure) ให้ 3% hypertonic saline อย่างระมัดระวัง (เพิ่ม Na ~4–6 mEq/L เพื่อหยุดชัก, ไม่เกิน 8–10/24 ชม.) กัน osmotic demyelination. หาสาเหตุร่วม.", "id": "set5-51"}, {"topic": "Mixed/Integrated", "q": "A young woman has fatigue, weight gain, cold intolerance, and menorrhagia; TSH is elevated. Which anemia pattern may coexist?", "choices": ["Microcytic from thalassemia", "Macrocytic (or normocytic) anemia associated with hypothyroidism", "Hemolytic", "Sideroblastic", "Aplastic"], "ans": 1, "exp": "Hypothyroidism อาจทำให้เกิด macrocytic/normocytic anemia (และ menorrhagia อาจเพิ่ม IDA). รักษา hypothyroidism ด้วย levothyroxine + ประเมิน iron/B12 ถ้ามี.", "id": "set5-52"}, {"topic": "Mixed/Integrated", "q": "A patient on warfarin for AF presents with an INR of 8 but no bleeding. What is appropriate management?", "choices": ["Continue same dose", "Hold warfarin ± low-dose oral vitamin K; recheck INR", "Give FFP", "Give PCC", "Increase dose"], "ans": 1, "exp": "INR สูงมาก (> 4.5–10) โดยไม่มีเลือดออก: หยุด warfarin ชั่วคราว ± vitamin K ขนาดต่ำ (oral) แล้วตรวจ INR ซ้ำ. PCC/FFP สงวนไว้เมื่อมี major bleeding.", "id": "set5-53"}, {"topic": "Mixed/Integrated", "q": "A patient with cirrhosis has new confusion, asterixis, and constipation. Besides lactulose, what is essential?", "choices": ["Sedation", "Identify and treat precipitants (GI bleed, infection, electrolyte, constipation)", "High protein diet", "Diuretic escalation", "Paracentesis for all"], "ans": 1, "exp": "Hepatic encephalopathy: lactulose + หา/แก้ precipitant (เลือดออก GI, ติดเชื้อ/SBP, electrolyte, ท้องผูก, ยา sedative). rifaximin เสริม; หลีกเลี่ยง sedative.", "id": "set5-54"}, {"topic": "Mixed/Integrated", "q": "A patient with acute chest pain has a normal ECG and a normal high-sensitivity troponin at 0 and 3 hours. What does this suggest?", "choices": ["Definite STEMI", "Low likelihood of acute MI (rule-out); consider other causes", "Immediate PCI", "Pericarditis confirmed", "Aortic dissection confirmed"], "ans": 1, "exp": "ECG ปกติ + hs-troponin ไม่เปลี่ยนแปลงที่ 0/3 ชม. ช่วย rule out acute MI (โอกาสต่ำ). ประเมินสาเหตุอื่นของ chest pain (GERD, MSK, PE, dissection ตามบริบท) + risk stratify.", "id": "set5-55"}, {"topic": "Mixed/Integrated", "q": "A patient with newly diagnosed HIV has a CD4 of 350. When should antiretroviral therapy be started?", "choices": ["When CD4 < 200", "As soon as possible (immediately) regardless of CD4", "Only if symptomatic", "After 6 months", "Never in asymptomatic"], "ans": 1, "exp": "แนวทางปัจจุบันแนะนำเริ่ม ART ทันที (rapid start) ในผู้ติดเชื้อ HIV ทุกรายโดยไม่ขึ้นกับ CD4 เพื่อสุขภาพและลดการแพร่ (U=U).", "id": "set5-56"}, {"topic": "Mixed/Integrated", "q": "A patient with severe community-acquired pneumonia has hyponatremia, diarrhea, and confusion. Which pathogen is suggested?", "choices": ["Streptococcus pneumoniae", "Legionella pneumophila", "Mycoplasma", "Klebsiella", "Staphylococcus"], "ans": 1, "exp": "Pneumonia + hyponatremia + diarrhea + confusion/relative bradycardia = Legionella (urine antigen). รักษาด้วย macrolide/respiratory fluoroquinolone.", "id": "set5-57"}, {"topic": "Mixed/Integrated", "q": "A diabetic patient has foot ulcer with surrounding cellulitis and probing to bone. What complication should be evaluated?", "choices": ["Gout", "Osteomyelitis (X-ray/MRI, bone culture)", "DVT", "Cellulitis only", "Charcot only"], "ans": 1, "exp": "Diabetic foot ulcer ที่ probe-to-bone positive/ไม่หาย → สงสัย osteomyelitis (MRI ไวสุด; bone biopsy/culture นำการรักษา) + revascularization ถ้ามี PAD + prolonged antibiotics ± debridement.", "id": "set5-58"}, {"topic": "Mixed/Integrated", "q": "A patient with atrial fibrillation and mechanical heart valve requires anticoagulation. Which is appropriate?", "choices": ["Apixaban", "Warfarin (DOACs contraindicated with mechanical valves)", "Aspirin only", "Dabigatran", "No anticoagulation"], "ans": 1, "exp": "Mechanical heart valve ต้องใช้ warfarin เท่านั้น; DOAC เป็นข้อห้าม (RE-ALIGN trial แสดง dabigatran แย่กว่า). เป้า INR ตามชนิด/ตำแหน่งลิ้น.", "id": "set5-59"}, {"topic": "Mixed/Integrated", "q": "A patient presents with painless jaundice, weight loss, and a dilated bile duct with a pancreatic head mass. What is the next step?", "choices": ["Reassurance", "Staging CT and tissue diagnosis (EUS-guided biopsy) for pancreatic cancer", "Antibiotics", "ERCP for stones only", "Observation"], "ans": 1, "exp": "Painless obstructive jaundice + pancreatic head mass = สงสัย pancreatic adenocarcinoma → contrast CT (staging/resectability) + tissue diagnosis (EUS-FNA); Whipple ถ้า resectable. Courvoisier sign สนับสนุน malignancy.", "id": "set5-60"}, {"topic": "Mixed/Integrated", "q": "A patient with heart failure on furosemide develops muscle weakness and ECG U waves. What is the electrolyte problem and risk?", "choices": ["Hyperkalemia", "Hypokalemia (arrhythmia risk, worsens with digoxin)", "Hypernatremia", "Hypercalcemia", "Hypomagnesemia only"], "ans": 1, "exp": "Loop diuretic ทำให้ hypokalemia (U wave, weakness) เพิ่มเสี่ยง arrhythmia และ digoxin toxicity. แก้ K + Mg; พิจารณา K-sparing (MRA) ที่เป็นเสาหลักใน HFrEF อยู่แล้ว.", "id": "set5-61"}, {"topic": "Mixed/Integrated", "q": "A patient with chronic kidney disease has fatigue and pallor; Hb 8.5, iron studies adequate. What is appropriate treatment?", "choices": ["Blood transfusion for all", "Erythropoiesis-stimulating agent after ensuring iron stores (target Hb ~10–11.5)", "High-dose iron IV only", "Vitamin B12", "Observation"], "ans": 1, "exp": "Anemia of CKD (EPO ต่ำ) รักษาด้วย ESA เมื่อ iron เพียงพอ, เป้า Hb ~10–11.5 (ไม่สูงเกิน — เสี่ยง CV/stroke). Transfusion เฉพาะเมื่อจำเป็น.", "id": "set5-62"}, {"topic": "Mixed/Integrated", "q": "A patient with rheumatoid arthritis on methotrexate develops a dry cough and dyspnea with new infiltrates. What must be considered?", "choices": ["Simple bronchitis", "Methotrexate pneumonitis or opportunistic infection", "Asthma", "GERD", "Anxiety"], "ans": 1, "exp": "Methotrexate อาจทำให้เกิด pneumonitis (hypersensitivity) และเพิ่มเสี่ยงการติดเชื้อ (รวม PCP/atypical) — ผู้ป่วย immunosuppressed ที่มีอาการทางเดินหายใจต้องประเมินทั้งสอง (หยุดยา, imaging, work-up).", "id": "set5-63"}, {"topic": "Mixed/Integrated", "q": "A patient presents with acute severe hypertension, headache, and pulmonary edema. Which is a hypertensive emergency requiring IV therapy?", "choices": ["Asymptomatic BP 160/100", "BP with acute target-organ damage (encephalopathy, ACS, pulmonary edema, dissection)", "White coat hypertension", "Isolated systolic HT with no symptoms", "Masked HT"], "ans": 1, "exp": "Hypertensive emergency = BP สูง + acute target-organ damage → IV antihypertensive แบบควบคุม. Asymptomatic BP สูง (urgency) ใช้ยากินและติดตาม ไม่ต้องลดเร็ว.", "id": "set5-64"}, {"topic": "Mixed/Integrated", "q": "A patient with type 2 diabetes and a recent MI needs a glucose-lowering agent with cardiovascular benefit. Which is appropriate?", "choices": ["Sulfonylurea", "GLP-1 receptor agonist or SGLT2 inhibitor with proven CV benefit", "Basal insulin only", "Thiazolidinedione", "Acarbose"], "ans": 1, "exp": "T2DM + ASCVD/หลัง MI: เลือก GLP-1 RA หรือ SGLT2i ที่มีหลักฐานลด CV events โดยไม่ขึ้นกับ A1c. หลีกเลี่ยง TZD (HF), ระวัง hypoglycemia จาก sulfonylurea/insulin.", "id": "set5-65"}, {"topic": "Mixed/Integrated", "q": "A patient with fever and a heart murmur has multiple septic emboli and blood cultures positive for Staph aureus. What is the diagnosis and key imaging?", "choices": ["Rheumatic fever; ASO", "Infective endocarditis; echocardiography (TTE/TEE)", "Myocarditis; MRI", "Pericarditis; ECG", "PE; CTPA"], "ans": 1, "exp": "IE (ไข้ + murmur + emboli + positive blood culture) — ทำ echocardiography หา vegetation (TEE ไวกว่า TTE) + ให้ IV antibiotics ตามเชื้อ 4–6 สัปดาห์; ผ่าตัดตามข้อบ่งชี้ (HF, abscess, large vegetation, resistant infection).", "id": "set5-66"}, {"topic": "Mixed/Integrated", "q": "A patient with cirrhosis develops rapidly worsening renal function with a bland urinalysis and no response to volume expansion. What is the diagnosis?", "choices": ["Acute tubular necrosis", "Hepatorenal syndrome", "Glomerulonephritis", "Prerenal from dehydration", "Obstruction"], "ans": 1, "exp": "AKI ใน cirrhosis ที่ bland urine + ไม่ตอบสนอง albumin/volume + ตัดสาเหตุอื่น = hepatorenal syndrome. รักษาด้วย terlipressin/noradrenaline + albumin; liver transplant เป็น definitive.", "id": "set5-67"}, {"topic": "Mixed/Integrated", "q": "A patient with sepsis has lactate 5 mmol/L. What does an elevated lactate indicate and guide?", "choices": ["Normal finding", "Tissue hypoperfusion; guides resuscitation and reflects severity", "Liver failure only", "Renal failure only", "Ignore it"], "ans": 1, "exp": "Lactate สูงใน sepsis สะท้อน tissue hypoperfusion/ความรุนแรง ใช้เป็นเป้า resuscitation (lactate clearance). ให้ fluid + norepinephrine + antibiotics + source control และติดตาม lactate ซ้ำ.", "id": "set5-68"}, {"topic": "Mixed/Integrated", "q": "A patient with a swollen, painful calf after a long flight has a positive D-dimer and compression ultrasound confirms DVT. What is the treatment?", "choices": ["Aspirin", "Anticoagulation (DOAC first-line)", "IVC filter for all", "Thrombolysis for all", "Observation"], "ans": 1, "exp": "DVT รักษาด้วย anticoagulation (DOAC เป็น first-line ในรายไม่มีข้อห้าม); LMHW ในมะเร็ง/ตั้งครรภ์. IVC filter เฉพาะเมื่อมีข้อห้ามต่อ anticoagulation.", "id": "set5-69"}, {"topic": "Mixed/Integrated", "q": "A patient with an anaphylactic reaction has been given IM adrenaline but remains hypotensive. What is the next step?", "choices": ["Only observe", "Repeat IM adrenaline every 5–15 min and give IV fluids (± adrenaline infusion)", "Give oral antihistamine", "Discharge", "Give beta-blocker"], "ans": 1, "exp": "Anaphylaxis ที่ยัง hypotensive: ให้ IM adrenaline ซ้ำทุก 5–15 นาที + IV fluid bolus + พิจารณา adrenaline infusion; airway/O2. Adjunct: antihistamine, steroid. สังเกต biphasic reaction.", "id": "set5-70"}, {"topic": "Mixed/Integrated", "q": "A patient with type 1 diabetes presents with DKA. During treatment, potassium is 3.2 mEq/L. What should be done before continuing insulin?", "choices": ["Give more insulin", "Replace potassium first (hold insulin until K ≥ 3.3)", "Give bicarbonate", "Stop fluids", "Give calcium"], "ans": 1, "exp": "ใน DKA ถ้า K < 3.3 ต้องเติม K ก่อน/ระหว่างก่อนให้ insulin เต็มที่ เพราะ insulin จะดัน K เข้าเซลล์ทำให้ hypokalemia รุนแรง (arrhythmia). ให้ fluid + monitor K ทุก 2–4 ชม.", "id": "set5-71"}, {"topic": "Mixed/Integrated", "q": "A patient develops sudden monocular vision loss ('curtain coming down') that resolves in minutes. What is this and what does it warrant?", "choices": ["Migraine aura", "Amaurosis fugax (transient retinal ischemia) — evaluate carotid and stroke risk", "Retinal detachment", "Optic neuritis", "Cataract"], "ans": 1, "exp": "Amaurosis fugax (transient monocular blindness) = retinal TIA — ประเมิน carotid stenosis + stroke risk factors + antiplatelet/statin; carotid endarterectomy ถ้า stenosis รุนแรงมีอาการ.", "id": "set5-72"}, {"topic": "Mixed/Integrated", "q": "A patient with fever, productive cough, and consolidation has CURB-65 of 3. What is the appropriate disposition?", "choices": ["Discharge with oral antibiotics", "Hospital admission (consider ICU) with IV antibiotics", "No treatment", "Outpatient follow-up in 1 week", "Antivirals only"], "ans": 1, "exp": "CURB-65 = 3 บ่งชี้ pneumonia รุนแรง → admit (พิจารณา ICU) + IV antibiotic (β-lactam + macrolide หรือ respiratory FQ). CURB-65 0–1 มัก OPD.", "id": "set5-73"}, {"topic": "Mixed/Integrated", "q": "A patient on ACE inhibitor develops a persistent dry cough. What is the appropriate change?", "choices": ["Stop all antihypertensives", "Switch to an ARB", "Add a beta-blocker", "Increase the ACE inhibitor", "Add an antitussive long-term"], "ans": 1, "exp": "ACE inhibitor cough (จาก bradykinin) → เปลี่ยนเป็น ARB (ไม่ทำให้ไอ) โดยยังคงประโยชน์ต่อไต/หัวใจ. ระวัง angioedema (ต้องหยุดและไม่ใช้ ACEI อีก).", "id": "set5-74"}, {"topic": "Mixed/Integrated", "q": "A patient with a first unprovoked seizure has a normal exam, normal labs, and normal imaging/EEG. What is the general approach?", "choices": ["Start lifelong antiseizure drug immediately for all", "Counsel on recurrence risk; decision to start therapy individualized (often after a second seizure)", "No follow-up", "Immediate surgery", "Sedation"], "ans": 1, "exp": "First unprovoked seizure: ประเมินหาสาเหตุ (imaging, EEG, labs). การเริ่มยาขึ้นกับความเสี่ยงกลับเป็นซ้ำ (EEG/MRI abnormal เพิ่มเสี่ยง) — มักเริ่มหลัง seizure ที่สอง หรือรายที่เสี่ยงสูง; ให้คำแนะนำเรื่องขับรถ/ความปลอดภัย.", "id": "set5-75"}, {"topic": "Mixed/Integrated", "q": "A patient with hypertension, hypokalemia, and metabolic alkalosis has an elevated aldosterone and suppressed renin. What is the diagnosis?", "choices": ["Pheochromocytoma", "Primary aldosteronism", "Cushing syndrome", "Renal artery stenosis", "Bartter syndrome"], "ans": 1, "exp": "HT + hypokalemia + metabolic alkalosis + aldosterone สูง/renin ต่ำ = primary aldosteronism. ยืนยัน confirmatory + adrenal imaging/AVS; รักษา MRA หรือผ่าตัด (unilateral adenoma).", "id": "set5-76"}, {"topic": "Mixed/Integrated", "q": "A patient develops acute flank pain, hematuria, and imaging shows a 4 mm ureteric stone without obstruction/infection. What is appropriate management?", "choices": ["Immediate surgery", "Analgesia, hydration, and medical expulsive therapy (alpha-blocker) with follow-up", "Antibiotics for all", "Dialysis", "Chemotherapy"], "ans": 1, "exp": "นิ่วท่อไตขนาดเล็ก (< 5–10 mm) ไม่มี obstruction/ติดเชื้อ: analgesia (NSAID), hydration, medical expulsive therapy (tamsulosin) รอนิ่วหลุด + ติดตาม. Intervention ถ้านิ่วใหญ่/อุดตัน/ติดเชื้อ/ปวดคุมไม่ได้.", "id": "set5-77"}, {"topic": "Mixed/Integrated", "q": "A patient with a suspected pulmonary embolism is hemodynamically stable with a high pretest probability. What is the best test?", "choices": ["D-dimer", "CT pulmonary angiography", "Chest X-ray", "Echocardiography", "Sputum culture"], "ans": 1, "exp": "High pretest probability PE → CT pulmonary angiography (gold standard) โดยไม่ต้องรอ D-dimer. D-dimer มีประโยชน์เฉพาะ low/intermediate probability เพื่อ rule out.", "id": "set5-78"}, {"topic": "Mixed/Integrated", "q": "A patient with fever, jaundice, RUQ pain, hypotension, and confusion (Reynolds pentad) needs which urgent intervention?", "choices": ["Cholecystectomy first", "Biliary decompression (ERCP) + antibiotics + resuscitation", "Observation", "Whipple", "Paracentesis"], "ans": 1, "exp": "Reynolds pentad (Charcot triad + hypotension + confusion) = suppurative ascending cholangitis รุนแรง → resuscitate + IV antibiotics + urgent biliary decompression (ERCP). Source control สำคัญ.", "id": "set5-79"}, {"topic": "Mixed/Integrated", "q": "A patient with hyperthyroidism and new AF should receive which for rate control (and consideration for stroke prevention)?", "choices": ["Digoxin only", "Beta-blocker for rate/symptom control (and assess anticoagulation by risk)", "Amiodarone first-line", "Adenosine", "No treatment"], "ans": 1, "exp": "Hyperthyroid + AF: beta-blocker คุม rate/อาการ + รักษา hyperthyroid (ATD). ประเมิน anticoagulation ตาม CHA2DS2-VASc. AF มักกลับเป็น sinus เมื่อ euthyroid.", "id": "set5-80"}, {"topic": "Mixed/Integrated", "q": "A patient with severe anemia (Hb 5) from chronic GI bleeding is hemodynamically stable. What is the appropriate transfusion approach?", "choices": ["Withhold transfusion", "Transfuse to a restrictive target (~7) and investigate/treat the source", "Transfuse to Hb 12", "Give platelets", "Only iron"], "ans": 1, "exp": "Chronic GI bleeding + anemia รุนแรง: ให้ PRC ตาม restrictive target (~7, หรือ 8 ในโรคหัวใจ) + iron + endoscopic investigation/treatment ของแหล่งเลือดออก (colonoscopy/EGD).", "id": "set5-81"}, {"topic": "Mixed/Integrated", "q": "A patient with newly diagnosed hypertension is young (<40) with resistant BP and an abdominal bruit. What secondary cause should be evaluated?", "choices": ["Primary aldosteronism only", "Renal artery stenosis (fibromuscular dysplasia in young women)", "Cushing only", "Pheochromocytoma only", "White coat HT"], "ans": 1, "exp": "HT อายุน้อย + resistant + abdominal bruit → renal artery stenosis (young women: fibromuscular dysplasia; older: atherosclerotic). ประเมินด้วย duplex/CTA/MRA; ระวัง Cr เพิ่มหลัง ACEI.", "id": "set5-82"}, {"topic": "Mixed/Integrated", "q": "A patient with community-acquired pneumonia fails to improve after 3 days of appropriate antibiotics and develops a loculated effusion with low pH. What is needed?", "choices": ["Continue same antibiotics only", "Chest tube drainage of the empyema/complicated effusion", "Observation", "Diuretics", "Steroids"], "ans": 1, "exp": "Complicated parapneumonic effusion/empyema (pH < 7.2, loculated, หนอง) ที่ไม่ตอบสนอง antibiotic ต้อง chest tube drainage (± intrapleural fibrinolytic/VATS). Source control สำคัญ.", "id": "set5-83"}, {"topic": "Mixed/Integrated", "q": "A patient with fatigue and pallor has a macrocytic anemia; further testing shows low B12 and anti-intrinsic factor antibodies. What is the diagnosis?", "choices": ["Folate deficiency", "Pernicious anemia (autoimmune B12 deficiency)", "Iron deficiency", "Thalassemia", "Hemolysis"], "ans": 1, "exp": "Macrocytic anemia + B12 ต่ำ + anti-intrinsic factor/parietal cell antibody = pernicious anemia (autoimmune gastritis). รักษาด้วย B12 (IM/oral high-dose); สัมพันธ์ autoimmune อื่นและ gastric cancer risk.", "id": "set5-84"}, {"topic": "Mixed/Integrated", "q": "A patient develops acute pancreatitis with a calcium of 6.5 mg/dL and tetany. What does hypocalcemia here indicate?", "choices": ["Mild disease", "A marker of severity (fat saponification)", "Hyperparathyroidism", "Normal", "Vitamin D excess"], "ans": 1, "exp": "Hypocalcemia ใน acute pancreatitis (จาก fat saponification/calcium sequestration) เป็นตัวบ่งชี้ความรุนแรง (Ranson criterion). แก้ symptomatic hypocalcemia + จัดการ pancreatitis.", "id": "set5-85"}, {"topic": "Mixed/Integrated", "q": "A patient with a chronic cough, weight loss, and hemoptysis has a lung mass; biopsy shows small cell carcinoma with SIADH. What is the paraneoplastic electrolyte finding?", "choices": ["Hypercalcemia", "Hyponatremia", "Hyperkalemia", "Hypernatremia", "Hypophosphatemia"], "ans": 1, "exp": "Small cell lung cancer หลั่ง ADH ectopic → SIADH → euvolemic hyponatremia. (Squamous cell → hypercalcemia จาก PTHrP). รักษา SIADH ด้วยจำกัดน้ำ + รักษามะเร็ง.", "id": "set5-86"}, {"topic": "Mixed/Integrated", "q": "A patient with acute kidney injury has hyperkalemia with ECG changes and pulmonary edema unresponsive to medical therapy. What is indicated?", "choices": ["More diuretics only", "Urgent hemodialysis", "More fluids", "Observation", "Steroids"], "ans": 1, "exp": "AKI ที่มี refractory hyperkalemia + pulmonary edema (overload) ที่ไม่ตอบสนองยา = ข้อบ่งชี้ urgent dialysis (AEIOU). ให้ calcium/insulin-glucose ระหว่างเตรียม dialysis.", "id": "set5-87"}, {"topic": "Mixed/Integrated", "q": "A patient with fever and neck stiffness has a petechial rash and rapid deterioration. What empiric treatment should not be delayed?", "choices": ["Antivirals", "Ceftriaxone (cover meningococcus) immediately, with dexamethasone", "Antifungals", "Observation", "Antihistamine"], "ans": 1, "exp": "Meningococcal meningitis/septicemia (fever + neck stiffness + petechiae) — ให้ ceftriaxone ทันที (± dexamethasone) โดยไม่รอผล LP ถ้าจะ delay; แจ้ง prophylaxis ผู้สัมผัส.", "id": "set5-88"}, {"topic": "Mixed/Integrated", "q": "A patient develops warfarin-associated major GI bleeding with INR 6. What is the appropriate reversal?", "choices": ["Oral vitamin K only", "4-factor prothrombin complex concentrate + IV vitamin K", "Protamine", "FFP slowly only", "Platelets"], "ans": 1, "exp": "Major bleeding on warfarin: 4-factor PCC (rapid reversal) + IV vitamin K (sustained). FFP ถ้าไม่มี PCC. Protamine ใช้กับ heparin; DOAC มี specific reversal (idarucizumab/andexanet).", "id": "set5-89"}, {"topic": "Mixed/Integrated", "q": "A patient with chronic alcohol use is admitted and develops tremor, agitation, hallucinations, and autonomic instability 2–3 days after stopping. What is the diagnosis and treatment?", "choices": ["Wernicke; thiamine only", "Alcohol withdrawal/delirium tremens; benzodiazepines + thiamine + supportive", "Sepsis; antibiotics", "Hepatic encephalopathy; lactulose", "Serotonin syndrome; cyproheptadine"], "ans": 1, "exp": "Delirium tremens (2–3 วันหลังหยุดสุรา): agitation, hallucination, autonomic instability, seizure — รักษาด้วย benzodiazepine (symptom-triggered) + thiamine + fluids/electrolyte. เป็นภาวะที่เสียชีวิตได้.", "id": "set5-90"}, {"topic": "Mixed/Integrated", "q": "A patient with metabolic acidosis has a high anion gap; history reveals antifreeze ingestion and calcium oxalate crystals in urine. What is the diagnosis and antidote?", "choices": ["Methanol; ethanol", "Ethylene glycol poisoning; fomepizole (± dialysis)", "Salicylate; bicarbonate", "Isoniazid; pyridoxine", "Uremia; dialysis"], "ans": 1, "exp": "Ethylene glycol (antifreeze) → high anion gap metabolic acidosis + calcium oxalate crystals + AKI. รักษาด้วย fomepizole (block alcohol dehydrogenase) ± hemodialysis. Methanol ให้ตาบอด + fomepizole เช่นกัน.", "id": "set5-91"}, {"topic": "Mixed/Integrated", "q": "A patient with fever and right-sided flank pain, pyuria, and an obstructing stone is septic. What is the priority?", "choices": ["Antibiotics alone", "Emergency decompression (stent/nephrostomy) + antibiotics", "Lithotripsy immediately", "Observation", "Diuretics"], "ans": 1, "exp": "Obstructing stone + infection (infected obstructed system) เป็น urologic emergency → decompress ด่วน (ureteric stent/percutaneous nephrostomy) + antibiotic + resuscitation. Definitive stone treatment ทำภายหลัง.", "id": "set5-92"}, {"topic": "Mixed/Integrated", "q": "A patient develops acute onset dyspnea, hypoxia, and clear lungs after major long-bone fracture, with petechiae and confusion. What is the diagnosis?", "choices": ["Pulmonary embolism (thrombotic)", "Fat embolism syndrome", "Pneumonia", "ARDS from sepsis", "Anaphylaxis"], "ans": 1, "exp": "Fat embolism syndrome (24–72 ชม.หลัง long-bone/pelvic fracture): triad = hypoxemia + neurologic (confusion) + petechial rash. รักษาแบบ supportive (oxygen/ventilation) + early fracture fixation เพื่อป้องกัน.", "id": "set5-93"}, {"topic": "Mixed/Integrated", "q": "A patient with a large anterior STEMI develops a new harsh holosystolic murmur and acute pulmonary edema 4 days later. What mechanical complication is likely?", "choices": ["Papillary muscle/ventricular septal rupture", "Pericarditis", "Reinfarction only", "Aortic dissection", "PE"], "ans": 0, "exp": "หลัง MI 3–7 วัน + murmur holosystolic ใหม่ + acute decompensation = mechanical complication (ventricular septal rupture หรือ acute mitral regurgitation จาก papillary muscle rupture) — emergency echo + surgical/hemodynamic support.", "id": "set5-94"}, {"topic": "Mixed/Integrated", "q": "A patient with obesity, snoring, and daytime sleepiness has resistant hypertension. Which condition should be screened for?", "choices": ["Hypothyroidism only", "Obstructive sleep apnea", "Pheochromocytoma only", "Diabetes insipidus", "Addison disease"], "ans": 1, "exp": "Resistant HT + obesity + snoring + daytime somnolence → obstructive sleep apnea (secondary/contributing cause of HT). ยืนยันด้วย sleep study; รักษาด้วย CPAP + ลดน้ำหนัก.", "id": "set5-95"}, {"topic": "Mixed/Integrated", "q": "A patient with a positive fecal occult blood test and iron deficiency anemia is 55 years old. What is the essential next investigation?", "choices": ["Reassurance", "Colonoscopy", "Upper endoscopy only", "CT abdomen only", "Repeat FIT in a year"], "ans": 1, "exp": "FOBT/FIT บวก + IDA ในผู้ใหญ่ ≥ 45–50 ปี ต้อง colonoscopy เพื่อประเมิน colorectal cancer/polyp (± EGD ถ้า colonoscopy ปกติ). อย่าเหมาเป็น hemorrhoid โดยไม่ตรวจ.", "id": "set5-96"}, {"topic": "Mixed/Integrated", "q": "A patient with hypertension is found to have a potassium of 6.8 with peaked T waves while on an ACE inhibitor and spironolactone. What is the immediate priority?", "choices": ["Give more spironolactone", "IV calcium gluconate then shift/remove potassium; stop offending drugs", "Increase ACE inhibitor", "Observation", "Give potassium"], "ans": 1, "exp": "Severe hyperkalemia (ECG changes) จากยา RAAS + K-sparing: ให้ calcium gluconate stabilize membrane → insulin/glucose + salbutamol shift → diuretic/resin/dialysis removal + หยุด ACEI/spironolactone.", "id": "set5-97"}, {"topic": "Mixed/Integrated", "q": "A patient with severe asthma exacerbation has a rising PaCO2 and is tiring despite maximal therapy. What does this indicate?", "choices": ["Improvement", "Impending respiratory failure requiring ICU and possible intubation", "Mild attack", "Anxiety only", "Metabolic alkalosis"], "ans": 1, "exp": "ใน severe asthma การที่ PaCO2 สูงขึ้น (แทนที่จะต่ำ) + ผู้ป่วยเหนื่อยล้า/silent chest = impending respiratory failure → ICU, เตรียม intubation, ให้ IV magnesium, systemic steroid, continuous nebulizer.", "id": "set5-98"}, {"topic": "Mixed/Integrated", "q": "A patient presents with jaundice; labs show elevated ALP and GGT with mild transaminase rise and pruritus. What pattern is this?", "choices": ["Hepatocellular", "Cholestatic (obstructive) pattern — image the biliary tree", "Hemolytic", "Isolated indirect hyperbilirubinemia", "Normal"], "ans": 1, "exp": "ALP + GGT สูงเด่น + pruritus = cholestatic pattern (obstruction/biliary disease) → imaging (US/MRCP) หา obstruction (stone, stricture, mass). ต่างจาก hepatocellular (AST/ALT สูงเด่น).", "id": "set5-99"}, {"topic": "Mixed/Integrated", "q": "A patient with type 2 diabetes presents for a routine visit. Which vaccination is particularly important to offer?", "choices": ["None", "Influenza, pneumococcal, hepatitis B, and COVID-19 vaccines", "Only rabies", "Only tetanus", "Only HPV"], "ans": 1, "exp": "ผู้ป่วยเบาหวาน/โรคเรื้อรังควรได้วัคซีนป้องกัน influenza (ทุกปี), pneumococcal, hepatitis B, และ COVID-19 เพื่อลดภาวะแทรกซ้อนจากการติดเชื้อ. เป็นส่วนหนึ่งของ preventive care.", "id": "set5-100"}]}];
